  emerald: 'text-emerald-400 drop-shadow-[0_0_2px_rgba(52,211,153,0.8)] decoration-emerald-500/30 underline decoration-2 underline-offset-4',
  rose: 'text-[#ff003c] drop-shadow-[0_0_2px_rgba(255,0,60,0.8)] decoration-[#ff003c]/30 underline decoration-2 underline-offset-4',
  amber: 'text-amber-400 drop-shadow-[0_0_2px_rgba(251,191,36,0.8)] decoration-amber-500/30 underline decoration-2 underline-offset-4',
  cyan: 'text-cyan-300 drop-shadow-[0_0_2px_rgba(34,211,238,0.8)] decoration-cyan-500/30 underline decoration-2 underline-offset-4',
};

const TEXT_SIZES: Record<string, string> = {
  sm: 'text-[14px]',
  base: 'text-[16px]',
  lg: 'text-[18px]',
  xl: 'text-[22px]',
};

const LINE_HEIGHTS: Record<string, string> = {
  tight: 'leading-tight',
  normal: 'leading-normal',
  relaxed: 'leading-relaxed',
  loose: 'leading-loose',
};

const LETTER_SPACINGS: Record<string, string> = {
  tighter: 'tracking-tighter',
  normal: 'tracking-normal',
  wide: 'tracking-wide',
  wider: 'tracking-wider',
};

const formatTime = (seconds: number): string => {
  if (!seconds || isNaN(seconds)) return "00:00";
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
};

const rearrangeAndCleanText = (text: string): string => {
  if (!text) return "";
  let cleaned = cleanGenAiText(text);
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n');
  return cleaned.trim();
};

const paginateText = (text: string, targetSize: number): string[] => {
  const pages: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= targetSize) {
      pages.push(remaining.trim());
      break;
    }
    let splitIdx = targetSize;
    const paragraphBreak = remaining.lastIndexOf('\n\n', targetSize);
    if (paragraphBreak > targetSize * 0.7) {
      splitIdx = paragraphBreak;
    } else {
      const sentenceBreak = Math.max(
          remaining.lastIndexOf('. ', targetSize),
          remaining.lastIndexOf('? ', targetSize),
          remaining.lastIndexOf('! ', targetSize)
      );
      if (sentenceBreak > targetSize * 0.5) splitIdx = sentenceBreak + 1;
      else {
          const spaceBreak = remaining.lastIndexOf(' ', targetSize);
          if (spaceBreak > 0) splitIdx = spaceBreak;
      }
    }
    pages.push(remaining.substring(0, splitIdx).trim());
    remaining = remaining.substring(splitIdx).trim();
  }
  return pages;
};

const splitIntoSentences = (text: string): string[] => {
  if (!text) return [];
  const sentences = text.match(/[^.!?]+[.!?]+["'”’]?\s*|.+$/g) || [text];
  return sentences.map(s => s.trim()).filter(s => s.length > 0);
};

const processQueue = async <T, R>(
  items: T[],
  concurrency: number,
  fn: (item: T, index: number) => Promise<R>,
  checkAbort?: () => boolean
): Promise<(R | null)[]> => {
  const results: (R | null)[] = new Array(items.length).fill(null);
  const queue = items.map((item, index) => ({ item, index }));
  const worker = async () => {
    while (queue.length > 0) {
      if (checkAbort && checkAbort()) break;
      const task = queue[0];
      if (!task) break; 
      const { item, index } = task;
      try {
        const result = await fn(item, index);
        results[index] = result;
        queue.shift();
      } catch (e: any) {
        queue.shift();
        results[index] = null;
      }
      await new Promise(resolve => setTimeout(resolve, 500));
    }
  };
  const workers = Array.from({ length: concurrency }).map(() => worker());
  await Promise.all(workers);
  return results;
};

export const AudioBook: React.FC<Props> = ({ chapter, fileContext, settings, onSettingsUpdate }) => {
  const [pages, setPages] = useState<string[]>([]);
  const [paragraphData, setParagraphData] = useState<ParagraphData[]>([]);
  const [flatSentenceMap, setFlatSentenceMap] = useState<SentenceMap[]>([]);
  const [currentPage, setCurrentPage] = useState(0);
  const [isLoadingText, setIsLoadingText] = useState(false);
  const [isTranslating, setIsTranslating] = useState(false);
  const [viewMode, setViewMode] = useState<'single' | 'split'>('single');
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [timings, setTimings] = useState<ChunkTiming[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [generationProgress, setGenerationProgress] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1);
  const [selectedVoice, setSelectedVoice] = useState('Puck');
  const [audioLanguage, setAudioLanguage] = useState(settings.targetLanguage);
  const [autoScroll, setAutoScroll] = useState(true);
  const [activeSentenceIndex, setActiveSentenceIndex] = useState<number>(-1);
  const [isModuleMinimized, setIsModuleMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const abortGenerationRef = useRef<boolean>(false);
  const animationRef = useRef<number | null>(null);

  const resetAudioState = () => {
    if (audioSrc) URL.revokeObjectURL(audioSrc);
    setAudioSrc(null);
    setTimings([]);
    setIsPlaying(false);
    setPlaybackProgress(0);
    setCurrentTime(0);
    setDuration(0);
    setActiveSentenceIndex(-1);
    setGenerationProgress("");
    setHasInitiated(false);
  };

  useEffect(() => {
    return () => { if (audioSrc) URL.revokeObjectURL(audioSrc); };
  }, [audioSrc]);

  const loadContent = async () => {
    setIsLoadingText(true);
    setPages([]);
    setCurrentPage(0);
    resetAudioState();
    try {
      const rawText = await extractChapterText(fileContext, chapter);
      const cleanText = rearrangeAndCleanText(rawText);
      setPages(paginateText(cleanText, PAGE_TARGET_SIZE));
    } catch (err: any) {
      console.error(err);
    } finally {
      setIsLoadingText(false);
    }
  };

  useEffect(() => { loadContent(); }, [chapter, fileContext]);

  useEffect(() => {
     if (!pages[currentPage]) return;
     const pageText = pages[currentPage];
     const rawParagraphs = pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0);
     const newParagraphData: ParagraphData[] = [];
     const newSentenceMap: SentenceMap[] = [];
     let globalIdx = 0;
     rawParagraphs.forEach((pText, pIndex) => {
         const sentences = splitIntoSentences(pText);
         sentences.forEach((s, sIndex) => {
             newSentenceMap.push({ pIndex, sIndex, globalIndex: globalIdx, text: s });
             globalIdx++;
         });
         newParagraphData.push({ original: sentences, translated: [] });
     });
     setParagraphData(newParagraphData);
     setFlatSentenceMap(newSentenceMap);
     resetAudioState();
     abortGenerationRef.current = true;
  }, [currentPage, pages]);

  useEffect(() => {
    const loadTranslation = async () => {
      if (settings.targetLanguage === 'Original' || paragraphData.length === 0) {
        setIsTranslating(false);
        return;
      }

      const currentSentenceCount = paragraphData.reduce((acc, p) => acc + p.original.length, 0);
      const allSentences = paragraphData.flatMap(p => p.original);

      setIsTranslating(true);
      try {
        const translations = await translateSentences(allSentences, settings.targetLanguage);

        let syncedTranslations = [...translations];
        if (syncedTranslations.length < currentSentenceCount) {
            syncedTranslations = [...syncedTranslations, ...new Array(currentSentenceCount - syncedTranslations.length).fill("")];
        } else if (syncedTranslations.length > currentSentenceCount) {
            syncedTranslations = syncedTranslations.slice(0, currentSentenceCount);
        }

        let transPointer = 0;
        setParagraphData(prev => {
            if (prev.length === 0) return prev;

            return prev.map((p) => {
                const pTrans = syncedTranslations.slice(transPointer, transPointer + p.original.length);
                transPointer += p.original.length;
                return { ...p, translated: pTrans };
            });
        });
      } catch(e) { 
        console.error("Translation error", e); 
      } finally { 
        setIsTranslating(false); 
      }
    };
    loadTranslation();
  }, [currentPage, settings.targetLanguage, paragraphData.length]);

  useEffect(() => {
    if (audioRef.current) {
        audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    const syncPlayback = () => {
        if (!audioRef.current) return;
        const audio = audioRef.current;
        const t = audio.currentTime;
        setCurrentTime(t);
        setDuration(audio.duration || 0);
        setPlaybackProgress((t / (audio.duration || 1)) * 100);
        const activeIdx = timings.findIndex(chunk => !chunk.isWhitespace && t >= chunk.start && t < chunk.end);
        if (activeIdx !== -1) setActiveSentenceIndex(activeIdx);

        if (canvasRef.current && !isModuleMinimized) {
            const canvas = canvasRef.current;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.clearRect(0, 0, canvas.width, canvas.height);
                const centerX = canvas.width / 2;
                const bars = 40;
                const step = canvas.width / 2 / bars;
                for (let i = 0; i < bars; i++) {
                    const value = Math.random() * 255; 
                    const h = isPlaying ? (value / 255) * canvas.height * 0.9 : 2;
                    ctx.fillStyle = isPlaying ? `rgb(${value}, ${243 - value}, 255)` : `rgb(30, 41, 59)`;
                    ctx.fillRect(centerX + (i * step), (canvas.height - h) / 2, step - 2, h);
                    ctx.fillRect(centerX - ((i + 1) * step), (canvas.height - h) / 2, step - 2, h);
                }
            }
        }
        if (isPlaying) animationRef.current = requestAnimationFrame(syncPlayback);
    };
    if (isPlaying) animationRef.current = requestAnimationFrame(syncPlayback);
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, timings, audioSrc, isModuleMinimized]);

  useEffect(() => {
    if (!autoScroll) return;
    if (activeSentenceIndex !== -1 && flatSentenceMap[activeSentenceIndex]) {
        const sentenceEl = document.getElementById(`original-sent-${activeSentenceIndex}`);
        if (sentenceEl) sentenceEl.scrollIntoView({ behavior: 'smooth', block: 'center', inline: 'nearest' });
    }
  }, [activeSentenceIndex, autoScroll, flatSentenceMap]); 

  const handleInitiateToggle = async () => {
    if (isGenerating) {
        abortGenerationRef.current = true;
        setIsGenerating(false);
        setHasInitiated(true);
        return;
    }
    generatePageAudio();
  };

  const generatePageAudio = async () => {
    if (isGenerating || !flatSentenceMap.length) return;
    abortGenerationRef.current = false;
    setIsGenerating(true);
    setHasInitiated(true);
    setGenerationProgress("INIT_VOICE_CORE...");
    try {
      let sentencesToSpeak: string[] = [];
      if (audioLanguage === 'Original') sentencesToSpeak = flatSentenceMap.map(m => m.text);
      else {
          if (audioLanguage === settings.targetLanguage && paragraphData.every(p => p.translated.length > 0)) sentencesToSpeak = paragraphData.flatMap(p => p.translated);
          else {
              setGenerationProgress("AUDIO_TRANS...");
              sentencesToSpeak = await translateSentences(flatSentenceMap.map(m => m.text), audioLanguage);
          }
      }

      const audioResults = await processQueue<string, string | null>(
        sentencesToSpeak, CONCURRENCY_LIMIT, 
        async (sentence, idx) => {
           if (abortGenerationRef.current) return null;
           setGenerationProgress(`PACKET_${idx + 1}_OF_${sentencesToSpeak.length}`);
           return await generateSpeech(sentence, selectedVoice);
        },
        () => abortGenerationRef.current
      );
      if (abortGenerationRef.current) return;

      const audioBuffers: Uint8Array[] = [];
      const newTimings: ChunkTiming[] = [];
      let currentByteOffset = 0;
      const BYTES_PER_SEC = 48000; 

      for (let i = 0; i < sentencesToSpeak.length; i++) {
        const b64 = audioResults[i];
        if (!b64) {
          newTimings.push({ text: sentencesToSpeak[i], start: currentByteOffset / BYTES_PER_SEC, end: currentByteOffset / BYTES_PER_SEC, isWhitespace: true });
          continue;
        }
        const binaryString = atob(b64);
        const bytes = new Uint8Array(binaryString.length);
        for (let k = 0; k < binaryString.length; k++) bytes[k] = binaryString.charCodeAt(k);
        audioBuffers.push(bytes);
        const durationSec = bytes.length / BYTES_PER_SEC;
        const startSec = currentByteOffset / BYTES_PER_SEC;
        newTimings.push({ text: sentencesToSpeak[i], start: startSec, end: startSec + durationSec, isWhitespace: false });
        currentByteOffset += bytes.length;
      }

      const mergedBuffer = new Uint8Array(currentByteOffset);
      let offset = 0;
      for (const buf of audioBuffers) { mergedBuffer.set(buf, offset); offset += buf.length; }

      const wavHeader = new ArrayBuffer(44);
      const view = new DataView(wavHeader);
      const writeString = (v: DataView, o: number, s: string) => { for (let k = 0; k < s.length; k++) v.setUint8(o + k, s.charCodeAt(k)); };
      writeString(view, 0, 'RIFF'); view.setUint32(4, 36 + currentByteOffset, true); writeString(view, 8, 'WAVE'); writeString(view, 12, 'fmt '); view.setUint32(16, 16, true); view.setUint16(20, 1, true); view.setUint16(22, 1, true); view.setUint32(24, 24000, true); view.setUint32(28, 48000, true); view.setUint16(32, 2, true); view.setUint16(34, 16, true); writeString(view, 36, 'data'); view.setUint32(40, currentByteOffset, true);

      const url = URL.createObjectURL(new Blob([wavHeader, mergedBuffer], { type: 'audio/wav' }));
      setTimings(newTimings); 
      setAudioSrc(url); 
    } catch(e) {
      console.error(e);
      setGenerationProgress("ERR_LINK_FAILED");
    } finally { setIsGenerating(false); }
  };

  const togglePlay = async () => {
    if (!audioSrc || !audioRef.current) return;
    try {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
      } else {
        const playPromise = audioRef.current.play();
        if (playPromise !== undefined) {
          await playPromise.catch(e => {
            if (e.name !== 'AbortError') throw e;
          });
          setIsPlaying(true);
        }
      }
    } catch (err) {
      console.warn("Playback interrupted:", err);
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (audioRef.current && duration) {
       audioRef.current.currentTime = (val / 100) * duration;
    }
  };

  if (isLoadingText) return <Loader text="DECODING_TEXT_BLOCK..." className="h-full" />;

  const currentStatusLabel = isGenerating ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE";
  const currentStatusIcon = isGenerating ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />;

  return (
    <div className="h-full flex flex-col gap-4 animate-fade-in relative font-sans text-zinc-100 text-left" style={{ fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' }}>
      <audio 
        ref={audioRef} 
        src={audioSrc || undefined} 
        onEnded={() => setIsPlaying(false)} 
        onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
        className="hidden" 
      />

      {/* Controller Toolbar */}
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2 z-20">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Headphones size={18} className="text-[#00f3ff]" />
                 <span>Voice_Synth</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedVoice} onChange={(e) => { setSelectedVoice(e.target.value); resetAudioState(); }} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">
                    {VOICES.map(v => <option key={v.name} value={v.name}>{v.name}</option>)}
                 </select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={audioLanguage} onChange={(e) => { setAudioLanguage(e.target.value); resetAudioState(); }} className="bg-transparent text-xs text-[#00f3ff] outline-none font-mono uppercase w-[120px] bg-[#050505] cursor-pointer">
                    {LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>
              <button 
                onClick={handleInitiateToggle} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isGenerating ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {currentStatusIcon}
                 {currentStatusLabel}
              </button>
          </div>
      </div>

      <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isModuleMinimized ? 'h-auto' : 'h-[277px]'}`}>
          {!isModuleMinimized && (
              <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                 <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>
                 {isGenerating ? (
                    <div className="z-20 scale-75 animate-fade-in"><Loader text={generationProgress} /></div>
                 ) : (
                    <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                 )}
                 <div className="absolute bottom-0 left-0 w-full h-1 bg-zinc-900 z-30 group cursor-pointer">
                    <input type="range" min="0" max="100" value={playbackProgress} onChange={handleSeek} disabled={!audioSrc} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-40" />
                    <div className="h-full bg-[#00f3ff] relative transition-all duration-100 ease-linear shadow-[0_0_10px_#00f3ff]" style={{ width: `${playbackProgress}%` }} />
                 </div>
              </div>
          )}

          <div className="bg-[#020202] p-3 flex items-center justify-between">
              <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                   {RATES.map(s => (
                     <button key={s} onClick={() => setPlaybackRate(s)} className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}>{s.toFixed(2)}x</button>
                   ))}
              </div>
              <div className="flex-2 flex items-center justify-center gap-6">
                  <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                  <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>
                    {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}
                  </button>
                  <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
              </div>
              <div className="flex-1 flex justify-end gap-2 items-center">
                  <span className="text-[10px] font-mono text-zinc-600 mr-2">{formatTime(currentTime)} / {formatTime(duration)}</span>
                  <a href={audioSrc || '#'} download={`lumina-voice-pg${currentPage + 1}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()}><Download size={20} /></a>
                  <button onClick={() => setIsModuleMinimized(!isModuleMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50">{isModuleMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
              </div>
          </div>
      </div>

      <div className="flex shrink-0 border border-zinc-800 bg-[#0a0a0c]/90 backdrop-blur-md rounded-sm z-10 w-full flex-col overflow-hidden">
          <div className="flex items-center justify-between p-2">
               <div className="flex items-center gap-2">
                  <button onClick={() => setCurrentPage(prev => Math.max(0, prev - 1))} disabled={currentPage === 0} className="flex items-center justify-center w-10 py-1.5 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all"><ChevronLeft size={14} /></button>
                  <h3 className="text-[10px] font-bold text-[#00f3ff] font-tech uppercase tracking-widest px-4">PG.{String(currentPage + 1).padStart(2,'0')}</h3>
                  <button onClick={() => setCurrentPage(prev => Math.min(pages.length - 1, prev + 1))} disabled={currentPage === pages.length - 1} className="flex items-center justify-center w-10 py-1.5 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all"><ChevronRight size={14} /></button>
              </div>
              <div className="flex items-center gap-2">
                  <button onClick={() => setViewMode(viewMode === 'split' ? 'single' : 'split')} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-[10px] font-bold font-mono uppercase transition-all min-w-[120px] justify-center ${viewMode === 'split' ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}><Columns size={12} /> SPLIT_VIEW</button>
                  <button onClick={() => setAutoScroll(!autoScroll)} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-[10px] font-bold font-mono uppercase transition-all min-w-[120px] justify-center ${autoScroll ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}><Eye size={12} /> SYNC_TRACK</button>
               </div>
          </div>
      </div>

      <div className="flex-1 overflow-hidden rounded-sm border border-zinc-800 bg-[#050505] relative flex flex-col hud-border text-left">
         <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8 pb-32">
            {paragraphData.map((para, pIdx) => (
                <div key={pIdx} className={`w-full flex ${viewMode === 'split' ? '' : 'justify-center'}`}>
                    <div className={`${viewMode === 'split' ? 'w-1/2 pr-6 border-r border-zinc-800/20' : 'w-full max-w-3xl'} ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} ${LETTER_SPACINGS[settings.letterSpacing]} text-zinc-400 font-medium`}>
                        {para.original.map((sentence, sIdx) => {
                            const mapping = flatSentenceMap.find(m => m.pIndex === pIdx && m.sIndex === sIdx);
                            const globalIdx = mapping?.globalIndex ?? -1;
                            const isActive = autoScroll && globalIdx === activeSentenceIndex;
                            return (
                                <span key={sIdx} id={`original-sent-${globalIdx}`} className={`transition-all duration-300 px-[2px] ${isActive ? HIGHLIGHT_STYLES[settings.highlightColor] : 'hover:text-zinc-200 cursor-pointer'}`} onClick={() => { if(audioRef.current && timings[globalIdx]) { audioRef.current.currentTime = timings[globalIdx].start; togglePlay(); } }}>
                                    {sentence}{' '}
                                </span>
                            );
                        })}
                    </div>
                    {viewMode === 'split' && (
                        <div className={`w-1/2 pl-6 ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} ${LETTER_SPACINGS[settings.letterSpacing]} text-zinc-500 font-medium`}>
                            {isTranslating && para.translated.length === 0 ? (
                                <span className="animate-pulse text-[10px] font-mono text-zinc-700 uppercase">Decrypting_Matrix...</span>
                            ) : (
                                para.original.map((_, sIdx) => {
                                    const mapping = flatSentenceMap.find(m => m.pIndex === pIdx && m.sIndex === sIdx);
                                    const globalIdx = mapping?.globalIndex ?? -1;
                                    const isActive = autoScroll && globalIdx === activeSentenceIndex;
                                    const tText = para.translated[sIdx] || "";
                                    return (
                                        <span key={sIdx} className={`transition-all duration-500 px-[2px] ${isActive ? HIGHLIGHT_STYLES[settings.highlightColor] : ''}`}>
                                            {tText}{' '}
                                        </span>
                                    );
                                })
                            )}
                        </div>
                    )}
                </div>
            ))}
         </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 128;
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;
    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }
      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          const centerX = canvas.width / 2;
          const bars = bufferLength / 2;
          const step = canvas.width / 2 / bars;
          for (let i = 0; i < bars; i++) {
            const value = dataArray[i];
            const h = (value / 255) * canvas.height * 0.9;
            ctx.fillStyle = `rgb(${value}, ${243 - value}, 255)`;
            ctx.fillRect(centerX + (i * step), (canvas.height - h) / 2, step - 2, h);
            ctx.fillRect(centerX - ((i + 1) * step), (canvas.height - h) / 2, step - 2, h);
          }
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const renderButtonLabel = () => {
    if (isLoading) return "STOP";
    if (hasInitiated) return "REGENERATE";
    return "INITIATE";
  };

  const renderButtonIcon = () => {
    if (isLoading) return <Square size={14} fill="currentColor" />;
    if (hasInitiated) return <RefreshCw size={14} />;
    return <Play size={14} fill="currentColor" />;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
              <div className="hidden md:flex items-center gap-3 text-[10px] font-mono border-l border-zinc-800 pl-4 uppercase">
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">HOST:</span>
                    <span className="text-cyan-400 font-bold">{hosts.host1.toUpperCase()}</span>
                 </div>
                 <div className="text-zinc-700">|</div>
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">CO-HOST:</span>
                    <span className="text-[#ff003c] font-bold">{hosts.host2.toUpperCase()}</span>
                 </div>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {renderButtonIcon()}
                 {renderButtonLabel()}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>
                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            <div className="bg-black/70 backdrop-blur-md border border-zinc-800/50 px-6 py-3 rounded-sm shadow-[0_0_40px_rgba(0,0,0,0.9)] border-cyan-500/20 max-w-[85%] text-center">
                               <span className="text-sm font-bold text-cyan-400 font-tech uppercase tracking-[0.3em] opacity-95 whitespace-normal block leading-relaxed drop-shadow-[0_0_8px_rgba(0,243,255,0.6)]">EPISODE: {episodeTitle.toUpperCase()}</span>
                            </div>
                        </div>
                      )}
                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_COMM_LINK..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(255,0,60,0.3)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Film, Download, RotateCcw, Settings2, MonitorPlay, Globe, Square, RefreshCw, Play, Pause, RotateCw, Volume2, VolumeX, Maximize2, Minimize2 } from 'lucide-react';
import { Chapter, FileContext } from '../types';
import { generateSummaryVideo, hasValidKeyForVeo, requestVeoKey } from '../services/gemini';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Cyberpunk', 
  'Vaporwave', 'Noir', 'Documentary', 'Surreal'
];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const RESOLUTIONS: ('720p' | '1080p')[] = ['720p', '1080p'];
const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

export const VideoSummary: React.FC<Props> = ({ chapter, fileContext }) => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState('Cinematic');
  const [selectedLanguage, setSelectedLanguage] = useState('English');
  const [selectedResolution, setSelectedResolution] = useState<'720p' | '1080p'>('720p');

  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isMuted, setIsMuted] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [controlsVisible, setControlsVisible] = useState(true);

  const abortRef = useRef<boolean>(false);
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const controlsTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (videoUrl) URL.revokeObjectURL(videoUrl);
    };
  }, [videoUrl]);

  const handleToggleGeneration = async () => {
    if (isGenerating) {
        abortRef.current = true;
        setIsGenerating(false);
        setStatus("");
        return;
    }
    setError(null);
    setIsGenerating(true);
    abortRef.current = false;
    setStatus("Authenticating & Generating...");
    try {
      const hasKey = await hasValidKeyForVeo();
      if (!hasKey) {
        setStatus("Waiting for Access Key...");
        await requestVeoKey();
      }
      if (abortRef.current) return;

      const url = await generateSummaryVideo(
        fileContext, 
        chapter, 
        setStatus, 
        selectedStyle, 
        selectedLanguage,
        selectedResolution
      );

      if (!abortRef.current) {
        if (videoUrl) URL.revokeObjectURL(videoUrl);
        setVideoUrl(url);
        setIsPlaying(false);
      }
    } catch (e: any) {
      if (!abortRef.current) {
        console.error(e);
        let msg = "Generation failed.";
        if (e.message?.includes("Requested entity was not found")) {
            msg = "Key Invalid. Paid project key required.";
            await requestVeoKey();
        } else if (e.message) msg = e.message;
        setError(msg);
      }
    } finally {
      if (!abortRef.current) {
        setIsGenerating(false);
        setStatus("");
      }
    }
  };

  const togglePlay = async (e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!videoRef.current || !videoUrl) return;

    try {
      if (isPlaying) {
        videoRef.current.pause();
        setIsPlaying(false);
      } else {
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          await playPromise;
          setIsPlaying(true);
        }
      }
    } catch (err) {
      console.warn("Playback interrupted or failed:", err);
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (videoRef.current && duration) {
       videoRef.current.currentTime = (val / 100) * duration;
    }
  };

  const toggleMute = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (videoRef.current) {
        videoRef.current.muted = !isMuted;
        setIsMuted(!isMuted);
    }
  };

  const toggleFullScreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
        containerRef.current.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable full-screen mode: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
  };

  const resetControlsTimeout = () => {
    setControlsVisible(true);
    if (controlsTimeoutRef.current) {
      window.clearTimeout(controlsTimeoutRef.current);
    }
    if (isPlaying) {
      controlsTimeoutRef.current = window.setTimeout(() => {
        setControlsVisible(false);
      }, 3000);
    }
  };

  useEffect(() => {
    const handleFsChange = () => {
      const isFs = !!document.fullscreenElement;
      setIsFullScreen(isFs);
      if (!isFs) setControlsVisible(true);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const formatTime = (seconds: number): string => {
    if (!seconds || isNaN(seconds)) return "00:00";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const updateProgress = () => {
    if (videoRef.current) {
        setCurrentTime(videoRef.current.currentTime);
        setDuration(videoRef.current.duration || 0);
        setPlaybackProgress((videoRef.current.currentTime / (videoRef.current.duration || 1)) * 100);
    }
  };

  useEffect(() => {
    if (videoRef.current) {
        videoRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, videoUrl]);

  const currentStatusLabel = isGenerating ? "STOP" : videoUrl ? "REGENERATE" : "INITIATE";
  const currentStatusIcon = isGenerating ? <Square size={14} fill="currentColor" /> : videoUrl ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />;

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left overflow-hidden">
      {/* Top Controls Bar */}
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-3 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2 z-20">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <MonitorPlay size={18} className="text-[#00f3ff]" />
                 <span>Cine_Render</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedStyle} onChange={(e) => setSelectedStyle(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[110px] bg-[#050505]">{STYLES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[110px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500 font-mono text-[10px] uppercase text-zinc-400">RES:</div>
                 <select value={selectedResolution} onChange={(e) => setSelectedResolution(e.target.value as any)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[80px] bg-[#050505]">{RESOLUTIONS.map(res => <option key={res} value={res}>{res}</option>)}</select>
              </div>
              <button onClick={handleToggleGeneration} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isGenerating ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}>
                {currentStatusIcon}
                {currentStatusLabel}
              </button>
          </div>
      </div>

      {/* Main Content Area - Strictly 16:9 ratio fit */}
      <div className="flex-1 flex flex-col items-center justify-center relative min-h-0 bg-[#020202] rounded-lg border border-zinc-900 shadow-inner overflow-hidden">
        <div className="absolute inset-0 bg-grid opacity-[0.05] pointer-events-none"></div>

        {/* The 16:9 Screen Container */}
        <div 
          ref={containerRef} 
          onMouseMove={resetControlsTimeout}
          className="relative w-full max-w-full aspect-video flex flex-col bg-black shadow-2xl transition-all duration-500 group overflow-hidden"
        >
            {/* Visual Screen */}
            <div className="flex-1 relative flex items-center justify-center overflow-hidden border-b border-zinc-900" onClick={() => videoUrl && togglePlay()}>
                {!videoUrl && !isGenerating && (
                    <div className="z-10 text-center space-y-4 p-8">
                        <div className="w-16 h-16 bg-zinc-900/50 rounded-full flex items-center justify-center mx-auto border border-zinc-800">
                             <Film className="text-zinc-700 w-6 h-6" />
                        </div>
                        <p className="text-zinc-600 font-mono text-[10px] uppercase tracking-widest">Awaiting Render Signal</p>
                        {error && <p className="text-[#ff003c] text-[9px] font-mono mt-2 border border-[#ff003c]/20 p-2 bg-[#ff003c]/5">ERROR: {error}</p>}
                    </div>
                )}

                {isGenerating && (
                    <div className="z-20 scale-75">
                         <Loader text={status} />
                    </div>
                )}

                {videoUrl && !isGenerating && (
                    <>
                        <video 
                            key={videoUrl}
                            ref={videoRef}
                            src={videoUrl ? `${videoUrl}#t=0.001` : undefined}
                            onTimeUpdate={updateProgress}
                            onLoadedMetadata={updateProgress}
                            onPlay={() => { 
                                setIsPlaying(true);
                                if(videoRef.current) videoRef.current.playbackRate = playbackRate;
                            }}
                            onPause={() => setIsPlaying(false)}
                            className="w-full h-full object-contain pointer-events-none"
                            playsInline
                        />
                        <div className={`absolute top-3 left-3 z-30 flex gap-2 transition-opacity duration-500 ${controlsVisible ? 'opacity-100' : 'opacity-0'}`}>
                             <div className="bg-black/60 backdrop-blur-md px-2 py-0.5 border border-cyan-500/30 rounded-sm text-[8px] font-mono text-cyan-400 uppercase tracking-widest">Live_Playback</div>
                             <div className="bg-black/60 backdrop-blur-md px-2 py-0.5 border border-zinc-800 rounded-sm text-[8px] font-mono text-zinc-500 uppercase tracking-widest">{selectedResolution}</div>
                        </div>
                    </>
                )}
            </div>

            {/* Bottom Progress Bar Overlay */}
            {videoUrl && (
                <div className={`absolute bottom-11 left-0 w-full h-1 bg-zinc-900/50 group-hover:h-2 transition-all cursor-pointer z-40 ${controlsVisible ? 'opacity-100' : 'opacity-0'}`}>
                    <input 
                        type="range" min="0" max="100" step="0.1" 
                        value={playbackProgress} onChange={handleSeek} 
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-50" 
                    />
                    <div className="h-full bg-cyan-500 shadow-[0_0_10px_#00f3ff] transition-all" style={{ width: `${playbackProgress}%` }}></div>
                </div>
            )}

            {/* Control Bar - Matched to Net_Cast Spec */}
            <div className={`w-full bg-[#020202] p-3 flex items-center justify-between z-40 shrink-0 transition-all duration-500 ${videoUrl && controlsVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-full pointer-events-none'}`}>
                {/* Speed Controls (flex-1) */}
                <div className="flex-1 flex items-center gap-2">
                    {SPEEDS.map(s => (
                        <button 
                            key={s} 
                            onClick={(e) => { e.stopPropagation(); setPlaybackRate(s); }} 
                            className={`text-[8px] font-mono font-bold transition-all ${playbackRate === s ? 'text-cyan-400' : 'text-zinc-600 hover:text-zinc-400'}`}
                        >
                            {s}x
                        </button>
                    ))}
                </div>

                {/* Primary Transport (flex-2) */}
                <div className="flex-2 flex items-center justify-center gap-6">
                    <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime -= 5; }} className="text-zinc-500 hover:text-cyan-400 transition-colors"><RotateCcw size={20} /></button>
                    <button onClick={togglePlay} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${isPlaying ? 'bg-transparent border-2 border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>
                        {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}
                    </button>
                    <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime += 5; }} className="text-zinc-500 hover:text-cyan-400 transition-colors"><RotateCw size={20} /></button>
                </div>

                {/* Secondary Controls (flex-1) */}
                <div className="flex-1 flex items-center justify-end gap-3">
                    <span className="text-[10px] font-mono text-zinc-600 min-w-[70px] text-right">{formatTime(currentTime)} / {formatTime(duration)}</span>
                    <button onClick={toggleMute} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                        {isMuted ? <VolumeX size={18} /> : <Volume2 size={18} />}
                    </button>
                    <a href={videoUrl || '#'} download={`cine-render-${chapter.id}.mp4`} onClick={(e) => e.stopPropagation()} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                        <Download size={18} />
                    </a>
                    <button onClick={toggleFullScreen} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                        {isFullScreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
                    </button>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type, Modality, Chat, Content, Part } from "@google/genai";
import { BookStructure, Chapter, Concept, DictionaryEntry, FileContext } from "../types";

const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  let cleaned = text.replace(/^(Below|Here|Following|This) is the (translation|text).*?:/gi, '');
  cleaned = cleaned.replace(/^(以下是|这是).*(翻译|内容).*?：/gi, '');
  return cleaned
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') 
    .trim();
};

const withRetry = async <T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const getErrorDetails = (e: any) => {
        if (e.error && typeof e.error === 'object') return e.error;
        if (e.response?.data?.error) return e.response.data.error;
        return e;
    };
    const details = getErrorDetails(error);
    const code = details.code || details.status || error.status || error.code;
    const message = String(details.message || error.message || JSON.stringify(error)).toLowerCase();

    const isRateLimit = Number(code) === 429 || message.includes('429') || message.includes('quota');
    const isServerError = (Number(code) >= 500 && Number(code) < 600) || message.includes('internal error');

    if (retries > 0 && (isRateLimit || isServerError)) {
      const nextDelay = isRateLimit ? delay * 4 : delay * 2;
      console.warn(`Gemini API error (${code}). Retrying in ${nextDelay}ms...`);
      await new Promise(resolve => setTimeout(resolve, nextDelay));
      return withRetry(fn, retries - 1, nextDelay);
    }
    throw error;
  }
};

const getFilePart = (file: FileContext): Part => {
  if (file.isText) {
    // Truncate text content if it's excessively large for a single prompt part to avoid 500 errors
    const content = file.content.length > 200000 ? file.content.substring(0, 200000) : file.content;
    return { text: content };
  }
  return { inlineData: { mimeType: file.mimeType, data: file.content } };
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: "Analyze the provided book. Extract the title, author, and a list of major chapters (max 20). For each chapter, provide a brief title and a concise one-sentence description. Output strictly in JSON format." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["id", "title"]
              }
            }
          },
          required: ["title", "author", "chapters"]
        }
      }
    });
    const data = JSON.parse(response.text || "{}");
    return { ...data, id: crypto.randomUUID(), bookmarks: [] } as BookStructure;
  });
};

export const translateSentences = async (sentences: string[], targetLanguage: string): Promise<string[]> => {
  if (sentences.length === 0) return [];
  // Batch sentences to avoid massive prompts which often cause 500 errors
  const batchSize = 15;
  const results: string[] = [];

  for (let i = 0; i < sentences.length; i += batchSize) {
    const batch = sentences.slice(i, i + batchSize);
    const batchResult = await withRetry(async () => {
      const ai = getAi();
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: {
          parts: [{ text: `Translate the following sentences to ${targetLanguage}. Return a JSON array of strings. Maintain 1:1 mapping.\n\nSentences: ${JSON.stringify(batch)}` }]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return JSON.parse(response.text || "[]") as string[];
    });
    results.push(...batchResult);
  }
  return results;
};

export const extractChapterText = async (file: FileContext, chapter: Chapter): Promise<string> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Extract the full text for the chapter: "${chapter.title}". If the exact title is not found, extract the closest matching section. Use double newlines for paragraph breaks.` }
        ]
      }
    });
    return response.text || "";
  });
};

export const generatePodcastAudio = async (
  file: FileContext,
  chapter: Chapter,
  tone: string = 'Engaging',
  hosts: { host1: string, voice1: string, host2: string, voice2: string },
  language: string = 'English'
): Promise<{ audio: string; script: string; episodeTitle: string }> => {
  return withRetry(async () => {
    const ai = getAi();
    const scriptResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Create a ${tone} podcast dialogue about the content of "${chapter.title}" in ${language}. Use the hosts: ${hosts.host1} and ${hosts.host2}. Format as "Name: Text".` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            episodeTitle: { type: Type.STRING },
            script: { type: Type.STRING }
          },
          required: ["episodeTitle", "script"]
        }
      }
    });

    const parsedResponse = JSON.parse(scriptResponse.text || "{}");
    const audioResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: parsedResponse.script }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              { speaker: hosts.host1, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice1 } } },
              { speaker: hosts.host2, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice2 } } }
            ]
          }
        }
      }
    });
    const base64Audio = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Audio generation failed");
    return { audio: base64Audio, script: parsedResponse.script, episodeTitle: parsedResponse.episodeTitle };
  });
};

export const extractConcepts = async (file: FileContext, chapter: Chapter): Promise<Concept[]> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Identify 3 key concepts from "${chapter.title}". Return as JSON array of objects with 'term', 'definition', and 'visualPrompt'.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              term: { type: Type.STRING },
              definition: { type: Type.STRING },
              visualPrompt: { type: Type.STRING }
            },
            required: ["term", "definition", "visualPrompt"]
          }
        }
      }
    });
    return JSON.parse(response.text || "[]") as Concept[];
  });
};

export const generateConceptImage = async (visualPrompt: string, style: string = 'Digital Art', aspectRatio: string = '1:1'): Promise<string> => {
  return withRetry(async () => {
    const ai = getAi();
