          y += 25;
      }

      // Divider
      ctx.strokeStyle = '#334155';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(margin, y);
      ctx.lineTo(canvas.width - margin, y);
      ctx.stroke();
      y += 40;

      // --- Main Text Content (Auto-Scaling) ---
      // Base font size
      let fontSize = 32;
      // Use selected font setting or fallback
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;

      const words = item.text.split(' ');
      let lines = [];
      let line = '';

      // Function to calculate lines
      const calculateLines = () => {
         lines = [];
         line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line);
              line = words[n] + ' ';
            } else {
              line = testLine;
            }
         }
         lines.push(line);
      };

      calculateLines();

      // Auto-scale down if text takes too much vertical space
      const maxHeight = 350; // Adjusted for square layout + extra metadata

      // Loop to reduce font size if too tall
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2;
          ctx.font = `${fontSize}px ${mainFont}`;
          calculateLines();
      }

      // Draw Quote
      ctx.fillStyle = '#334155';
      ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);

      ctx.fillStyle = '#e2e8f0'; 
      ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;

      for (let i = 0; i < lines.length; i++) {
         ctx.fillText(lines[i], margin, y);
         y += lineHeight;
      }

      y += 30;

      // --- Definition Section ---
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; // Cyan
          ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y);
          y += 20;

          ctx.fillStyle = '#94a3b8';
          ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y);
               defLine = defWords[n] + ' ';
               y += 18;
            } else {
               defLine = testLine;
            }
         }
         ctx.fillText(defLine, margin, y);
         y += 35;
      }

      // --- Comments Section ---
      if (item.comment) {
          ctx.fillStyle = '#fb7185'; // Rose
          ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y);
