  const animationRef = useRef<number | null>(null);

  const resetAudioState = () => {
    if (audioSrc) URL.revokeObjectURL(audioSrc);
    setAudioSrc(null);
    setTimings([]);
    setIsPlaying(false);
    setPlaybackProgress(0);
    setCurrentTime(0);
    setDuration(0);
    setActiveSentenceIndex(-1);
    setGenerationProgress("");
    setHasInitiated(false);
  };

  useEffect(() => {
    return () => { if (audioSrc) URL.revokeObjectURL(audioSrc); };
  }, [audioSrc]);

  const loadContent = async () => {
    setIsLoadingText(true);
    setPages([]);
    setCurrentPage(0);
    resetAudioState();
    try {
      const rawText = await extractChapterText(fileContext, chapter);
      const cleanText = rearrangeAndCleanText(rawText);
      setPages(paginateText(cleanText, PAGE_TARGET_SIZE));
    } catch (err: any) {
      console.error(err);
    } finally {
      setIsLoadingText(false);
    }
  };

  useEffect(() => { loadContent(); }, [chapter, fileContext]);

  useEffect(() => {
     if (!pages[currentPage]) return;
     const pageText = pages[currentPage];
     const rawParagraphs = pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0);
     const newParagraphData: ParagraphData[] = [];
     const newSentenceMap: SentenceMap[] = [];
     let globalIdx = 0;
     rawParagraphs.forEach((pText, pIndex) => {
         const sentences = splitIntoSentences(pText);
         sentences.forEach((s, sIndex) => {
             newSentenceMap.push({ pIndex, sIndex, globalIndex: globalIdx, text: s });
             globalIdx++;
         });
         newParagraphData.push({ original: sentences, translated: [] });
     });
     setParagraphData(newParagraphData);
     setFlatSentenceMap(newSentenceMap);
     resetAudioState();
     abortGenerationRef.current = true;
     setIsTranslating(false); // Reset translation status on page flip
  }, [currentPage, pages]);

  useEffect(() => {
    const loadTranslation = async () => {
      if (settings.targetLanguage === 'Original' || paragraphData.length === 0) {
        setIsTranslating(false);
        return;
      }

      const allSentences = paragraphData.flatMap(p => p.original);
      if (allSentences.length === 0) return;

      setIsTranslating(true);
      try {
        const translations = await translateSentences(allSentences, settings.targetLanguage);

        let transPointer = 0;
        setParagraphData(prev => {
            if (prev.length === 0) return prev;
            return prev.map((p) => {
                const count = p.original.length;
                const pTrans = translations.slice(transPointer, transPointer + count);
                transPointer += count;
                // If translations array is shorter, pad with empty strings
                while (pTrans.length < count) pTrans.push("");
                return { ...p, translated: pTrans };
            });
        });
      } catch(e) { 
        console.error("Translation error", e); 
      } finally { 
        setIsTranslating(false); 
      }
    };
    loadTranslation();
  }, [currentPage, settings.targetLanguage, pages]); // Pages dependency ensures it triggers after paginateText finishes

  useEffect(() => {
    if (audioRef.current) {
        audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    const syncPlayback = () => {
        if (!audioRef.current) return;
        const audio = audioRef.current;
        const t = audio.currentTime;
        setCurrentTime(t);
        setDuration(audio.duration || 0);
        setPlaybackProgress((t / (audio.duration || 1)) * 100);

        // Accurate timing search
        const activeIdx = timings.findIndex(chunk => !chunk.isWhitespace && t >= chunk.start && t < chunk.end);
        if (activeIdx !== -1 && activeIdx !== activeSentenceIndex) {
            setActiveSentenceIndex(activeIdx);
        }

        if (canvasRef.current && !isModuleMinimized) {
            const canvas = canvasRef.current;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.clearRect(0, 0, canvas.width, canvas.height);
                const centerX = canvas.width / 2;
                const bars = 40;
                const step = canvas.width / 2 / bars;
                for (let i = 0; i < bars; i++) {
                    const value = Math.random() * 255; 
                    const h = isPlaying ? (value / 255) * canvas.height * 0.9 : 2;
                    ctx.fillStyle = isPlaying ? `rgb(${value}, ${243 - value}, 255)` : `rgb(30, 41, 59)`;
                    ctx.fillRect(centerX + (i * step), (canvas.height - h) / 2, step - 2, h);
                    ctx.fillRect(centerX - ((i + 1) * step), (canvas.height - h) / 2, step - 2, h);
                }
            }
        }
        if (isPlaying) animationRef.current = requestAnimationFrame(syncPlayback);
    };
    if (isPlaying) animationRef.current = requestAnimationFrame(syncPlayback);
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, timings, audioSrc, isModuleMinimized, activeSentenceIndex]);

  useEffect(() => {
    if (!autoScroll) return;
    if (activeSentenceIndex !== -1 && flatSentenceMap[activeSentenceIndex]) {
        const sentenceEl = document.getElementById(`original-sent-${activeSentenceIndex}`);
        if (sentenceEl) sentenceEl.scrollIntoView({ behavior: 'smooth', block: 'center', inline: 'nearest' });
    }
  }, [activeSentenceIndex, autoScroll, flatSentenceMap]); 

  const handleInitiateToggle = async () => {
    if (isGenerating) {
        abortGenerationRef.current = true;
        setIsGenerating(false);
        setHasInitiated(true);
        return;
    }
    generatePageAudio();
  };

  const generatePageAudio = async () => {
    if (isGenerating || !flatSentenceMap.length) return;
    abortGenerationRef.current = false;
    setIsGenerating(true);
    setHasInitiated(true);
    setGenerationProgress("INIT_VOICE_CORE...");
    try {
      let sentencesToSpeak: string[] = [];
      if (audioLanguage === 'Original') {
          sentencesToSpeak = flatSentenceMap.map(m => m.text);
      } else {
          if (audioLanguage === settings.targetLanguage && paragraphData.every(p => p.translated.length > 0)) {
              sentencesToSpeak = paragraphData.flatMap(p => p.translated);
          } else {
              setGenerationProgress("AUDIO_TRANS...");
              sentencesToSpeak = await translateSentences(flatSentenceMap.map(m => m.text), audioLanguage);
          }
      }

      const batchedSentences: string[] = [];
      for (let i = 0; i < sentencesToSpeak.length; i += TTS_BATCH_SIZE) {
          batchedSentences.push(sentencesToSpeak.slice(i, i + TTS_BATCH_SIZE).join(' '));
      }

      const audioResults = await processQueue<string, string | null>(
        batchedSentences, 
        CONCURRENCY_LIMIT, 
        async (batchText, idx) => {
           if (abortGenerationRef.current) return null;
           setGenerationProgress(`PACKET_${idx + 1}_OF_${batchedSentences.length}`);
           return await generateSpeech(batchText, selectedVoice);
        },
        () => abortGenerationRef.current
      );

      if (abortGenerationRef.current) return;

      const audioBuffers: Uint8Array[] = [];
      const newTimings: ChunkTiming[] = [];
      let currentByteOffset = 0;
      const BYTES_PER_SEC = 48000; // 24000Hz * 16bit * 1channel

      for (let i = 0; i < audioResults.length; i++) {
        const b64 = audioResults[i];
        const startIndex = i * TTS_BATCH_SIZE;
        const endIndex = Math.min(startIndex + TTS_BATCH_SIZE, sentencesToSpeak.length);
        const batchSentencesSubset = sentencesToSpeak.slice(startIndex, endIndex);
        const sentenceCount = batchSentencesSubset.length;

        if (!b64) {
          for(let k = 0; k < sentenceCount; k++) {
              newTimings.push({ text: sentencesToSpeak[startIndex + k], start: currentByteOffset / BYTES_PER_SEC, end: currentByteOffset / BYTES_PER_SEC, isWhitespace: true });
          }
          continue;
        }

        const binaryString = atob(b64);
        const bytes = new Uint8Array(binaryString.length);
        for (let k = 0; k < binaryString.length; k++) bytes[k] = binaryString.charCodeAt(k);
        audioBuffers.push(bytes);

        const durationSec = bytes.length / BYTES_PER_SEC;

        // IMPROVED: Weighted distribution of time based on character count for better sync
        const totalCharsInBatch = batchSentencesSubset.reduce((acc, s) => acc + s.length, 0);
        let batchOffset = 0;
        for (let k = 0; k < sentenceCount; k++) {
            const sText = batchSentencesSubset[k];
            const sDuration = (sText.length / (totalCharsInBatch || 1)) * durationSec;
            const startSec = (currentByteOffset / BYTES_PER_SEC) + batchOffset;

            newTimings.push({ 
                text: sText, 
                start: startSec, 
                end: startSec + sDuration, 
                isWhitespace: false 
            });
            batchOffset += sDuration;
        }
        currentByteOffset += bytes.length;
      }

      const mergedBuffer = new Uint8Array(currentByteOffset);
      let offset = 0;
      for (const buf of audioBuffers) { mergedBuffer.set(buf, offset); offset += buf.length; }

      const wavHeader = new ArrayBuffer(44);
      const view = new DataView(wavHeader);
      const writeString = (v: DataView, o: number, s: string) => { for (let k = 0; k < s.length; k++) v.setUint8(o + k, s.charCodeAt(k)); };
      writeString(view, 0, 'RIFF'); view.setUint32(4, 36 + currentByteOffset, true); writeString(view, 8, 'WAVE'); writeString(view, 12, 'fmt '); view.setUint32(16, 16, true); view.setUint16(20, 1, true); view.setUint16(22, 1, true); view.setUint32(24, 24000, true); view.setUint32(28, 48000, true); view.setUint16(32, 2, true); view.setUint16(34, 16, true); writeString(view, 36, 'data'); view.setUint32(40, currentByteOffset, true);

      const url = URL.createObjectURL(new Blob([wavHeader, mergedBuffer], { type: 'audio/wav' }));
      setTimings(newTimings); 
      setAudioSrc(url); 
    } catch(e) {
      console.error(e);
      setGenerationProgress("ERR_LINK_FAILED");
    } finally { setIsGenerating(false); }
  };

  const togglePlay = async () => {
    if (!audioSrc || !audioRef.current) return;
    try {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
      } else {
        const playPromise = audioRef.current.play();
        if (playPromise !== undefined) {
          await playPromise.catch(e => {
            if (e.name !== 'AbortError') throw e;
          });
          setIsPlaying(true);
        }
      }
    } catch (err) {
      console.warn("Playback interrupted:", err);
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (audioRef.current && duration) {
       audioRef.current.currentTime = (val / 100) * duration;
    }
  };

  if (isLoadingText) return <Loader text="DECODING_TEXT_BLOCK..." className="h-full" />;

  const currentStatusLabel = isGenerating ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE";
  const currentStatusIcon = isGenerating ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />;

  return (
    <div className="h-full flex flex-col gap-4 animate-fade-in relative font-sans text-zinc-100 text-left" style={{ fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' }}>
      <audio 
        ref={audioRef} 
        src={audioSrc || undefined} 
        onEnded={() => setIsPlaying(false)} 
        onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
        className="hidden" 
      />

      {/* Controller Toolbar */}
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2 z-20">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Headphones size={18} className="text-[#00f3ff]" />
                 <span>Voice_Synth</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedVoice} onChange={(e) => { setSelectedVoice(e.target.value); resetAudioState(); }} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">
                    {VOICES.map(v => <option key={v.name} value={v.name}>{v.name}</option>)}
                 </select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={audioLanguage} onChange={(e) => { setAudioLanguage(e.target.value); resetAudioState(); }} className="bg-transparent text-xs text-[#00f3ff] outline-none font-mono uppercase w-[120px] bg-[#050505] cursor-pointer">
                    {LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>
              <button 
                onClick={handleInitiateToggle} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isGenerating ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {currentStatusIcon}
                 {currentStatusLabel}
              </button>
          </div>
      </div>

      <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isModuleMinimized ? 'h-auto' : 'h-[277px]'}`}>
          {!isModuleMinimized && (
              <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                 <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>
                 {isGenerating ? (
                    <div className="z-20 scale-75 animate-fade-in"><Loader text={generationProgress} /></div>
                 ) : (
                    <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                 )}
                 <div className="absolute bottom-0 left-0 w-full h-1 bg-zinc-900 z-30 group cursor-pointer">
                    <input type="range" min="0" max="100" value={playbackProgress} onChange={handleSeek} disabled={!audioSrc} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-40" />
                    <div className="h-full bg-[#00f3ff] relative transition-all duration-100 ease-linear shadow-[0_0_10px_#00f3ff]" style={{ width: `${playbackProgress}%` }} />
                 </div>
              </div>
          )}

          <div className="bg-[#020202] p-3 flex items-center justify-between">
              <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                   {RATES.map(s => (
                     <button key={s} onClick={() => setPlaybackRate(s)} className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}>{s.toFixed(2)}x</button>
                   ))}
              </div>
              <div className="flex-2 flex items-center justify-center gap-6">
                  <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                  <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>
                    {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}
                  </button>
                  <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
              </div>
              <div className="flex-1 flex justify-end gap-2 items-center">
                  <span className="text-[10px] font-mono text-zinc-600 mr-2">{formatTime(currentTime)} / {formatTime(duration)}</span>
                  <a href={audioSrc || '#'} download={`lumina-voice-pg${currentPage + 1}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()}><Download size={20} /></a>
                  <button onClick={() => setIsModuleMinimized(!isModuleMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50">{isModuleMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
              </div>
          </div>
      </div>

      <div className="flex shrink-0 border border-zinc-800 bg-[#0a0a0c]/90 backdrop-blur-md rounded-sm z-10 w-full flex-col overflow-hidden">
          <div className="flex items-center justify-between p-2">
               <div className="flex items-center gap-2">
                  <button onClick={() => setCurrentPage(prev => Math.max(0, prev - 1))} disabled={currentPage === 0} className="flex items-center justify-center w-10 py-1.5 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all"><ChevronLeft size={14} /></button>
                  <h3 className="text-[10px] font-bold text-[#00f3ff] font-tech uppercase tracking-widest px-4">PG.{String(currentPage + 1).padStart(2,'0')}</h3>
                  <button onClick={() => setCurrentPage(prev => Math.min(pages.length - 1, prev + 1))} disabled={currentPage === pages.length - 1} className="flex items-center justify-center w-10 py-1.5 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all"><ChevronRight size={14} /></button>
              </div>
              <div className="flex items-center gap-2">
                  <button onClick={() => setViewMode(viewMode === 'split' ? 'single' : 'split')} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-[10px] font-bold font-mono uppercase transition-all min-w-[120px] justify-center ${viewMode === 'split' ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}><Columns size={12} /> SPLIT_VIEW</button>
                  <button onClick={() => setAutoScroll(!autoScroll)} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-[10px] font-bold font-mono uppercase transition-all min-w-[120px] justify-center ${autoScroll ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}><Eye size={12} /> SYNC_TRACK</button>
               </div>
          </div>
      </div>

      <div className="flex-1 overflow-hidden rounded-sm border border-zinc-800 bg-[#050505] relative flex flex-col hud-border text-left">
         <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8 pb-32">
            {paragraphData.map((para, pIdx) => (
                <div key={pIdx} className={`w-full flex ${viewMode === 'split' ? '' : 'justify-center'}`}>
                    <div className={`${viewMode === 'split' ? 'w-1/2 pr-6 border-r border-zinc-800/20' : 'w-full max-w-3xl'} ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} ${LETTER_SPACINGS[settings.letterSpacing]} text-zinc-400 font-medium`}>
                        {para.original.map((sentence, sIdx) => {
                            const mapping = flatSentenceMap.find(m => m.pIndex === pIdx && m.sIndex === sIdx);
                            const globalIdx = mapping?.globalIndex ?? -1;
                            const isActive = autoScroll && globalIdx === activeSentenceIndex;
                            return (
                                <span key={sIdx} id={`original-sent-${globalIdx}`} className={`transition-all duration-300 px-[2px] ${isActive ? HIGHLIGHT_STYLES[settings.highlightColor] : 'hover:text-zinc-200 cursor-pointer'}`} onClick={() => { if(audioRef.current && timings[globalIdx]) { audioRef.current.currentTime = timings[globalIdx].start; togglePlay(); } }}>
                                    {sentence}{' '}
                                </span>
                            );
                        })}
                    </div>
                    {viewMode === 'split' && (
                        <div className={`w-1/2 pl-6 ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} ${LETTER_SPACINGS[settings.letterSpacing]} text-zinc-500 font-medium`}>
                            {isTranslating && para.translated.length === 0 ? (
                                <span className="animate-pulse text-[10px] font-mono text-zinc-700 uppercase">Decrypting_Matrix...</span>
                            ) : (
                                para.original.map((_, sIdx) => {
                                    const mapping = flatSentenceMap.find(m => m.pIndex === pIdx && m.sIndex === sIdx);
                                    const globalIdx = mapping?.globalIndex ?? -1;
                                    const isActive = autoScroll && globalIdx === activeSentenceIndex;
                                    const tText = para.translated[sIdx] || "";
                                    return (
                                        <span key={sIdx} className={`transition-all duration-500 px-[2px] ${isActive ? HIGHLIGHT_STYLES[settings.highlightColor] : ''}`}>
                                            {tText}{' '}
                                        </span>
                                    );
                                })
                            )}
                        </div>
                    )}
                </div>
            ))}
         </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Book, Copy, Search, Loader2, BookOpen, FilePlus, Volume2, Languages } from 'lucide-react';
import { getQuickDefinition, generateSpeech, translateText } from '../services/gemini';
import { NotebookItem } from '../types';

interface Props {
  onAddToNotebook: (item: Omit<NotebookItem, 'id' | 'timestamp'>) => void;
  activeLanguage: string;
}

interface ContextMenuState {
  visible: boolean;
  x: number;
  y: number;
  text: string;
  source: string; // New field for context source
}

interface DefinitionState {
  visible: boolean;
  loading: boolean;
  text: string | null;
  originalText: string | null;
  translatedText: string | null;
  isTranslated: boolean;
  position: { x: number; y: number };
}

export const GlobalContextLayer: React.FC<Props> = ({ onAddToNotebook, activeLanguage }) => {
  const [menu, setMenu] = useState<ContextMenuState>({ visible: false, x: 0, y: 0, text: '', source: 'Input_Stream' });
  const [definition, setDefinition] = useState<DefinitionState>({ 
      visible: false, 
      loading: false, 
      text: null, 
      originalText: null,
      translatedText: null,
      isTranslated: false,
      position: { x: 0, y: 0 } 
  });
  const [isPlaying, setIsPlaying] = useState(false);
  const [isTranslating, setIsTranslating] = useState(false);

  const menuRef = useRef<HTMLDivElement>(null);
  const defRef = useRef<HTMLDivElement>(null);

  // Helper to wrap raw PCM bytes in a WAV header for browser compatibility
  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);

    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };

    /* RIFF identifier */
    writeString(view, 0, 'RIFF');
    /* file length */
    view.setUint32(4, 36 + len, true);
    /* RIFF type */
    writeString(view, 8, 'WAVE');
    /* format chunk identifier */
    writeString(view, 12, 'fmt ');
    /* format chunk length */
    view.setUint32(16, 16, true);
    /* sample format (raw) */
    view.setUint16(20, 1, true);
    /* channel count */
    view.setUint16(22, 1, true);
    /* sample rate */
    view.setUint32(24, 24000, true);
    /* byte rate (sample rate * block align) */
    view.setUint32(28, 24000 * 2, true);
    /* block align (channel count * bytes per sample) */
    view.setUint16(32, 2, true);
    /* bits per sample */
    view.setUint16(34, 16, true);
    /* data chunk identifier */
    writeString(view, 36, 'data');
    /* data chunk length */
    view.setUint32(40, len, true);

    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

    return new Blob([buffer], { type: 'audio/wav' });
  };

  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => {
      const selection = window.getSelection();
      const text = selection?.toString().trim();

      if (text && text.length > 0) {
        e.preventDefault();

        // Calculate position (keep within bounds)
        let x = e.clientX;
        let y = e.clientY;

        // Simple boundary check
        if (x + 200 > window.innerWidth) x = window.innerWidth - 210;
        if (y + 150 > window.innerHeight) y = window.innerHeight - 160;

        // Detect Source
        let source = "Input_Stream";
        let node = selection.anchorNode;
        while(node && node !== document.body) {
            if (node instanceof Element && node.getAttribute('data-source')) {
                source = node.getAttribute('data-source') || "Input_Stream";
                break;
            }
            node = node.parentElement;
        }

        setMenu({ visible: true, x, y, text, source });
        // Hide previous definition
        setDefinition(prev => ({ ...prev, visible: false }));
      }
    };

    const handleClick = (e: MouseEvent) => {
      // Close menu if clicked outside
      if (menu.visible && menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setMenu(prev => ({ ...prev, visible: false }));
      }

      // Close definition if clicked outside (and not clicking inside a menu that might be triggering it)
      if (definition.visible && defRef.current && !defRef.current.contains(e.target as Node)) {
          setDefinition(prev => ({ ...prev, visible: false }));
      }
    };

    document.addEventListener('contextmenu', handleContextMenu);
    document.addEventListener('mousedown', handleClick); // mousedown often better for outside click

    return () => {
      document.removeEventListener('contextmenu', handleContextMenu);
      document.removeEventListener('mousedown', handleClick);
    };
  }, [menu.visible, definition.visible]);

  const handleDefine = async (e: React.MouseEvent) => {
    // Stop propagation so the document click handler doesn't immediately close the new definition
    e.stopPropagation();
    e.nativeEvent.stopImmediatePropagation();

    // Show definition loader near the menu position
    setDefinition({ 
        visible: true, 
        loading: true, 
        text: null, 
        originalText: null,
        translatedText: null,
        isTranslated: false,
        position: { x: menu.x, y: menu.y } 
    });
    setMenu(prev => ({ ...prev, visible: false }));

    try {
        const def = await getQuickDefinition(menu.text, activeLanguage);
        setDefinition(prev => ({ 
            ...prev, 
            loading: false, 
            text: def,
            originalText: def 
        }));
    } catch (e) {
        setDefinition(prev => ({ ...prev, loading: false, text: "Could not retrieve definition." }));
    }
  };

  const handleTranslateToggle = async () => {
      if (isTranslating || definition.loading || !definition.text) return;

      // Toggle logic
      if (definition.isTranslated) {
          // Switch back to original
           setDefinition(prev => ({
              ...prev,
              text: prev.originalText,
              isTranslated: false
          }));
      } else {
          // Switch to translation
          if (definition.translatedText) {
              setDefinition(prev => ({
                  ...prev,
                  text: prev.translatedText,
                  isTranslated: true
              }));
          } else {
              // Fetch
              setIsTranslating(true);
              setDefinition(prev => ({ ...prev, loading: true }));

              try {
                  const trans = await translateText(definition.originalText || definition.text, activeLanguage);
                  setDefinition(prev => ({ 
                      ...prev, 
                      loading: false, 
                      text: trans,
                      translatedText: trans,
                      isTranslated: true
                  }));
              } catch(e) {
                  setDefinition(prev => ({ ...prev, loading: false }));
              } finally {
                  setIsTranslating(false);
              }
          }
      }
  };

  const handlePronounce = async () => {
      if (isPlaying || !menu.text) return;
      setIsPlaying(true);
      let audioUrl: string | null = null;
      try {
          const b64 = await generateSpeech(menu.text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setIsPlaying(false);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setIsPlaying(false);
          }
      } catch (e) {
          console.error(e);
          setIsPlaying(false);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const handleAddToNotebook = () => {
     onAddToNotebook({
         text: menu.text,
         type: menu.text.includes(' ') && menu.text.length > 30 ? 'sentence' : 'word',
         definition: undefined,
         contextSource: menu.source
     });
     setMenu(prev => ({ ...prev, visible: false }));
  };

  const handleSaveWithDefinition = () => {
      onAddToNotebook({
         text: menu.text,
         type: menu.text.includes(' ') && menu.text.length > 30 ? 'sentence' : 'word',
         definition: definition.text || undefined,
         contextSource: menu.source
      });
      setDefinition(prev => ({ ...prev, visible: false }));
  };

  // Helper to format definition text
  const formatDefinition = (text: string) => {
      if (!text) return null;
      // Split by double newlines for sections
      return text.split('\n\n').map((section, idx) => {
          // Check for headers like "Definition:", "Usage:"
          const parts = section.split(':');
          if (parts.length > 1 && parts[0].length < 20) {
             return (
                 <div key={idx} className="mb-3">
                     <span className="text-[#00f3ff] font-bold uppercase text-[10px] tracking-widest">{parts[0]}:</span>
                     <p className="mt-1 text-zinc-300">{parts.slice(1).join(':').trim()}</p>
                 </div>
             );
          }
          return <p key={idx} className="mb-3 text-zinc-300">{section}</p>;
      });
  };

  return (
    <div className="fixed inset-0 z-[100] pointer-events-none font-sans text-left">
        {/* Context Menu */}
        {menu.visible && (
            <div 
                ref={menuRef}
                className="absolute bg-[#0a0a0c] border border-cyan-900/50 shadow-[0_0_20px_rgba(0,0,0,0.8)] rounded-sm overflow-hidden min-w-[180px] pointer-events-auto animate-fade-in origin-top-left z-[101]"
                style={{ top: menu.y, left: menu.x }}
            >
                <div className="px-3 py-2 bg-zinc-900 border-b border-zinc-800 text-[10px] text-zinc-500 font-mono uppercase truncate max-w-[200px]">
                    {menu.text.length > 20 ? menu.text.substring(0, 20) + '...' : menu.text}
                </div>
                <div className="p-1">
                    <button 
                        onClick={handleDefine}
                        className="w-full text-left px-3 py-2 text-zinc-300 hover:bg-[#00f3ff]/10 hover:text-[#00f3ff] text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"
                    >
                        <Search size={14} />
                        Explain / Define
                    </button>
                    <button 
                        onClick={handleAddToNotebook}
                        className="w-full text-left px-3 py-2 text-zinc-300 hover:bg-[#00f3ff]/10 hover:text-[#00f3ff] text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"
                    >
                        <FilePlus size={14} />
                        Add to Notebook
                    </button>
                    <button 
                        onClick={() => {
                            navigator.clipboard.writeText(menu.text);
                            setMenu(prev => ({ ...prev, visible: false }));
                        }}
                        className="w-full text-left px-3 py-2 text-zinc-500 hover:bg-zinc-800 hover:text-zinc-300 text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"
                    >
                        <Copy size={14} />
                        Copy Text
                    </button>
                </div>
            </div>
        )}

        {/* Definition Popup */}
        {definition.visible && (
             <div 
                ref={defRef}
                className="absolute bg-[#050505]/95 backdrop-blur-md border border-[#00f3ff]/30 shadow-[0_0_30px_rgba(0,0,0,0.9)] rounded-lg p-5 w-80 pointer-events-auto animate-fade-in-up origin-top-left z-[102] max-h-[400px] flex flex-col"
                style={{ top: definition.position.y, left: definition.position.x }}
             >
                 <div className="flex items-start justify-between mb-3 shrink-0">
                     <h3 className="text-[#00f3ff] font-bold font-mono text-sm uppercase tracking-wider flex items-center gap-2">
                         <BookOpen size={16} />
                         Analysis
                     </h3>
                     <div className="flex items-center gap-2">
                         <button
                           onClick={handleTranslateToggle}
                           disabled={isTranslating || definition.loading || !definition.text}
                           className={`transition-colors ${definition.isTranslated || isTranslating ? 'text-[#00f3ff] animate-pulse' : 'text-zinc-400 hover:text-[#00f3ff]'}`}
                           title={definition.isTranslated ? "Show Original" : `Translate to ${activeLanguage}`}
                         >
                            <Languages size={16} />
                         </button>
                         <button
                           onClick={handlePronounce}
                           disabled={isPlaying || definition.loading}
                           className={`text-zinc-400 hover:text-[#00f3ff] transition-colors ${isPlaying ? 'animate-pulse text-[#00f3ff]' : ''}`}
                           title="Pronounce"
                         >
                            <Volume2 size={16} />
                         </button>
                         <button 
                           onClick={() => setDefinition(prev => ({ ...prev, visible: false }))}
                           className="text-zinc-600 hover:text-white transition-colors"
                         >
                            ×
                         </button>
                     </div>
                 </div>

                 <div className="mb-4 overflow-y-auto custom-scrollbar flex-1 text-sm">
                     {definition.loading ? (
                         <div className="flex items-center gap-2 text-zinc-500 text-xs font-mono py-2">
                             <Loader2 size={14} className="animate-spin" />
                             Processing Neural Data...
                         </div>
                     ) : (
                         <div className="leading-relaxed font-serif border-l-2 border-zinc-800 pl-3">
                             {formatDefinition(definition.text || "")}
                         </div>
                     )}
                 </div>

                 {!definition.loading && (
                     <button
                        onClick={handleSaveWithDefinition}
                        className="w-full py-2 bg-zinc-900 hover:bg-[#00f3ff]/20 text-zinc-400 hover:text-[#00f3ff] border border-zinc-800 hover:border-[#00f3ff]/50 rounded-sm text-xs font-mono uppercase transition-all flex items-center justify-center gap-2 shrink-0"
                     >
                         <FilePlus size={14} />
                         Save to Notebook
                     </button>
                 )}
             </div>
        )}
    </div>
  );
};

