import React, { useState } from 'react';
import { NotebookItem, AppSettings } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Type, CheckSquare, Square, ListChecks, X as XIcon, Play, RefreshCw, Zap, ChevronLeft, ChevronRight, RotateCcw } from 'lucide-react';
import { generateSpeech } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  settings: AppSettings;
}

type FilterType = 'word' | 'phrase' | 'sentence';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('word');

  // Selection State
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Flashcard State
  const [isFlashcardMode, setIsFlashcardMode] = useState(false);
  const [currentFlashcardIndex, setCurrentFlashcardIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  // Helper to wrap raw PCM bytes in a WAV header for browser compatibility
  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);

    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };

    /* RIFF identifier */
    writeString(view, 0, 'RIFF');
    /* file length */
    view.setUint32(4, 36 + len, true);
    /* RIFF type */
    writeString(view, 8, 'WAVE');
    /* format chunk identifier */
    writeString(view, 12, 'fmt ');
    /* format chunk length */
    view.setUint32(16, 16, true);
    /* sample format (raw) */
    view.setUint16(20, 1, true);
    /* channel count */
    view.setUint16(22, 1, true);
    /* sample rate */
    view.setUint32(24, 24000, true);
    /* byte rate (sample rate * block align) */
    view.setUint32(28, 24000 * 2, true);
    /* block align (channel count * bytes per sample) */
    view.setUint16(32, 2, true);
    /* bits per sample */
    view.setUint16(34, 16, true);
    /* data chunk identifier */
    writeString(view, 36, 'data');
    /* data chunk length */
    view.setUint32(40, len, true);

    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      canvas.width = 800;
      canvas.height = 800;

      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) {
        ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke();
      }
      for(let i=0; i < canvas.height; i+=40) {
        ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke();
      }

      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);

      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);

      let y = margin + 40;

      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;

      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }

      if (item.sourceChapter) {
          ctx.fillStyle = '#22d3ee';
          ctx.font = '16px "Courier New", monospace';
          ctx.fillText(`CHAPTER: ${item.sourceChapter.substring(0, 35)}`, margin, y);
          y += 25;
      }

      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;

      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;

      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';

      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };

      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }

      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);

      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) {
         ctx.fillText(lines[i], margin, y); y += lineHeight;
      }
      y += 30;

      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }

      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);

      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const filteredItems = items.filter(item => item.type === activeFilter);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const selectAll = () => {
    if (selectedIds.size === filteredItems.length) setSelectedIds(new Set());
    else setSelectedIds(new Set(filteredItems.map(i => i.id)));
  };

  const executeBulkDelete = () => {
      onBulkDelete(Array.from(selectedIds));
      setSelectedIds(new Set());
      setIsSelectionMode(false);
  };

  const startFlashcards = () => {
      if (filteredItems.length === 0) return;
      setCurrentFlashcardIndex(0);
      setIsFlipped(false);
      setIsFlashcardMode(true);
  };

  const nextCard = () => {
      setIsFlipped(false);
      setCurrentFlashcardIndex((prev) => (prev + 1) % filteredItems.length);
  };

  const prevCard = () => {
      setIsFlipped(false);
      setCurrentFlashcardIndex((prev) => (prev - 1 + filteredItems.length) % filteredItems.length);
  };

  if (isFlashcardMode && filteredItems.length > 0) {
      const item = filteredItems[currentFlashcardIndex];
      return (
          <div className="fixed inset-0 z-[200] bg-black/95 flex flex-col items-center justify-center p-6 animate-fade-in font-sans">
              <div className="absolute top-8 right-8">
                  <button 
                    onClick={() => setIsFlashcardMode(false)}
                    className="p-3 bg-zinc-900 text-zinc-400 hover:text-white rounded-full transition-all border border-zinc-800"
                  >
                      <XIcon size={24} />
                  </button>
              </div>

              <div className="text-center mb-8">
                  <h2 className="text-[#00f3ff] font-tech text-xs uppercase tracking-[0.4em] mb-2 animate-pulse">Neural_Study_Session</h2>
                  <p className="text-zinc-600 font-mono text-[10px]">LOG_INDEX: {currentFlashcardIndex + 1} / {filteredItems.length}</p>
              </div>

              <div 
                onClick={() => setIsFlipped(!isFlipped)}
                className={`relative w-full max-w-2xl aspect-[4/3] perspective-1000 cursor-pointer group`}
              >
                  <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                      {/* Front */}
                      <div className="absolute inset-0 backface-hidden bg-[#0a0a0c] border-2 border-[#00f3ff]/30 rounded-2xl flex flex-col items-center justify-center p-12 text-center shadow-[0_0_50px_rgba(0,243,255,0.1)]">
                          <div className="absolute top-6 left-6 text-[#00f3ff] opacity-20"><Zap size={48} /></div>
                          <p className="text-3xl md:text-4xl font-black text-white leading-tight font-serif italic">"{item.text}"</p>
                          <p className="absolute bottom-10 text-zinc-700 font-mono text-[10px] uppercase tracking-widest animate-bounce">Click to Decode Definition</p>
                      </div>

                      {/* Back */}
                      <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#050505] border-2 border-[#ff003c]/30 rounded-2xl flex flex-col items-center justify-center p-12 text-center shadow-[0_0_50px_rgba(255,0,60,0.1)]">
                          <div className="absolute top-6 right-6 text-[#ff003c] opacity-20"><RotateCcw size={48} /></div>
                          <div className="space-y-6 max-w-md">
                              <div>
                                  <h4 className="text-[#ff003c] font-mono text-xs uppercase tracking-widest mb-2 font-bold">Definition:</h4>
                                  <p className="text-xl text-zinc-300 font-mono leading-relaxed">{item.definition || "NO_DATA_LOGGED"}</p>
                              </div>
                              {item.comment && (
                                  <div className="pt-6 border-t border-zinc-800">
                                      <h4 className="text-amber-500 font-mono text-xs uppercase tracking-widest mb-2 font-bold">User_Annotation:</h4>
                                      <p className="text-base text-zinc-500 font-mono italic">"{item.comment}"</p>
                                  </div>
                              )}
                          </div>
                          <p className="absolute bottom-10 text-zinc-700 font-mono text-[10px] uppercase tracking-widest">Click to Review Snippet</p>
                      </div>
                  </div>
              </div>

              <div className="mt-12 flex items-center gap-12">
                  <button onClick={prevCard} className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-[#00f3ff] hover:border-[#00f3ff] rounded-full transition-all hover:scale-110"><ChevronLeft size={32} /></button>
                  <button onClick={nextCard} className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-[#00f3ff] hover:border-[#00f3ff] rounded-full transition-all hover:scale-110"><ChevronRight size={32} /></button>
              </div>

              <style>{`
                  .perspective-1000 { perspective: 1000px; }
                  .backface-hidden { backface-visibility: hidden; }
                  .rotate-y-180 { transform: rotateY(180deg); }
                  .transform-style-3d { transform-style: preserve-3d; }
              `}</style>
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left" style={fontStyle}>
       {/* New Flash_Notes Controller Toolbar */}
       <div className="mb-6 bg-zinc-950/80 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,0,0,0.5)] flex-wrap gap-3">
           {/* Segmented Filter */}
           <div className="flex bg-black p-1 rounded-sm border border-zinc-800">
                {(['word', 'phrase', 'sentence'] as const).map(f => (
                    <button 
                        key={f}
                        onClick={() => { setActiveFilter(f); setSelectedIds(new Set()); setIsSelectionMode(false); }}
                        className={`px-4 py-1.5 text-[10px] font-bold font-mono uppercase transition-all min-w-[100px] rounded-sm ${activeFilter === f ? 'bg-zinc-800 text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.2)]' : 'text-zinc-500 hover:text-zinc-300'}`}
                    >
                        {f}S
                    </button>
                ))}
           </div>

           <div className="flex items-center gap-3">
               <button 
                onClick={() => { setIsSelectionMode(!isSelectionMode); setSelectedIds(new Set()); }}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-[10px] font-bold font-mono uppercase border transition-all ${isSelectionMode ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'}`}
               >
                   {isSelectionMode ? <XIcon size={14} /> : <ListChecks size={14} />}
                   {isSelectionMode ? "EXIT_BATCH" : "BATCH_OPS"}
               </button>

               <button 
                 onClick={startFlashcards}
                 disabled={filteredItems.length === 0}
                 className="flex items-center gap-2 px-6 py-1.5 bg-[#00f3ff] text-black hover:bg-[#00c2cc] rounded-sm text-[10px] font-black font-mono uppercase transition-all shadow-[0_0_15px_rgba(0,243,255,0.3)] disabled:opacity-30 disabled:cursor-not-allowed"
               >
                   <Play size={14} fill="currentColor" />
                   INITIATE_FLASHCARDS
               </button>
           </div>
       </div>

       {/* Batch Operation Floating Toolbar */}
       {isSelectionMode && (
         <div className="mb-4 bg-[#ff003c]/5 border border-[#ff003c]/20 p-2 rounded flex items-center justify-between animate-fade-in shrink-0">
             <div className="flex items-center gap-4">
                 <button 
                    onClick={selectAll}
                    className="flex items-center gap-2 text-xs font-mono font-bold text-zinc-400 hover:text-white px-2 py-1 rounded hover:bg-zinc-800 transition-colors"
                 >
                     {selectedIds.size === filteredItems.length && filteredItems.length > 0 ? <CheckSquare size={14} className="text-[#ff003c]" /> : <Square size={14} />}
                     SELECT_ALL
                 </button>
                 <span className="text-[10px] font-mono text-[#ff003c] bg-[#ff003c]/10 px-2 py-0.5 rounded uppercase">
                     {selectedIds.size} SNIPPETS_TARGETED
                 </span>
             </div>

             <button 
                 onClick={executeBulkDelete}
                 disabled={selectedIds.size === 0}
                 className="flex items-center gap-2 px-3 py-1.5 bg-[#ff003c] text-white hover:bg-rose-600 rounded-sm text-xs font-mono font-bold uppercase disabled:opacity-30 disabled:cursor-not-allowed transition-all shadow-[0_0_15px_rgba(255,0,60,0.3)]"
             >
                 <Trash2 size={12} />
                 PURGE_SELECTED
             </button>
         </div>
       )}

       {items.length === 0 ? (
           <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in">
               <Book size={48} className="opacity-20" />
               <p className="text-sm">NO_DATA_LOGGED</p>
               <p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">
                   Right-click text selection to populate your neural lexicon.
               </p>
           </div>
       ) : filteredItems.length === 0 ? (
           <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in">
               <p className="text-xs uppercase tracking-widest opacity-50">NO_{activeFilter.toUpperCase()}S_FOUND_IN_BUFFER</p>
           </div>
       ) : (
           <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
               {filteredItems.map((item, idx) => {
                   const isSelected = selectedIds.has(item.id);
                   const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';

                   return (
                   <div key={item.id} className={`bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 ${isSelected ? 'border-[#ff003c] shadow-[0_0_15px_rgba(255,0,60,0.1)]' : 'border-zinc-800 hover:border-zinc-700 shadow-sm'}`} style={{ animationDelay: `${idx * 0.05}s` }}>

                       {isSelectionMode && (
                           <div 
                               onClick={() => toggleSelection(item.id)}
                               className="absolute inset-y-0 left-0 w-12 flex items-center justify-center z-30 cursor-pointer bg-gradient-to-r from-black/80 to-transparent"
                           >
                               {isSelected ? <CheckSquare size={20} className="text-[#ff003c]" /> : <Square size={20} className="text-zinc-600 hover:text-zinc-400" />}
                           </div>
                       )}

                       <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                           <button 
                             onClick={() => playPronunciation(item.id, item.text)}
                             disabled={!!playingId}
                             className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`}
                             title="Pronounce"
                           >
                               <Volume2 size={14} />
                           </button>
                           <button 
                             onClick={() => generateStickyNote(item)}
                             className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all"
                             title="Generate Visual Log"
                           >
                               <ImageDown size={14} />
                           </button>
                           <button 
                             onClick={() => onDelete(item.id)}
                             disabled={isSelectionMode}
                             className={`p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all ${isSelectionMode ? 'opacity-20 cursor-not-allowed' : ''}`}
                             title="Purge Entry"
                           >
                               <Trash2 size={14} />
                           </button>
                       </div>

                       <div className={`flex items-start gap-4 ${isSelectionMode ? 'pl-8 transition-all' : ''}`}>
                           <div className="mt-1 shrink-0">
                               {item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}
                           </div>
                           <div className="flex-1 min-w-0 space-y-3">
                               <div>
                                   <p className={`text-white text-base font-medium leading-relaxed font-serif break-words ${isSelected ? 'text-[#ff003c]' : ''}`}>"{item.text}"</p>
                                   <div className="flex items-center gap-3 mt-2 flex-wrap">
                                       <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>
                                           {item.type}
                                       </span>
                                       {item.bookTitle && (
                                           <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">
                                               {item.bookTitle}
                                           </span>
                                       )}
                                       {item.sourceChapter && (
                                           <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">
                                               CH: {item.sourceChapter}
                                           </span>
                                       )}
                                       <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1">
                                           <Clock size={10} />
                                           {new Date(item.timestamp).toLocaleDateString()}
                                       </span>
                                   </div>
                               </div>

                               {item.definition && (
                                   <div className="bg-black/50 p-3 rounded border border-zinc-900">
                                       <p className="text-sm text-zinc-500 italic font-mono leading-relaxed">
                                           {item.definition}
                                       </p>
                                   </div>
                               )}

                               <div className="mt-2">
                                   <textarea 
                                       placeholder="Add neural annotations..." 
                                       value={item.comment || ''}
                                       onChange={(e) => onUpdateComment(item.id, e.target.value)}
                                       className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono"
                                   />
                               </div>
                           </div>
                       </div>
                   </div>
                   );
               })}
           </div>
       )}
    </div>
  );
};

import React, { useState } from 'react';
import { NotebookItem, AppSettings } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Type, CheckSquare, Square, ListChecks, X as XIcon, Play, RefreshCw, Zap, ChevronLeft, ChevronRight, RotateCcw, Notebook as NotebookIcon, ChevronDown } from 'lucide-react';
import { generateSpeech } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  settings: AppSettings;
}

type FilterType = 'word' | 'phrase' | 'sentence';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('word');
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  // Selection State
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Flashcard State
  const [isFlashcardMode, setIsFlashcardMode] = useState(false);
  const [currentFlashcardIndex, setCurrentFlashcardIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const filteredItems = items.filter(item => item.type === activeFilter);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const selectAll = () => {
    if (selectedIds.size === filteredItems.length) setSelectedIds(new Set());
    else setSelectedIds(new Set(filteredItems.map(i => i.id)));
  };

  const executeBulkDelete = () => {
      onBulkDelete(Array.from(selectedIds));
      setSelectedIds(new Set());
      setIsSelectionMode(false);
  };

  const startFlashcards = () => {
      if (filteredItems.length === 0) return;
      setCurrentFlashcardIndex(0);
      setIsFlipped(false);
      setIsFlashcardMode(true);
  };

  if (isFlashcardMode && filteredItems.length > 0) {
      const item = filteredItems[currentFlashcardIndex];
      return (
          <div className="fixed inset-0 z-[200] bg-black/95 flex flex-col items-center justify-center p-6 animate-fade-in font-sans">
              <div className="absolute top-8 right-8">
                  <button onClick={() => setIsFlashcardMode(false)} className="p-3 bg-zinc-900 text-zinc-400 hover:text-white rounded-full transition-all border border-zinc-800">
                      <XIcon size={24} />
                  </button>
              </div>
              <div className="text-center mb-8">
                  <h2 className="text-[#00f3ff] font-tech text-xs uppercase tracking-[0.4em] mb-2 animate-pulse">Neural_Study_Session</h2>
                  <p className="text-zinc-600 font-mono text-[10px]">LOG_INDEX: {currentFlashcardIndex + 1} / {filteredItems.length}</p>
              </div>
              <div onClick={() => setIsFlipped(!isFlipped)} className="relative w-full max-w-2xl aspect-[4/3] perspective-1000 cursor-pointer group">
                  <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                      <div className="absolute inset-0 backface-hidden bg-[#0a0a0c] border-2 border-[#00f3ff]/30 rounded-2xl flex flex-col items-center justify-center p-12 text-center shadow-[0_0_50px_rgba(0,243,255,0.1)]">
                          <div className="absolute top-6 left-6 text-[#00f3ff] opacity-20"><Zap size={48} /></div>
                          <p className="text-3xl md:text-4xl font-black text-white leading-tight font-serif italic">"{item.text}"</p>
                          <p className="absolute bottom-10 text-zinc-700 font-mono text-[10px] uppercase tracking-widest animate-bounce">Click to Decode Definition</p>
                      </div>
                      <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#050505] border-2 border-[#ff003c]/30 rounded-2xl flex flex-col items-center justify-center p-12 text-center shadow-[0_0_50px_rgba(255,0,60,0.1)]">
                          <div className="absolute top-6 right-6 text-[#ff003c] opacity-20"><RotateCcw size={48} /></div>
                          <div className="space-y-6 max-w-md">
                              <div>
                                  <h4 className="text-[#ff003c] font-mono text-xs uppercase tracking-widest mb-2 font-bold">Definition:</h4>
                                  <p className="text-xl text-zinc-300 font-mono leading-relaxed">{item.definition || "NO_DATA_LOGGED"}</p>
                              </div>
                              {item.comment && (
                                  <div className="pt-6 border-t border-zinc-800">
                                      <h4 className="text-amber-500 font-mono text-xs uppercase tracking-widest mb-2 font-bold">User_Annotation:</h4>
                                      <p className="text-base text-zinc-500 font-mono italic">"{item.comment}"</p>
                                  </div>
                              )}
                          </div>
                          <p className="absolute bottom-10 text-zinc-700 font-mono text-[10px] uppercase tracking-widest">Click to Review Snippet</p>
                      </div>
                  </div>
              </div>
              <div className="mt-12 flex items-center gap-12">
                  <button onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex((prev) => (prev - 1 + filteredItems.length) % filteredItems.length); }} className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-[#00f3ff] hover:border-[#00f3ff] rounded-full transition-all hover:scale-110"><ChevronLeft size={32} /></button>
                  <button onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex((prev) => (prev + 1) % filteredItems.length); }} className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-[#00f3ff] hover:border-[#00f3ff] rounded-full transition-all hover:scale-110"><ChevronRight size={32} /></button>
              </div>
              <style>{`.perspective-1000 { perspective: 1000px; } .backface-hidden { backface-visibility: hidden; } .rotate-y-180 { transform: rotateY(180deg); } .transform-style-3d { transform-style: preserve-3d; }`}</style>
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left" style={fontStyle}>
       {/* Enhanced Controller Toolbar */}
       <div className="mb-6 bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shrink-0 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md z-40 relative">
           {/* Branding & Dropdown Filter */}
           <div className="flex items-center gap-6">
               <div className="flex items-center gap-3 border-r border-zinc-800 pr-6">
                   <div className="p-2 bg-[#00f3ff]/10 rounded-sm">
                      <NotebookIcon size={18} className="text-[#00f3ff]" />
                   </div>
                   <span className="text-sm font-tech font-bold text-white tracking-[0.2em] uppercase">Flash_Notes</span>
               </div>

               {/* Combined Dropdown Trigger */}
               <div className="relative">
                    <button 
                        onClick={() => setIsFilterOpen(!isFilterOpen)}
                        className="flex items-center gap-3 px-4 py-2 bg-black border border-zinc-800 rounded-sm text-[10px] font-bold font-mono uppercase text-[#00f3ff] hover:border-[#00f3ff]/50 transition-all min-w-[140px] justify-between group shadow-inner"
                    >
                        <span className="flex items-center gap-2">
                           <Type size={14} />
                           {activeFilter}S
                        </span>
                        <ChevronDown size={14} className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`} />
                    </button>

                    {isFilterOpen && (
                        <div className="absolute top-full left-0 mt-1 w-full bg-[#0a0a0c] border border-zinc-800 shadow-2xl rounded-sm overflow-hidden z-[60] animate-fade-in">
                            {(['word', 'phrase', 'sentence'] as const).map(f => (
                                <button 
                                    key={f}
                                    onClick={() => { setActiveFilter(f); setSelectedIds(new Set()); setIsSelectionMode(false); setIsFilterOpen(false); }}
                                    className={`w-full text-left px-4 py-3 text-[10px] font-bold font-mono uppercase transition-colors hover:bg-[#00f3ff]/10 ${activeFilter === f ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}
                                >
                                    {f}S
                                </button>
                            ))}
                        </div>
                    )}
               </div>

               <button 
                onClick={() => { setIsSelectionMode(!isSelectionMode); setSelectedIds(new Set()); }}
                className={`flex items-center gap-2 px-4 py-2 rounded-sm text-[10px] font-bold font-mono uppercase border transition-all ${isSelectionMode ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'}`}
               >
                   {isSelectionMode ? <XIcon size={14} /> : <ListChecks size={14} />}
                   {isSelectionMode ? "EXIT_BATCH" : "BATCH_OPS"}
               </button>
           </div>

           <div className="flex items-center">
               <button 
                 onClick={startFlashcards}
                 disabled={filteredItems.length === 0}
                 className="flex items-center gap-2 px-8 py-2 bg-[#00f3ff] text-black hover:bg-[#00c2cc] rounded-sm text-[11px] font-black font-mono uppercase transition-all shadow-[0_0_15px_rgba(0,243,255,0.4)] disabled:opacity-30 disabled:cursor-not-allowed transform active:scale-95"
               >
                   <Play size={14} fill="currentColor" />
                   INITIATE
               </button>
           </div>
       </div>

       {/* Batch Operation Toolbar */}
       {isSelectionMode && (
         <div className="mb-4 bg-[#ff003c]/5 border border-[#ff003c]/20 p-2 rounded flex items-center justify-between animate-fade-in shrink-0">
             <div className="flex items-center gap-4">
                 <button onClick={selectAll} className="flex items-center gap-2 text-xs font-mono font-bold text-zinc-400 hover:text-white px-2 py-1 rounded hover:bg-zinc-800 transition-colors">
                     {selectedIds.size === filteredItems.length && filteredItems.length > 0 ? <CheckSquare size={14} className="text-[#ff003c]" /> : <Square size={14} />}
                     SELECT_ALL
                 </button>
                 <span className="text-[10px] font-mono text-[#ff003c] bg-[#ff003c]/10 px-2 py-0.5 rounded uppercase">{selectedIds.size} SNIPPETS_TARGETED</span>
             </div>
             <button onClick={executeBulkDelete} disabled={selectedIds.size === 0} className="flex items-center gap-2 px-3 py-1.5 bg-[#ff003c] text-white hover:bg-rose-600 rounded-sm text-xs font-mono font-bold uppercase disabled:opacity-30 disabled:cursor-not-allowed transition-all shadow-[0_0_15px_rgba(255,0,60,0.3)]">
                 <Trash2 size={12} /> PURGE_SELECTED
             </button>
         </div>
       )}

       {items.length === 0 ? (
           <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in">
               <Book size={48} className="opacity-20" />
               <p className="text-sm">NO_DATA_LOGGED</p>
               <p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p>
           </div>
       ) : filteredItems.length === 0 ? (
           <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in">
               <p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter.toUpperCase()}S</p>
           </div>
       ) : (
           <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
               {filteredItems.map((item, idx) => {
                   const isSelected = selectedIds.has(item.id);
                   const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                   return (
                   <div key={item.id} className={`bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 ${isSelected ? 'border-[#ff003c] shadow-[0_0_15px_rgba(255,0,60,0.1)]' : 'border-zinc-800 hover:border-zinc-700'}`} style={{ animationDelay: `${idx * 0.05}s` }}>
                       {isSelectionMode && (
                           <div onClick={() => toggleSelection(item.id)} className="absolute inset-y-0 left-0 w-12 flex items-center justify-center z-30 cursor-pointer bg-gradient-to-r from-black/80 to-transparent">
                               {isSelected ? <CheckSquare size={20} className="text-[#ff003c]" /> : <Square size={20} className="text-zinc-600 hover:text-zinc-400" />}
                           </div>
                       )}
                       <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                           <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                           <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                           <button onClick={() => onDelete(item.id)} disabled={isSelectionMode} className={`p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all ${isSelectionMode ? 'opacity-20 cursor-not-allowed' : ''}`} title="Purge Entry"><Trash2 size={14} /></button>
                       </div>
                       <div className={`flex items-start gap-4 ${isSelectionMode ? 'pl-8 transition-all' : ''}`}>
                           <div className="mt-1 shrink-0">
                               {item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}
                           </div>
                           <div className="flex-1 min-w-0 space-y-3">
                               <div>
                                   <p className={`text-white text-base font-medium leading-relaxed font-serif break-words ${isSelected ? 'text-[#ff003c]' : ''}`}>"{item.text}"</p>
                                   <div className="flex items-center gap-3 mt-2 flex-wrap">
                                       <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                       {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                       {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                       <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                   </div>
                               </div>
                               {item.definition && (
                                   <div className="bg-black/50 p-3 rounded border border-zinc-900">
                                       <p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p>
                                   </div>
                               )}
                               <div className="mt-2">
                                   <textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" />
                               </div>
                           </div>
                       </div>
                   </div>
                   );
               })}
           </div>
       )}
    </div>
  );
};

import React, { useState } from 'react';
import { NotebookItem, AppSettings } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, CheckSquare, Square, ListChecks, X as XIcon, Play, RefreshCw, Zap, ChevronLeft, ChevronRight, RotateCcw, Notebook as NotebookIcon, ChevronDown, Settings2 } from 'lucide-react';
import { generateSpeech } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  settings: AppSettings;
}

type FilterType = 'word' | 'phrase' | 'sentence';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('word');
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  // Selection State
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Flashcard State
  const [isFlashcardMode, setIsFlashcardMode] = useState(false);
  const [currentFlashcardIndex, setCurrentFlashcardIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const filteredItems = items.filter(item => item.type === activeFilter);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const selectAll = () => {
    if (selectedIds.size === filteredItems.length) setSelectedIds(new Set());
    else setSelectedIds(new Set(filteredItems.map(i => i.id)));
  };

  const executeBulkDelete = () => {
      onBulkDelete(Array.from(selectedIds));
      setSelectedIds(new Set());
      setIsSelectionMode(false);
  };

  const startFlashcards = () => {
      if (filteredItems.length === 0) return;
      setCurrentFlashcardIndex(0);
      setIsFlipped(false);
      setIsFlashcardMode(true);
  };

  if (isFlashcardMode && filteredItems.length > 0) {
      const item = filteredItems[currentFlashcardIndex];
      return (
          <div className="fixed inset-0 z-[200] bg-black/95 flex flex-col items-center justify-center p-6 animate-fade-in font-sans text-left">
              <div className="absolute top-8 right-8">
                  <button onClick={() => setIsFlashcardMode(false)} className="p-3 bg-zinc-900 text-zinc-400 hover:text-white rounded-full transition-all border border-zinc-800">
                      <XIcon size={24} />
                  </button>
              </div>
              <div className="text-center mb-8">
                  <h2 className="text-[#00f3ff] font-tech text-xs uppercase tracking-[0.4em] mb-2 animate-pulse">Neural_Study_Session</h2>
                  <p className="text-zinc-600 font-mono text-[10px]">LOG_INDEX: {currentFlashcardIndex + 1} / {filteredItems.length}</p>
              </div>
              <div onClick={() => setIsFlipped(!isFlipped)} className="relative w-full max-w-2xl aspect-[4/3] perspective-1000 cursor-pointer group">
                  <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                      <div className="absolute inset-0 backface-hidden bg-[#0a0a0c] border-2 border-[#00f3ff]/30 rounded-2xl flex flex-col items-center justify-center p-12 text-center shadow-[0_0_50px_rgba(0,243,255,0.1)]">
                          <div className="absolute top-6 left-6 text-[#00f3ff] opacity-20"><Zap size={48} /></div>
                          <p className="text-3xl md:text-4xl font-black text-white leading-tight font-serif italic">"{item.text}"</p>
                          <p className="absolute bottom-10 text-zinc-700 font-mono text-[10px] uppercase tracking-widest animate-bounce">Click to Decode Definition</p>
                      </div>
                      <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#050505] border-2 border-[#ff003c]/30 rounded-2xl flex flex-col items-center justify-center p-12 text-center shadow-[0_0_50px_rgba(255,0,60,0.1)]">
                          <div className="absolute top-6 right-6 text-[#ff003c] opacity-20"><RotateCcw size={48} /></div>
                          <div className="space-y-6 max-w-md">
                              <div>
                                  <h4 className="text-[#ff003c] font-mono text-xs uppercase tracking-widest mb-2 font-bold">Definition:</h4>
                                  <p className="text-xl text-zinc-300 font-mono leading-relaxed">{item.definition || "NO_DATA_LOGGED"}</p>
                              </div>
                              {item.comment && (
                                  <div className="pt-6 border-t border-zinc-800">
                                      <h4 className="text-amber-500 font-mono text-xs uppercase tracking-widest mb-2 font-bold">User_Annotation:</h4>
                                      <p className="text-base text-zinc-500 font-mono italic">"{item.comment}"</p>
                                  </div>
                              )}
                          </div>
                          <p className="absolute bottom-10 text-zinc-700 font-mono text-[10px] uppercase tracking-widest">Click to Review Snippet</p>
                      </div>
                  </div>
              </div>
              <div className="mt-12 flex items-center gap-12">
                  <button onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex((prev) => (prev - 1 + filteredItems.length) % filteredItems.length); }} className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-[#00f3ff] hover:border-[#00f3ff] rounded-full transition-all hover:scale-110"><ChevronLeft size={32} /></button>
                  <button onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex((prev) => (prev + 1) % filteredItems.length); }} className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-[#00f3ff] hover:border-[#00f3ff] rounded-full transition-all hover:scale-110"><ChevronRight size={32} /></button>
              </div>
              <style>{`.perspective-1000 { perspective: 1000px; } .backface-hidden { backface-visibility: hidden; } .rotate-y-180 { transform: rotateY(180deg); } .transform-style-3d { transform-style: preserve-3d; }`}</style>
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left" style={fontStyle}>
       {/* Enhanced Controller Toolbar */}
       <div className="mb-6 bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shrink-0 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md z-40 relative">
           {/* Branding (Left) */}
           <div className="flex items-center gap-3 border-r border-zinc-800 pr-6">
               <NotebookIcon size={20} className="text-[#00f3ff]" />
               <span className="text-sm font-tech font-bold text-white tracking-[0.2em] uppercase">Flash_Notes</span>
           </div>

           {/* Controls (Right) */}
           <div className="flex items-center gap-3 flex-1 justify-end">
               {/* Combined Dropdown Filter */}
               <div className="relative">
                    <button 
                        onClick={() => setIsFilterOpen(!isFilterOpen)}
                        className="flex items-center gap-3 px-4 py-2 bg-black border border-zinc-800 rounded-sm text-[10px] font-bold font-mono uppercase text-[#00f3ff] hover:border-[#00f3ff]/50 transition-all min-w-[140px] justify-between group shadow-inner"
                    >
                        <span className="flex items-center gap-2">
                           <Settings2 size={14} />
                           {activeFilter}S
                        </span>
                        <ChevronDown size={14} className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`} />
                    </button>

                    {isFilterOpen && (
                        <div className="absolute top-full left-0 mt-1 w-full bg-[#0a0a0c] border border-zinc-800 shadow-2xl rounded-sm overflow-hidden z-[60] animate-fade-in">
                            {(['word', 'phrase', 'sentence'] as const).map(f => (
                                <button 
                                    key={f}
                                    onClick={() => { setActiveFilter(f); setSelectedIds(new Set()); setIsSelectionMode(false); setIsFilterOpen(false); }}
                                    className={`w-full text-left px-4 py-3 text-[10px] font-bold font-mono uppercase transition-colors hover:bg-[#00f3ff]/10 ${activeFilter === f ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}
                                >
                                    {f}S
                                </button>
                            ))}
                        </div>
                    )}
               </div>

               {/* Batch Ops Button */}
               <button 
                onClick={() => { setIsSelectionMode(!isSelectionMode); setSelectedIds(new Set()); }}
                className={`flex items-center gap-2 px-4 py-2 rounded-sm text-[10px] font-bold font-mono uppercase border transition-all ${isSelectionMode ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'}`}
               >
                   {isSelectionMode ? <XIcon size={14} /> : <ListChecks size={14} />}
                   {isSelectionMode ? "EXIT_BATCH" : "BATCH_OPS"}
               </button>

               {/* Initiate Button */}
               <button 
                 onClick={startFlashcards}
                 disabled={filteredItems.length === 0}
                 className="flex items-center gap-2 px-8 py-2 bg-[#00f3ff] text-black hover:bg-[#00c2cc] rounded-sm text-[11px] font-black font-mono uppercase transition-all shadow-[0_0_15px_rgba(0,243,255,0.4)] disabled:opacity-30 disabled:cursor-not-allowed transform active:scale-95 ml-2"
               >
                   <Play size={14} fill="currentColor" />
                   INITIATE
               </button>
           </div>
       </div>

       {/* Batch Operation Toolbar Area */}
       {isSelectionMode && (
         <div className="mb-4 bg-[#ff003c]/5 border border-[#ff003c]/20 p-2 rounded flex items-center justify-between animate-fade-in shrink-0">
             <div className="flex items-center gap-4">
                 <button onClick={selectAll} className="flex items-center gap-2 text-xs font-mono font-bold text-zinc-400 hover:text-white px-2 py-1 rounded hover:bg-zinc-800 transition-colors">
                     {selectedIds.size === filteredItems.length && filteredItems.length > 0 ? <CheckSquare size={14} className="text-[#ff003c]" /> : <Square size={14} />}
                     SELECT_ALL
                 </button>
                 <span className="text-[10px] font-mono text-[#ff003c] bg-[#ff003c]/10 px-2 py-0.5 rounded uppercase">{selectedIds.size} SNIPPETS_TARGETED</span>
             </div>
             <button onClick={executeBulkDelete} disabled={selectedIds.size === 0} className="flex items-center gap-2 px-3 py-1.5 bg-[#ff003c] text-white hover:bg-rose-600 rounded-sm text-xs font-mono font-bold uppercase disabled:opacity-30 disabled:cursor-not-allowed transition-all shadow-[0_0_15px_rgba(255,0,60,0.3)]">
                 <Trash2 size={12} /> PURGE_SELECTED
             </button>
         </div>
       )}

       {items.length === 0 ? (
           <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in">
               <Book size={48} className="opacity-20" />
               <p className="text-sm">NO_DATA_LOGGED</p>
               <p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p>
           </div>
       ) : filteredItems.length === 0 ? (
           <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in">
               <p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter.toUpperCase()}S</p>
           </div>
       ) : (
           <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
               {filteredItems.map((item, idx) => {
                   const isSelected = selectedIds.has(item.id);
                   const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                   return (
                   <div key={item.id} className={`bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 ${isSelected ? 'border-[#ff003c] shadow-[0_0_15px_rgba(255,0,60,0.1)]' : 'border-zinc-800 hover:border-zinc-700'}`} style={{ animationDelay: `${idx * 0.05}s` }}>
                       {isSelectionMode && (
                           <div onClick={() => toggleSelection(item.id)} className="absolute inset-y-0 left-0 w-12 flex items-center justify-center z-30 cursor-pointer bg-gradient-to-r from-black/80 to-transparent">
                               {isSelected ? <CheckSquare size={20} className="text-[#ff003c]" /> : <Square size={20} className="text-zinc-600 hover:text-zinc-400" />}
                           </div>
                       )}
                       <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                           <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                           <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                           <button onClick={() => onDelete(item.id)} disabled={isSelectionMode} className={`p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all ${isSelectionMode ? 'opacity-20 cursor-not-allowed' : ''}`} title="Purge Entry"><Trash2 size={14} /></button>
                       </div>
                       <div className={`flex items-start gap-4 ${isSelectionMode ? 'pl-8 transition-all' : ''}`}>
                           <div className="mt-1 shrink-0">
                               {item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}
                           </div>
                           <div className="flex-1 min-w-0 space-y-3">
                               <div>
                                   <p className={`text-white text-base font-medium leading-relaxed font-serif break-words ${isSelected ? 'text-[#ff003c]' : ''}`}>"{item.text}"</p>
                                   <div className="flex items-center gap-3 mt-2 flex-wrap">
                                       <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                       {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                       {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                       <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                   </div>
                               </div>
                               {item.definition && (
                                   <div className="bg-black/50 p-3 rounded border border-zinc-900">
                                       <p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p>
                                   </div>
                               )}
                               <div className="mt-2">
                                   <textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" />
                               </div>
                           </div>
                       </div>
                   </div>
                   );
               })}
           </div>
       )}
    </div>
  );
};

import React, { useState } from 'react';
import { NotebookItem, AppSettings } from '../types';
// Added 'Type' to the lucide-react imports to fix the "Cannot find name 'Type'" error on line 349
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, CheckSquare, Square, ListChecks, X as XIcon, Play, RefreshCw, Zap, ChevronLeft, ChevronRight, RotateCcw, Notebook as NotebookIcon, ChevronDown, Settings2, Type } from 'lucide-react';
import { generateSpeech } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  settings: AppSettings;
}

type FilterType = 'word' | 'phrase' | 'sentence';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('word');
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  // Selection State
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Flashcard State
  const [isFlashcardMode, setIsFlashcardMode] = useState(false);
  const [currentFlashcardIndex, setCurrentFlashcardIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const filteredItems = items.filter(item => item.type === activeFilter);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const selectAll = () => {
    if (selectedIds.size === filteredItems.length) setSelectedIds(new Set());
    else setSelectedIds(new Set(filteredItems.map(i => i.id)));
  };

  const executeBulkDelete = () => {
      onBulkDelete(Array.from(selectedIds));
      setSelectedIds(new Set());
      setIsSelectionMode(false);
  };

  const startFlashcards = () => {
      if (filteredItems.length === 0) return;
      setCurrentFlashcardIndex(0);
      setIsFlipped(false);
      setIsFlashcardMode(true);
  };

  if (isFlashcardMode && filteredItems.length > 0) {
      const item = filteredItems[currentFlashcardIndex];
      return (
          <div className="fixed inset-0 z-[200] bg-black/95 flex flex-col items-center justify-center p-6 animate-fade-in font-sans text-left">
              <div className="absolute top-8 right-8">
                  <button onClick={() => setIsFlashcardMode(false)} className="p-3 bg-zinc-900 text-zinc-400 hover:text-white rounded-full transition-all border border-zinc-800">
                      <XIcon size={24} />
                  </button>
              </div>
              <div className="text-center mb-8">
                  <h2 className="text-[#00f3ff] font-tech text-xs uppercase tracking-[0.4em] mb-2 animate-pulse">Neural_Study_Session</h2>
                  <p className="text-zinc-600 font-mono text-[10px]">LOG_INDEX: {currentFlashcardIndex + 1} / {filteredItems.length}</p>
              </div>
              <div onClick={() => setIsFlipped(!isFlipped)} className="relative w-full max-w-2xl aspect-[4/3] perspective-1000 cursor-pointer group">
                  <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                      <div className="absolute inset-0 backface-hidden bg-[#0a0a0c] border-2 border-[#00f3ff]/30 rounded-2xl flex flex-col items-center justify-center p-12 text-center shadow-[0_0_50px_rgba(0,243,255,0.1)]">
                          <div className="absolute top-6 left-6 text-[#00f3ff] opacity-20"><Zap size={48} /></div>
                          <p className="text-3xl md:text-4xl font-black text-white leading-tight font-serif italic">"{item.text}"</p>
                          <p className="absolute bottom-10 text-zinc-700 font-mono text-[10px] uppercase tracking-widest animate-bounce">Click to Decode Definition</p>
                      </div>
                      <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#050505] border-2 border-[#ff003c]/30 rounded-2xl flex flex-col items-center justify-center p-12 text-center shadow-[0_0_50px_rgba(255,0,60,0.1)]">
                          <div className="absolute top-6 right-6 text-[#ff003c] opacity-20"><RotateCcw size={48} /></div>
                          <div className="space-y-6 max-w-md">
                              <div>
                                  <h4 className="text-[#ff003c] font-mono text-xs uppercase tracking-widest mb-2 font-bold">Definition:</h4>
                                  <p className="text-xl text-zinc-300 font-mono leading-relaxed">{item.definition || "NO_DATA_LOGGED"}</p>
                              </div>
                              {item.comment && (
                                  <div className="pt-6 border-t border-zinc-800">
                                      <h4 className="text-amber-500 font-mono text-xs uppercase tracking-widest mb-2 font-bold">User_Annotation:</h4>
                                      <p className="text-base text-zinc-500 font-mono italic">"{item.comment}"</p>
                                  </div>
                              )}
                          </div>
                          <p className="absolute bottom-10 text-zinc-700 font-mono text-[10px] uppercase tracking-widest">Click to Review Snippet</p>
                      </div>
                  </div>
              </div>
              <div className="mt-12 flex items-center gap-12">
                  <button onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex((prev) => (prev - 1 + filteredItems.length) % filteredItems.length); }} className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-[#00f3ff] hover:border-[#00f3ff] rounded-full transition-all hover:scale-110"><ChevronLeft size={32} /></button>
                  <button onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex((prev) => (prev + 1) % filteredItems.length); }} className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-[#00f3ff] hover:border-[#00f3ff] rounded-full transition-all hover:scale-110"><ChevronRight size={32} /></button>
              </div>
              <style>{`.perspective-1000 { perspective: 1000px; } .backface-hidden { backface-visibility: hidden; } .rotate-y-180 { transform: rotateY(180deg); } .transform-style-3d { transform-style: preserve-3d; }`}</style>
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left" style={fontStyle}>
       {/* Enhanced Controller Toolbar */}
       <div className="mb-6 bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shrink-0 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md z-40 relative">
           {/* Branding (Left) */}
           <div className="flex items-center gap-3 border-r border-zinc-800 pr-6">
               <NotebookIcon size={20} className="text-[#00f3ff]" />
               <span className="text-sm font-tech font-bold text-white tracking-[0.2em] uppercase">Flash_Notes</span>
           </div>

           {/* Controls (Right) */}
           <div className="flex items-center gap-3 flex-1 justify-end">
               {/* Combined Dropdown Filter */}
               <div className="relative">
                    <button 
                        onClick={() => setIsFilterOpen(!isFilterOpen)}
                        className="flex items-center gap-3 px-4 py-2 bg-black border border-zinc-800 rounded-sm text-[10px] font-bold font-mono uppercase text-[#00f3ff] hover:border-[#00f3ff]/50 transition-all min-w-[140px] justify-between group shadow-inner"
                    >
                        <span className="flex items-center gap-2">
                           <Settings2 size={14} />
                           {activeFilter}S
                        </span>
                        <ChevronDown size={14} className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`} />
                    </button>

                    {isFilterOpen && (
                        <div className="absolute top-full left-0 mt-1 w-full bg-[#0a0a0c] border border-zinc-800 shadow-2xl rounded-sm overflow-hidden z-[60] animate-fade-in">
                            {(['word', 'phrase', 'sentence'] as const).map(f => (
                                <button 
                                    key={f}
                                    onClick={() => { setActiveFilter(f); setSelectedIds(new Set()); setIsSelectionMode(false); setIsFilterOpen(false); }}
                                    className={`w-full text-left px-4 py-3 text-[10px] font-bold font-mono uppercase transition-colors hover:bg-[#00f3ff]/10 ${activeFilter === f ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}
                                >
                                    {f}S
                                </button>
                            ))}
                        </div>
                    )}
               </div>

               {/* Batch Ops Button */}
               <button 
                onClick={() => { setIsSelectionMode(!isSelectionMode); setSelectedIds(new Set()); }}
                className={`flex items-center gap-2 px-4 py-2 rounded-sm text-[10px] font-bold font-mono uppercase border transition-all ${isSelectionMode ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'}`}
               >
                   {isSelectionMode ? <XIcon size={14} /> : <ListChecks size={14} />}
                   {isSelectionMode ? "EXIT_BATCH" : "BATCH_OPS"}
               </button>

               {/* Initiate Button */}
               <button 
                 onClick={startFlashcards}
                 disabled={filteredItems.length === 0}
                 className="flex items-center gap-2 px-8 py-2 bg-[#00f3ff] text-black hover:bg-[#00c2cc] rounded-sm text-[11px] font-black font-mono uppercase transition-all shadow-[0_0_15px_rgba(0,243,255,0.4)] disabled:opacity-30 disabled:cursor-not-allowed transform active:scale-95 ml-2"
               >
                   <Play size={14} fill="currentColor" />
                   INITIATE
               </button>
