export const generateSpeech = async (text: string, voiceName: string = 'Kore'): Promise<string> => {
  if (!text || text.trim().length === 0) {
      console.warn("generateSpeech called with empty text");
      return "";
  }

  return withRetry(async () => {
    const ai = getAi();
    // Truncate text for single speech generation to avoid model timeouts or 500s
    const safeText = text.length > 3000 ? text.substring(0, 3000) : text;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: safeText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) {
        console.error("Gemini TTS response missing audio data. Candidate count:", response.candidates?.length);
        throw new Error("Failed to generate audio: Empty response data");
    }
    return base64Audio;
  });
};

