export const generateSpeech = async (text: string, voiceName: string = 'Kore'): Promise<string> => {
  if (!text || text.trim().length === 0) {
      console.warn("generateSpeech called with empty text");
      return "";
  }

  return withRetry(async () => {
    const ai = getAi();
    const safeText = text.length > 3000 ? text.substring(0, 3000) : text;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: safeText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) {
        throw new Error("Failed to generate audio: Empty response data");
    }
    return base64Audio;
  });
};

export const translateText = async (text: string, targetLanguage: string): Promise<string> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [{ text: `Translate the following to ${targetLanguage}. Return ONLY translation.\n\n${text}` }]
      }
    });
    return response.text || "";
  });
};

export const getQuickDefinition = async (text: string, language: string): Promise<string> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [{ text: `Explain this term in ${language}: "${text}".` }]
      }
    });
    return response.text || "";
  });
};

export const batchGetDefinitions = async (items: { id: string, text: string }[], language: string): Promise<Record<string, string>> => {
  if (items.length === 0) return {};
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [{ text: `Provide concise one-sentence definitions in ${language} for the following items. Return as a JSON object where the keys are the original IDs provided.\n\nItems: ${JSON.stringify(items)}` }]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          description: "Definitions mapped by item ID"
        }
      }
    });
    return JSON.parse(response.text || "{}");
  });
};

