export const batchGetDefinitions = async (items: { id: string, text: string }[], language: string): Promise<Record<string, string>> => {
  if (items.length === 0) return {};
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ 
          role: 'user', 
          parts: [{ text: `Provide concise one-sentence definitions in ${language} for the following items. Return a JSON array of objects, each containing an "id" field (the original ID) and a "definition" field. \n\nItems: ${JSON.stringify(items)}` }] 
      }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              definition: { type: Type.STRING }
            },
            required: ["id", "definition"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return {};
    const rawResults = JSON.parse(text) as { id: string, definition: string }[];
    const mapping: Record<string, string> = {};
    rawResults.forEach(r => { mapping[r.id] = r.definition; });
    return mapping;
  });
};

