                                      </div>
                                  )}
                              </div>
                              <p className="absolute bottom-10 text-zinc-700 font-mono text-[8px] uppercase tracking-widest">Return to Snippet_View</p>
                          </div>
                      </div>
                  </div>

                  {/* Navigation Controls */}
