                      <button onClick={(e) => { e.stopPropagation(); setIsFlipped(false); setCurrentFlashcardIndex((prev) => (prev - 1 + filteredItems.length) % filteredItems.length); }} className="group flex flex-col items-center gap-2">
                         <div className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-500 group-hover:text-[#00f3ff] group-hover:border-[#00f3ff] rounded-full transition-all group-hover:scale-110 shadow-lg">
                            <ChevronLeft size={28} />
                         </div>
                         <span className="text-[8px] font-mono text-zinc-700 group-hover:text-zinc-500 uppercase tracking-widest">Previous</span>
                      </button>
                      <button onClick={(e) => { e.stopPropagation(); setIsFlipped(false); setCurrentFlashcardIndex((prev) => (prev + 1) % filteredItems.length); }} className="group flex flex-col items-center gap-2">
                         <div className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-500 group-hover:text-[#00f3ff] group-hover:border-[#00f3ff] rounded-full transition-all group-hover:scale-110 shadow-lg">
                            <ChevronRight size={28} />
                         </div>
                         <span className="text-[8px] font-mono text-zinc-700 group-hover:text-zinc-500 uppercase tracking-widest">Next</span>
                      </button>
                  </div>
              </div>
              <style>{`.perspective-1000 { perspective: 1000px; } .backface-hidden { backface-visibility: hidden; } .rotate-y-180 { transform: rotateY(180deg); } .transform-style-3d { transform-style: preserve-3d; }`}</style>
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       {/* Enhanced Controller Toolbar */}
       <div className="mb-6 bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shrink-0 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md z-40 relative">
           <div className="flex items-center gap-3 border-r border-zinc-800 pr-6">
               <NotebookIcon size={20} className="text-[#00f3ff]" />
               <span className="text-sm font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>

           <div className="flex items-center gap-3 flex-1 justify-end">
               <div className="relative">
                    <button 
                        onClick={() => setIsFilterOpen(!isFilterOpen)}
                        className="flex items-center gap-3 px-4 py-2 bg-black border border-zinc-800 rounded-sm text-[10px] font-bold font-mono uppercase text-[#00f3ff] hover:border-[#00f3ff]/50 transition-all min-w-[140px] justify-between group shadow-inner"
                    >
                        <span className="flex items-center gap-2">
                           <Settings2 size={14} />
                           {activeFilter}S
                        </span>
                        <ChevronDown size={14} className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`} />
                    </button>

                    {isFilterOpen && (
                        <div className="absolute top-full left-0 mt-1 w-full bg-[#0a0a0c] border border-zinc-800 shadow-2xl rounded-sm overflow-hidden z-[60] animate-fade-in">
                            {(['word', 'phrase', 'sentence'] as const).map(f => (
                                <button 
                                    key={f}
                                    onClick={() => { setActiveFilter(f); setSelectedIds(new Set()); setIsSelectionMode(false); setIsFilterOpen(false); }}
                                    className={`w-full text-left px-4 py-3 text-[10px] font-bold font-mono uppercase transition-colors hover:bg-[#00f3ff]/10 ${activeFilter === f ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}
                                >
                                    {f}S
                                </button>
                            ))}
                        </div>
                    )}
               </div>

               <button 
                onClick={() => { setIsSelectionMode(!isSelectionMode); setSelectedIds(new Set()); }}
                className={`flex items-center gap-2 px-4 py-2 rounded-sm text-[10px] font-bold font-mono uppercase border transition-all ${isSelectionMode ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'}`}
               >
                   {isSelectionMode ? <XIcon size={14} /> : <ListChecks size={14} />}
                   {isSelectionMode ? "EXIT_BATCH" : "BATCH_OPS"}
               </button>

               <button 
                 onClick={startFlashcards}
                 disabled={filteredItems.length === 0 || isPreparingCards}
                 className="flex items-center gap-2 px-8 py-2 bg-[#00f3ff] text-black hover:bg-[#00c2cc] rounded-sm text-[11px] font-black font-mono uppercase transition-all shadow-[0_0_15px_rgba(0,243,255,0.4)] disabled:opacity-30 disabled:cursor-not-allowed transform active:scale-95 ml-2"
               >
                   {isPreparingCards ? <Loader2 size={14} className="animate-spin" /> : <Play size={14} fill="currentColor" />}
                   {isPreparingCards ? "SYNCING..." : "INITIATE"}
               </button>
           </div>
       </div>

       {isSelectionMode && (
         <div className="mb-4 bg-[#ff003c]/5 border border-[#ff003c]/20 p-2 rounded flex items-center justify-between animate-fade-in shrink-0">
             <div className="flex items-center gap-4">
                 <button onClick={selectAll} className="flex items-center gap-2 text-xs font-mono font-bold text-zinc-400 hover:text-white px-2 py-1 rounded hover:bg-zinc-800 transition-colors">
                     {selectedIds.size === filteredItems.length && filteredItems.length > 0 ? <CheckSquare size={14} className="text-[#ff003c]" /> : <Square size={14} />}
                     SELECT_ALL
                 </button>
                 <span className="text-[10px] font-mono text-[#ff003c] bg-[#ff003c]/10 px-2 py-0.5 rounded uppercase">{selectedIds.size} SNIPPETS_TARGETED</span>
             </div>
             <button onClick={executeBulkDelete} disabled={selectedIds.size === 0} className="flex items-center gap-2 px-3 py-1.5 bg-[#ff003c] text-white hover:bg-rose-600 rounded-sm text-xs font-mono font-bold uppercase disabled:opacity-30 disabled:cursor-not-allowed transition-all shadow-[0_0_15px_rgba(255,0,60,0.3)]">
                 <Trash2 size={12} /> PURGE_SELECTED
             </button>
         </div>
       )}

       {items.length === 0 ? (
           <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in">
               <Book size={48} className="opacity-20" />
               <p className="text-sm">NO_DATA_LOGGED</p>
               <p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p>
           </div>
       ) : filteredItems.length === 0 ? (
           <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in">
               <p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter.toUpperCase()}S</p>
           </div>
       ) : (
           <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
               {filteredItems.map((item, idx) => {
                   const isSelected = selectedIds.has(item.id);
                   const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                   return (
                   <div key={item.id} className={`bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 ${isSelected ? 'border-[#ff003c] shadow-[0_0_15px_rgba(255,0,60,0.1)]' : 'border-zinc-800 hover:border-zinc-700'}`} style={{ animationDelay: `${idx * 0.05}s` }}>
                       {isSelectionMode && (
                           <div onClick={() => toggleSelection(item.id)} className="absolute inset-y-0 left-0 w-12 flex items-center justify-center z-30 cursor-pointer bg-gradient-to-r from-black/80 to-transparent">
                               {isSelected ? <CheckSquare size={20} className="text-[#ff003c]" /> : <Square size={20} className="text-zinc-600 hover:text-zinc-400" />}
                           </div>
                       )}
                       <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                           <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                           <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                           <button onClick={() => onDelete(item.id)} disabled={isSelectionMode} className={`p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all ${isSelectionMode ? 'opacity-20 cursor-not-allowed' : ''}`} title="Purge Entry"><Trash2 size={14} /></button>
                       </div>
                       <div className={`flex items-start gap-4 ${isSelectionMode ? 'pl-8 transition-all' : ''}`}>
                           <div className="mt-1 shrink-0">
                               {item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}
                           </div>
                           <div className="flex-1 min-w-0 space-y-3">
                               <div>
                                   <p className={`text-white text-base font-medium leading-relaxed font-serif break-words ${isSelected ? 'text-[#ff003c]' : ''}`}>"{item.text}"</p>
                                   <div className="flex items-center gap-3 mt-2 flex-wrap">
                                       <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                       {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                       {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                       <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                   </div>
                               </div>
                               {item.definition && (
                                   <div className="bg-black/50 p-3 rounded border border-zinc-900">
                                       <p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p>
                                   </div>
                               )}
                               <div className="mt-2">
                                   <textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" />
                               </div>
                           </div>
                       </div>
                   </div>
                   );
               })}
           </div>
       )}
    </div>
  );
};

import React, { useState } from 'react';
import { Upload, BookOpen, Headphones, Image as ImageIcon, BookA, Film, Menu, X, ChevronRight, FileText, Mic2, Settings as SettingsIcon, Library as LibraryIcon, Tag, Bookmark, Cpu, Notebook as NotebookIcon, Terminal, Activity, Database, Shield } from 'lucide-react';
import JSZip from 'jszip';
import { BookStructure, Chapter, AppView, Tab, FileContext, AppSettings, LibraryItem, NotebookItem } from './types';
import { analyzeBookStructure } from './services/gemini';
import { PodcastPlayer } from './components/PodcastPlayer';
import { Visualizer } from './components/Visualizer';
import { VideoSummary } from './components/VideoSummary';
import { AudioBook } from './components/AudioBook';
import { Notebook } from './components/Notebook';
import { SettingsModal } from './components/SettingsModal';
import { GlobalContextLayer } from './components/GlobalContextLayer';
import { Loader } from './components/ui/Loader';
import { AIAssistant } from './components/AIAssistant';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.UPLOAD);

  const [library, setLibrary] = useState<LibraryItem[]>([]);
  const [activeBookId, setActiveBookId] = useState<string | null>(null);

  // Notebook State
  const [notebook, setNotebook] = useState<NotebookItem[]>([]);

  const activeBook = library.find(item => item.book.id === activeBookId)?.book || null;
  const activeFileContext = library.find(item => item.book.id === activeBookId)?.fileContext || null;

  const [activeChapterId, setActiveChapterId] = useState<number | null>(null);
  const activeChapter = activeBook?.chapters.find(c => c.id === activeChapterId) || null;

  const [activeTab, setActiveTab] = useState<Tab>(Tab.AUDIOBOOK);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showLibraryList, setShowLibraryList] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    targetLanguage: 'Spanish',
    highlightColor: 'indigo',
    textSize: 'base',
    lineHeight: 'normal',
    letterSpacing: 'normal',
    font: 'Inter'
  });

  const handleAddToNotebook = (item: Omit<NotebookItem, 'id' | 'timestamp'>) => {
      // Improved classification logic for Words vs Phrases vs Sentences
      let detectedType: 'word' | 'phrase' | 'sentence' = 'word';
      const text = item.text.trim();
      const wordCount = text.split(/\s+/).length;

      if (wordCount === 1 || text.length < 15) {
          detectedType = 'word';
      } else if (wordCount <= 6 && text.length < 50) {
          detectedType = 'phrase';
      } else {
          detectedType = 'sentence';
      }

      const newItem: NotebookItem = {
          ...item,
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          type: detectedType,
          sourceChapter: activeChapter?.title,
          bookTitle: activeBook?.title,
          bookAuthor: activeBook?.author
      };
      setNotebook(prev => [newItem, ...prev]);
  };

  const handleDeleteNotebookItem = (id: string) => {
      setNotebook(prev => prev.filter(i => i.id !== id));
  };

  const handleBulkDeleteNotebookItems = (ids: string[]) => {
      setNotebook(prev => prev.filter(i => !ids.includes(i.id)));
  };

  const handleUpdateNotebookComment = (id: string, comment: string) => {
      setNotebook(prev => prev.map(item => item.id === id ? { ...item, comment } : item));
  };

  const handleBatchUpdateDefinitions = (updates: Record<string, string>) => {
      setNotebook(prev => prev.map(item => {
          if (updates[item.id]) {
              return { ...item, definition: updates[item.id] };
          }
          return item;
      }));
  };

  const processEpub = async (file: File): Promise<string> => {
    try {
      const zip = await JSZip.loadAsync(file);
      let fullText = "";
      const contentFiles = Object.keys(zip.files).filter(filename => 
        filename.match(/\.(html|xhtml|htm)$/i) && !filename.includes('__MACOSX')
      );
      contentFiles.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
      const parser = new DOMParser();
      for (const filename of contentFiles) {
        const content = await zip.files[filename].async("string");
        const doc = parser.parseFromString(content, "text/html");
        fullText += (doc.body.textContent || "") + "\n\n";
      }
      if (!fullText) throw new Error("No readable text found in EPUB.");
      if (fullText.length > 80000) {
        return fullText.substring(0, 80000) + "... [Truncated for stability]";
      }
      return fullText;
    } catch (e) {
      console.error("EPUB processing error", e);
      throw new Error("Could not parse EPUB file.");
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.pdf', '.txt', '.md', '.html', '.xml', '.epub'];
    const hasAllowedExt = allowedExtensions.some(ext => file.name.toLowerCase().endsWith(ext));

    if (!hasAllowedExt) {
      setError("Supported formats: PDF, EPUB, TXT, MD, HTML.");
      return;
    }

    if (!file.type.startsWith('text/') && !file.name.toLowerCase().endsWith('.epub') && file.size > 8 * 1024 * 1024) {
       setError("PDF too large (>8MB). Please optimize or split the file.");
       return;
    }

    setIsProcessing(true);
    setError(null);

    const reader = new FileReader();
    const isEpub = file.name.toLowerCase().endsWith('.epub');
    const isTextBased = file.type.startsWith('text/') || 
                        ['.txt', '.md', '.html', '.xml'].some(ext => file.name.toLowerCase().endsWith(ext));

    const finalizeUpload = async (context: FileContext) => {
        try {
            const structure = await analyzeBookStructure(context);
            const newItem: LibraryItem = {
                book: structure,
                fileContext: context,
                uploadDate: Date.now()
            };
            setLibrary(prev => [newItem, ...prev]);
            setActiveBookId(structure.id);
            if (structure.chapters.length > 0) setActiveChapterId(structure.chapters[0].id);
            setView(AppView.DASHBOARD);
            setShowLibraryList(false);
        } catch (err: any) {
            setError("Decoding failed. The file might be too complex or large. " + (err.message || "Internal Error"));
        } finally {
            setIsProcessing(false);
        }
    };

    if (isEpub) {
       try {
         const textContent = await processEpub(file);
         await finalizeUpload({
            content: textContent,
            mimeType: 'text/plain',
            isText: true
         });
       } catch (err: any) {
         setError(err.message || "Failed to process EPUB.");
         setIsProcessing(false);
       }
       return;
    }

    reader.onload = async (e) => {
      let context: FileContext;
      if (isTextBased) {
          let content = e.target?.result as string;
          if (content.length > 80000) content = content.substring(0, 80000) + "... [Truncated]";
          context = { content, mimeType: 'text/plain', isText: true };
      } else {
          const base64 = (e.target?.result as string).split(',')[1];
          context = { content: base64, mimeType: 'application/pdf', isText: false };
      }
      await finalizeUpload(context);
    };

    if (isTextBased) reader.readAsText(file);
    else reader.readAsDataURL(file);
  };

  const toggleBookmark = (chapterId: number) => {
    if (!activeBookId) return;
    setLibrary(prev => prev.map(item => {
        if (item.book.id === activeBookId) {
            const bookmarks = item.book.bookmarks || [];
            const isBookmarked = bookmarks.includes(chapterId);
            const newBookmarks = isBookmarked 
                ? bookmarks.filter(id => id !== chapterId)
                : [...bookmarks, chapterId];
            return { ...item, book: { ...item.book, bookmarks: newBookmarks } };
        }
        return item;
    }));
  };

  const renderContent = () => {
    if (activeTab === Tab.NOTEBOOK) {
        return (
            <Notebook 
                items={notebook} 
                onDelete={handleDeleteNotebookItem} 
                onBulkDelete={handleBulkDeleteNotebookItems} 
                onUpdateComment={handleUpdateNotebookComment} 
                onBatchUpdateDefinitions={handleBatchUpdateDefinitions}
                settings={settings} 
            />
        );
    }

    if (!activeChapter || !activeFileContext) return null;

    let content;
    switch (activeTab) {
      case Tab.AUDIOBOOK:
        content = <AudioBook chapter={activeChapter} fileContext={activeFileContext} settings={settings} onSettingsUpdate={setSettings} />;
        break;
      case Tab.PODCAST:
        content = <PodcastPlayer chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.CONCEPTS:
        content = <Visualizer chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      case Tab.ANIMATION:
        content = <VideoSummary chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      default:
        content = null;
    }

    return (
      <div key={`${activeBookId}-${activeChapter.id}-${activeTab}`} className="h-full animate-fade-in">
        {content}
      </div>
    );
  };

  if (view === AppView.UPLOAD) {
    return (
      <div className="min-h-screen bg-[#020202] bg-grid flex flex-col items-center justify-center p-6 relative overflow-hidden font-tech text-left">
        <div className="absolute top-8 left-8 w-24 h-24 border-l border-t border-zinc-800 rounded-tl-lg pointer-events-none"></div>
        <div className="absolute bottom-8 right-8 w-24 h-24 border-r border-b border-zinc-800 rounded-br-lg pointer-events-none"></div>

        <div className="z-10 max-w-lg w-full text-center space-y-12">
          <div className="space-y-2 animate-fade-in-up text-center">
             <div className="flex items-center justify-center gap-2 mb-4">
                <Terminal size={32} className="text-[#00f3ff]" />
             </div>
            <h1 className="text-7xl font-bold tracking-tighter text-white drop-shadow-[0_0_25px_rgba(0,243,255,0.3)]">
              Decod<span className="text-[#00f3ff]">Ebook</span>
            </h1>
            <p className="text-zinc-500 tracking-[0.2em] text-xs uppercase">
              V.4.2 // Neural Text Decoding Interface
            </p>
          </div>

          <div className="relative group animate-fade-in-up hud-border bg-[#050505] p-10 transition-all duration-500 hover:shadow-[0_0_30px_rgba(0,243,255,0.1)]" style={{ animationDelay: '0.1s' }}>
              {isProcessing ? (
                <Loader text="DECODING_SOURCE..." />
              ) : (
                <div className="relative flex flex-col items-center justify-center space-y-8">
                  <div className="relative">
                    <div className="w-32 h-32 bg-[#0a0a0c] border border-zinc-800 rounded-full flex items-center justify-center group-hover:border-[#00f3ff] transition-all duration-500">
                        <Upload className="w-12 h-12 text-zinc-600 group-hover:text-[#00f3ff] transition-colors" />
                    </div>
                    <div className="absolute -inset-2 border border-dashed border-zinc-800 rounded-full animate-spin-slow pointer-events-none group-hover:border-[#00f3ff]/30"></div>
                  </div>
                  <div className="space-y-2 text-center">
                    <p className="text-[#00f3ff] font-bold uppercase tracking-widest text-sm animate-pulse">Initialize Upload</p>
                    <p className="text-[10px] text-zinc-600 font-mono">SUPPORTED PROTOCOLS: PDF / EPUB / TXT / MD</p>
                  </div>
                  <input 
                    type="file" 
                    accept=".pdf,.txt,.md,.html,.xml,.epub"
                    onChange={handleFileUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
              )}
          </div>

          {library.length > 0 && (
             <button 
                onClick={() => setView(AppView.DASHBOARD)}
                className="text-zinc-500 hover:text-[#00f3ff] text-xs font-mono uppercase tracking-widest transition-colors flex items-center gap-2 mx-auto border border-transparent hover:border-[#00f3ff]/30 px-4 py-2 rounded-sm"
             >
                <LibraryIcon size={14} />
                Access_Data_Bank [{library.length}]
             </button>
          )}
          {error && <p className="text-[#ff003c] text-xs font-mono border border-[#ff003c]/30 p-2 bg-[#ff003c]/5">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020202] bg-grid text-zinc-300 overflow-hidden font-sans relative text-left">
      <GlobalContextLayer onAddToNotebook={handleAddToNotebook} activeLanguage={settings.targetLanguage} />
      <AIAssistant 
        fileContext={activeFileContext} 
        bookTitle={activeBook?.title} 
        bookId={activeBook?.id} 
      />
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        settings={settings}
        onUpdate={setSettings}
      />

      <aside 
        className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-[#050505] flex flex-col overflow-hidden relative z-20 transition-all duration-300 border-r border-zinc-900`}
      >
        <div className="p-4 border-b border-zinc-900 shrink-0 bg-black/80 backdrop-blur-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-[1px] bg-[#00f3ff] opacity-20"></div>
            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2">
                    <Cpu size={16} className="text-[#00f3ff]" />
                    <span className="text-xs font-tech font-bold text-white tracking-[0.2em]">DECOD.EBOOK</span>
                </div>
                <button 
