const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  let cleaned = text.replace(/^(Below|Here|Following|This) is the (translation|text).*?:/gi, '');
  cleaned = cleaned.replace(/^(以下是|这是).*(翻译|内容).*?：/gi, '');
  return cleaned
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') 
    .trim();
};

const withRetry = async <T>(fn: () => Promise<T>, retries = 3, delay = 3000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    console.error("Gemini API Error details:", error);

    const getErrorDetails = (e: any) => {
        if (e.error && typeof e.error === 'object') return e.error;
        if (e.response?.data?.error) return e.response.data.error;
        return e;
    };

    const details = getErrorDetails(error);
    const code = details.code || details.status || error.status || error.code;
    const message = String(details.message || error.message || JSON.stringify(error)).toLowerCase();

    let extractedDelay = 0;
    if (details.details) {
        const retryInfo = details.details.find((d: any) => d['@type']?.includes('RetryInfo'));
        if (retryInfo && retryInfo.retryDelay) {
            extractedDelay = parseInt(retryInfo.retryDelay) * 1000;
        }
    }

    const isRateLimit = Number(code) === 429 || message.includes('429') || message.includes('quota');
    const isServerError = (Number(code) >= 500 && Number(code) < 600) || message.includes('internal error') || message.includes('500');

    if (retries > 0 && (isRateLimit || isServerError)) {
      const nextDelay = extractedDelay || (isRateLimit ? delay * 5 : delay * 2);
      console.warn(`Gemini API error (${code}). Retrying in ${nextDelay}ms... (Retries left: ${retries})`);
      await new Promise(resolve => setTimeout(resolve, nextDelay));
      return withRetry(fn, retries - 1, nextDelay);
    }
    throw error;
  }
};

const getFilePart = (file: FileContext): Part => {
  if (file.isText) {
    const content = file.content.length > 60000 ? file.content.substring(0, 60000) : file.content;
    return { text: content };
  }
  return { inlineData: { mimeType: file.mimeType, data: file.content } };
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: "Analyze the provided book. Extract the title, author, and a list of major chapters (max 20). For each chapter, provide a brief title and a concise one-sentence description. Output strictly in JSON format. Do not include markdown code blocks." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["id", "title"]
              }
            }
          },
          required: ["title", "author", "chapters"]
        }
      }
    });

    if (!response.text) throw new Error("Empty response from model");
    const data = JSON.parse(response.text.trim());
    return { ...data, id: crypto.randomUUID(), bookmarks: [] } as BookStructure;
  });
};

export const translateSentences = async (sentences: string[], targetLanguage: string): Promise<string[]> => {
  if (sentences.length === 0) return [];
  const batchSize = 10;
  const results: string[] = [];

  for (let i = 0; i < sentences.length; i += batchSize) {
    const batch = sentences.slice(i, i + batchSize);
    const batchResult = await withRetry(async () => {
      const ai = getAi();
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: {
          parts: [{ text: `Translate the following sentences to ${targetLanguage}. Return a JSON array of strings. Maintain 1:1 mapping.\n\nSentences: ${JSON.stringify(batch)}` }]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return JSON.parse(response.text || "[]") as string[];
    });
    results.push(...batchResult);
    if (i + batchSize < sentences.length) {
        await new Promise(r => setTimeout(r, 1000));
    }
  }
  return results;
};

