export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          ctx.clearRect(0, 0, canvas.width, canvas.height);

          const centerY = canvas.height / 2;
          const bars = bufferLength / 1.5;
          const points: { x: number, y1: number, y2: number, val: number }[] = [];

          ctx.shadowBlur = 10;
          ctx.shadowColor = 'rgba(0, 243, 255, 0.6)';

          // Step 1: Extract and draw the primary filaments
          for (let i = 0; i < bars; i++) {
            const value = dataArray[i];
            const h = (value / 255) * canvas.height * 0.75;
            const x = i * (canvas.width / bars);
            const yOffset = Math.sin(Date.now() * 0.005 + i * 0.1) * 3;

            const topY = centerY - h/2 + yOffset;
            const bottomY = centerY + h/2 + yOffset;

            points.push({ x, y1: topY, y2: bottomY, val: value });

            // Drawing the filament
            ctx.strokeStyle = `rgba(0, 243, 255, ${0.05 + (value / 255) * 0.8})`;
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(x, topY);
            ctx.lineTo(x, bottomY);
            ctx.stroke();

            // Terminal points
            ctx.fillStyle = `rgb(0, 243, 255)`;
            const dotSize = 1.5 + (value / 255) * 2.5;
            ctx.beginPath();
            ctx.arc(x, topY, dotSize/2, 0, Math.PI * 2);
            ctx.arc(x, bottomY, dotSize/2, 0, Math.PI * 2);
            ctx.fill();
          }

          // Step 2: Draw Quantum Entanglement connections
          // We connect high intensity peaks with "neural threads"
          ctx.lineWidth = 0.5;
          ctx.shadowBlur = 5;

          const highActivityPoints = points.filter(p => p.val > 140).slice(0, 15);

          for (let i = 0; i < highActivityPoints.length; i++) {
              for (let j = i + 1; j < highActivityPoints.length; j++) {
                  const p1 = highActivityPoints[i];
                  const p2 = highActivityPoints[j];
                  const dist = Math.abs(p1.x - p2.x);

                  // Only connect if within a reasonable neural distance to keep it look "entangled" but clean
                  if (dist < canvas.width * 0.3) {
                      const opacity = (p1.val + p2.val) / 510 * 0.3;
                      const gradient = ctx.createLinearGradient(p1.x, p1.y1, p2.x, p2.y1);
                      gradient.addColorStop(0, `rgba(0, 243, 255, ${opacity})`);
                      gradient.addColorStop(0.5, `rgba(255, 0, 60, ${opacity * 1.5})`);
                      gradient.addColorStop(1, `rgba(0, 243, 255, ${opacity})`);

                      ctx.strokeStyle = gradient;
                      ctx.beginPath();
                      ctx.moveTo(p1.x, p1.y1);
                      // Quadratic curve for "entanglement path"
                      ctx.quadraticCurveTo(
                          (p1.x + p2.x) / 2, 
                          centerY - (dist * 0.2) - (p1.val / 5), 
                          p2.x, 
                          p2.y1
                      );
                      ctx.stroke();

                      // Bottom arcs
                      ctx.beginPath();
                      ctx.moveTo(p1.x, p1.y2);
                      ctx.quadraticCurveTo(
                          (p1.x + p2.x) / 2, 
                          centerY + (dist * 0.2) + (p1.val / 5), 
                          p2.x, 
                          p2.y2
                      );
                      ctx.stroke();
                  }
              }
          }
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

