const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  let cleaned = text.replace(/^(Below|Here|Following|This) is the (translation|text).*?:/gi, '');
  cleaned = cleaned.replace(/^(以下是|这是).*(翻译|内容).*?：/gi, '');
  return cleaned
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') 
    .trim();
};

/**
 * Enhanced retry wrapper with exponential backoff and jitter.
 * Designed to handle transient 500 Internal Server Errors and Rate Limits.
 */
const withRetry = async <T>(fn: () => Promise<T>, retries = 10, delay = 2000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const code = error.status || error.code || 500;
    const message = error.message?.toLowerCase() || "";

    // Log for debugging
    console.error(`Gemini API Error [${code}]:`, error);

    const isRetryable = 
      code === 429 || 
      code === 500 || 
      code === 502 ||
      code === 503 || 
      code === 504 ||
      message.includes('quota') || 
      message.includes('internal error') ||
      message.includes('server error') ||
      message.includes('internal server error') ||
      message.includes('deadline exceeded') ||
      message.includes('overloaded') ||
      message.includes('temporary') ||
      // Catch specific app-level errors that should trigger a retry
      message.includes('script generation failed') ||
      message.includes('malformed json');

    if (retries > 0 && isRetryable) {
      // Exponential backoff with jitter (max delay ~30s)
      const nextDelay = Math.min(
        (code === 429 ? delay * 4 : delay * 2) * (11 - retries) + (Math.random() * 1500),
        30000
      );
      console.warn(`Transient error detected. Retrying in ${Math.round(nextDelay)}ms... (${retries} attempts left)`);
      await new Promise(resolve => setTimeout(resolve, nextDelay));
      return withRetry(fn, retries - 1, delay);
    }
    throw error;
  }
};

const getFilePart = (file: FileContext): Part => {
  if (file.isText) {
    // Ensuring we don't exceed model context limits for single parts
    const content = file.content.length > 100000 ? file.content.substring(0, 100000) : file.content;
    return { text: content };
  }
  return { inlineData: { mimeType: file.mimeType, data: file.content } };
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: "Analyze the provided book. Extract the title, author, and a list of major chapters (max 20). For each chapter, provide a brief title and a concise one-sentence description. Output strictly in JSON format. Do not include markdown code blocks." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["id", "title"]
              }
            }
          },
          required: ["title", "author", "chapters"]
        }
      }
    });

    const text = response.text?.trim();
    if (!text) throw new Error("Internal Error: Empty response from model");
    try {
        const data = JSON.parse(text);
        return { ...data, id: crypto.randomUUID(), bookmarks: [] } as BookStructure;
    } catch (e) {
        throw new Error("Internal Error: Malformed JSON in book structure");
    }
  });
};

export const translateSentences = async (sentences: string[], targetLanguage: string): Promise<string[]> => {
  if (sentences.length === 0) return [];
  const batchSize = 10;
  const results: string[] = [];

  for (let i = 0; i < sentences.length; i += batchSize) {
    const batch = sentences.slice(i, i + batchSize);
    const batchResult = await withRetry(async () => {
      const ai = getAi();
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: {
          parts: [{ text: `Translate the following sentences to ${targetLanguage}. Return a JSON array of strings. Maintain 1:1 mapping.\n\nSentences: ${JSON.stringify(batch)}` }]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      const text = response.text?.trim();
      if (!text) throw new Error("Internal Error: Empty translation response");
      return JSON.parse(text) as string[];
    });
    results.push(...batchResult);
    if (i + batchSize < sentences.length) {
        await new Promise(r => setTimeout(r, 800));
    }
  }
  return results;
};

