  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<Particle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 512; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // Initialize particles
      const particles: Particle[] = [];
      for (let i = 0; i < 200; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 192,
          vx: (Math.random() - 0.5) * 2,
          vy: (Math.random() - 0.5) * 2,
          size: Math.random() * 3 + 1,
          targetSize: 2,
          hue: 180,
          alpha: Math.random() * 0.5 + 0.2
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          // Audio Bands
          let bass = 0;
          let mid = 0;
          let high = 0;

          for (let i = 0; i < 10; i++) bass += dataArray[i];
          for (let i = 10; i < 60; i++) mid += dataArray[i];
          for (let i = 60; i < 120; i++) high += dataArray[i];

          bass = (bass / 10) / 255;
          mid = (mid / 50) / 255;
          high = (high / 60) / 255;

          // Clear with trail effect
          ctx.fillStyle = 'rgba(2, 2, 2, 0.15)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          // Update & Draw Particles
          particlesRef.current.forEach((p, i) => {
            // Apply Audio Dynamics

            // Bass: Pulse size and Attract to center
            p.targetSize = 1 + (bass * 8);
            p.size += (p.targetSize - p.size) * 0.2;

            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);
            const attraction = (bass * 0.05);
            p.vx += (dx / dist) * attraction;
            p.vy += (dy / dist) * attraction;

            // Mid: Shift Hue
            // Cycle between cyan (180) and neon red (345)
            const targetHue = 180 + (mid * 165);
            p.hue += (targetHue - p.hue) * 0.05;

            // High: Velocity & Jitter
            const speedBoost = (high * 15);
            p.vx += (Math.random() - 0.5) * speedBoost;
            p.vy += (Math.random() - 0.5) * speedBoost;

            // Movement
            p.x += p.vx;
            p.y += p.vy;

            // Damping
            p.vx *= 0.95;
            p.vy *= 0.95;

            // Boundaries
            if (p.x < 0) { p.x = canvas.width; }
            if (p.x > canvas.width) { p.x = 0; }
            if (p.y < 0) { p.y = canvas.height; }
            if (p.y > canvas.height) { p.y = 0; }

            // Render
            const opacity = 0.2 + (mid * 0.6) + (high * 0.2);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 60%, ${opacity})`;

            // Draw shimmering trails for high frequencies
            if (high > 0.4) {
               ctx.shadowBlur = 10 * high;
               ctx.shadowColor = `hsla(${p.hue}, 100%, 70%, 1)`;
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fill();

            // Inter-particle entanglement (only for high bass activity)
            if (bass > 0.6 && i % 10 === 0) {
               const neighbor = particlesRef.current[(i + 1) % particlesRef.current.length];
               ctx.strokeStyle = `hsla(${p.hue}, 100%, 50%, ${bass * 0.2})`;
               ctx.lineWidth = 0.5;
               ctx.beginPath();
               ctx.moveTo(p.x, p.y);
               ctx.lineTo(neighbor.x, neighbor.y);
               ctx.stroke();
            }
          });
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const renderButtonLabel = () => {
    if (isLoading) return "STOP";
    if (hasInitiated) return "REGENERATE";
    return "INITIATE";
  };

  const renderButtonIcon = () => {
    if (isLoading) return <Square size={14} fill="currentColor" />;
    if (hasInitiated) return <RefreshCw size={14} />;
    return <Play size={14} fill="currentColor" />;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
              <div className="hidden md:flex items-center gap-3 text-[10px] font-mono border-l border-zinc-800 pl-4 uppercase">
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">HOST:</span>
                    <span className="text-cyan-400 font-bold">{hosts.host1.toUpperCase()}</span>
                 </div>
                 <div className="text-zinc-700">|</div>
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">CO-HOST:</span>
                    <span className="text-[#ff003c] font-bold">{hosts.host2.toUpperCase()}</span>
                 </div>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {renderButtonIcon()}
                 {renderButtonLabel()}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            <div className="bg-black/40 backdrop-blur-sm border border-cyan-500/10 px-10 py-5 rounded-sm shadow-[0_0_60px_rgba(0,243,255,0.1)] relative">
                               {/* HUD corners */}
                               <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-[#00f3ff]"></div>
                               <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-[#00f3ff]"></div>

                               <span className="text-4xl font-black text-[#00f3ff] font-tech uppercase tracking-[0.5em] drop-shadow-[0_0_20px_rgba(0,243,255,0.9)] italic flex items-center gap-4">
                                  <Zap size={24} className="text-[#ff003c] animate-pulse" />
                                  {episodeTitle.toUpperCase()}
                               </span>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2, Zap, Share2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  targetSize: number;
  activity: number; // For entanglement calculation
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<Particle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // Initialize Quantum Particles
      const particles: Particle[] = [];
      for (let i = 0; i < 250; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 192,
          vx: (Math.random() - 0.5) * 1.5,
          vy: (Math.random() - 0.5) * 1.5,
          size: Math.random() * 2 + 1,
          targetSize: 2,
          hue: 180,
          alpha: Math.random() * 0.5 + 0.3,
          activity: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          // Neural Decomposition of Audio Data
          let bass = 0;   // 0-20% of spectrum
          let mid = 0;    // 20-60% of spectrum
          let high = 0;   // 60-100% of spectrum

          const spectrumSplit1 = Math.floor(bufferLength * 0.15);
          const spectrumSplit2 = Math.floor(bufferLength * 0.55);

          for (let i = 0; i < spectrumSplit1; i++) bass += dataArray[i];
          for (let i = spectrumSplit1; i < spectrumSplit2; i++) mid += dataArray[i];
          for (let i = spectrumSplit2; i < bufferLength; i++) high += dataArray[i];

          bass = (bass / spectrumSplit1) / 255;
          mid = (mid / (spectrumSplit2 - spectrumSplit1)) / 255;
          high = (high / (bufferLength - spectrumSplit2)) / 255;

          // Trail effect: Synthetic temporal persistence
          ctx.fillStyle = 'rgba(5, 5, 8, 0.2)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          // Quantum Core Visuals
          ctx.save();
          ctx.beginPath();
          const coreRadius = 40 + (bass * 60);
          const gradient = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, coreRadius);
          gradient.addColorStop(0, `rgba(0, 243, 255, ${0.1 * bass})`);
          gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
          ctx.fillStyle = gradient;
          ctx.arc(centerX, centerY, coreRadius, 0, Math.PI * 2);
          ctx.fill();
          ctx.restore();

          // Particle Physics Engine
          particlesRef.current.forEach((p, i) => {
            // Quantum Attractor: Bass makes particles converge on the quantum core
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const distance = Math.sqrt(dx * dx + dy * dy);

            // Attractor force proportional to bass intensity
            const force = (bass * 0.15);
            p.vx += (dx / distance) * force;
            p.vy += (dy / distance) * force;

            // Size modulation based on bass pulse
            p.targetSize = (p.size * 0.8) + (bass * 12);
            p.activity = (bass + mid + high) / 3;

            // Hue shift: Mid frequencies drive color transitions (Cyberpunk palette)
            // Cyberpunk Hue range: 180 (Cyan) -> 300 (Magenta) -> 345 (Neon Red)
            const baseHue = 180;
            const hueRange = 165;
            const targetHue = baseHue + (mid * hueRange);
            p.hue += (targetHue - p.hue) * 0.1;

            // High frequency: Trajectories & Jitter
            const jitter = (high * 20);
            p.vx += (Math.random() - 0.5) * jitter;
            p.vy += (Math.random() - 0.5) * jitter;

            // Velocity Damping
            p.vx *= 0.96;
            p.vy *= 0.96;

            // Integration
            p.x += p.vx;
            p.y += p.vy;

            // Boundary wrapping
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Rendering: Quantum Particles
            const pAlpha = 0.3 + (mid * 0.5) + (high * 0.2);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 65%, ${pAlpha})`;

            // Shimmering trails for high frequencies
            if (high > 0.5) {
               ctx.shadowBlur = 15 * high;
               ctx.shadowColor = `hsla(${p.hue}, 100%, 75%, 1)`;
               // Occasional sub-atomic "jump"
               if (Math.random() > 0.98) {
                   p.x += (Math.random() - 0.5) * 100 * high;
                   p.y += (Math.random() - 0.5) * 50 * high;
               }
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            const currentDrawSize = Math.max(1, p.targetSize);
            ctx.arc(p.x, p.y, currentDrawSize / 2, 0, Math.PI * 2);
            ctx.fill();

            // Quantum Entanglement: Link highly active particles
            // Connect to a few nearby particles if activity is high
            if (bass > 0.4 && i % 12 === 0) {
               for (let j = 0; j < 3; j++) {
                  const neighborIndex = (i + j + 1) % particlesRef.current.length;
                  const neighbor = particlesRef.current[neighborIndex];
                  const dnx = p.x - neighbor.x;
                  const dny = p.y - neighbor.y;
                  const distToNeighbor = Math.sqrt(dnx * dnx + dny * dny);

                  if (distToNeighbor < canvas.width * 0.15) {
                     ctx.strokeStyle = `hsla(${p.hue}, 100%, 50%, ${bass * 0.15})`;
                     ctx.lineWidth = 0.5;
                     ctx.beginPath();
                     ctx.moveTo(p.x, p.y);
                     // Entanglement arc
                     const cpX = (p.x + neighbor.x) / 2;
                     const cpY = (p.y + neighbor.y) / 2 - (distToNeighbor * 0.2);
                     ctx.quadraticCurveTo(cpX, cpY, neighbor.x, neighbor.y);
                     ctx.stroke();
                  }
               }
            }
          });
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const renderButtonLabel = () => {
    if (isLoading) return "STOP";
    if (hasInitiated) return "REGENERATE";
    return "INITIATE";
  };

  const renderButtonIcon = () => {
    if (isLoading) return <Square size={14} fill="currentColor" />;
    if (hasInitiated) return <RefreshCw size={14} />;
    return <Play size={14} fill="currentColor" />;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
              <div className="hidden md:flex items-center gap-3 text-[10px] font-mono border-l border-zinc-800 pl-4 uppercase">
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">HOST:</span>
                    <span className="text-cyan-400 font-bold">{hosts.host1.toUpperCase()}</span>
                 </div>
                 <div className="text-zinc-700">|</div>
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">CO-HOST:</span>
                    <span className="text-[#ff003c] font-bold">{hosts.host2.toUpperCase()}</span>
                 </div>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {renderButtonIcon()}
                 {renderButtonLabel()}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            <div className="bg-black/40 backdrop-blur-sm border border-cyan-500/10 px-10 py-5 rounded-sm shadow-[0_0_60px_rgba(0,243,255,0.1)] relative">
                               {/* HUD corners */}
                               <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-[#00f3ff]"></div>
                               <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-[#00f3ff]"></div>

                               <span className="text-4xl font-black text-[#00f3ff] font-tech uppercase tracking-[0.5em] drop-shadow-[0_0_20px_rgba(0,243,255,0.9)] italic flex items-center gap-4">
                                  <Share2 size={24} className="text-[#ff003c] animate-pulse" />
                                  {episodeTitle.toUpperCase()}
                               </span>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2, Zap, Share2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  targetSize: number;
  activity: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<Particle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // Initialize Quantum Particles
      const particles: Particle[] = [];
      for (let i = 0; i < 280; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 192,
          vx: (Math.random() - 0.5) * 2,
          vy: (Math.random() - 0.5) * 2,
          size: Math.random() * 1.5 + 0.5,
          targetSize: 1.5,
          hue: 180,
          alpha: Math.random() * 0.4 + 0.2,
          activity: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          let bass = 0; 
          let mid = 0;
          let high = 0;

          const split1 = Math.floor(bufferLength * 0.15);
          const split2 = Math.floor(bufferLength * 0.55);

          for (let i = 0; i < split1; i++) bass += dataArray[i];
          for (let i = split1; i < split2; i++) mid += dataArray[i];
          for (let i = split2; i < bufferLength; i++) high += dataArray[i];

          bass = (bass / split1) / 255;
          mid = (mid / (split2 - split1)) / 255;
          high = (high / (bufferLength - split2)) / 255;

          // Trail persist
          ctx.fillStyle = 'rgba(2, 2, 4, 0.18)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          // Entanglement Field Draw
          particlesRef.current.forEach((p, i) => {
            // Quantum Physics: Bass forces converge on center
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            const attraction = (bass * 0.2);
            p.vx += (dx / dist) * attraction;
            p.vy += (dy / dist) * attraction;

            // Size pulse
            p.targetSize = (p.size * 0.5) + (bass * 14);
            p.activity = (bass + mid + high) / 3;

            // Cyberpunk Hue cycle (Cyan to Magenta to Red)
            const hueBase = 180; // Cyan
            const hueRange = 165; 
            const targetHue = hueBase + (mid * hueRange);
            p.hue += (targetHue - p.hue) * 0.08;

            // High freq jitter
            const shake = (high * 22);
            p.vx += (Math.random() - 0.5) * shake;
            p.vy += (Math.random() - 0.5) * shake;

            p.vx *= 0.94;
            p.vy *= 0.94;

            p.x += p.vx;
            p.y += p.vy;

            // Wrap
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            const opacity = 0.25 + (mid * 0.5) + (high * 0.25);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 60%, ${opacity})`;

            if (high > 0.45) {
               ctx.shadowBlur = 12 * high;
               ctx.shadowColor = `hsla(${p.hue}, 100%, 70%, 1)`;
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, Math.max(0.5, p.targetSize / 2), 0, Math.PI * 2);
            ctx.fill();

            // Quantum Entanglement Connections
            if (bass > 0.35 && i % 14 === 0) {
               const partners = [
                 particlesRef.current[(i + 1) % particlesRef.current.length],
                 particlesRef.current[(i + 5) % particlesRef.current.length]
               ];

               partners.forEach(partner => {
                  const dpx = p.x - partner.x;
                  const dpy = p.y - partner.y;
                  const pDist = Math.sqrt(dpx * dpx + dpy * dpy);

                  if (pDist < canvas.width * 0.12) {
                     ctx.strokeStyle = `hsla(${p.hue}, 100%, 55%, ${bass * 0.15})`;
                     ctx.lineWidth = 0.6;
                     ctx.beginPath();
                     ctx.moveTo(p.x, p.y);
                     const arcX = (p.x + partner.x) / 2;
                     const arcY = (p.y + partner.y) / 2 - (pDist * 0.15);
                     ctx.quadraticCurveTo(arcX, arcY, partner.x, partner.y);
                     ctx.stroke();
                  }
               });
            }
          });
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {isLoading ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                 {isLoading ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE"}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            <div className="bg-black/60 backdrop-blur-md border border-cyan-500/20 px-6 py-3 rounded-sm shadow-[0_0_40px_rgba(0,243,255,0.15)] relative max-w-[80%]">
                               <div className="absolute top-0 left-0 w-3 h-3 border-t border-l border-[#00f3ff]"></div>
                               <div className="absolute bottom-0 right-0 w-3 h-3 border-b border-r border-[#00f3ff]"></div>

                               <span className="text-xl font-black text-[#00f3ff] font-tech uppercase tracking-[0.3em] drop-shadow-[0_0_15px_rgba(0,243,255,0.8)] italic flex items-center gap-3 text-center justify-center">
                                  <Share2 size={16} className="text-[#ff003c] animate-pulse shrink-0" />
                                  {episodeTitle.toUpperCase()}
                               </span>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2, Zap, Share2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

interface QuantumParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  targetSize: number;
  intensity: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<QuantumParticle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // Initialize Quantum Particles
      const particles: QuantumParticle[] = [];
      for (let i = 0; i < 300; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 192,
          vx: (Math.random() - 0.5) * 1.5,
          vy: (Math.random() - 0.5) * 1.5,
          size: Math.random() * 1.5 + 0.5,
          targetSize: 1,
          hue: 180,
          alpha: Math.random() * 0.4 + 0.2,
          intensity: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          // Audio Band Processing
          let bass = 0; 
          let mid = 0;
          let high = 0;
          const split1 = Math.floor(bufferLength * 0.1);
          const split2 = Math.floor(bufferLength * 0.5);

          for (let i = 0; i < split1; i++) bass += dataArray[i];
          for (let i = split1; i < split2; i++) mid += dataArray[i];
          for (let i = split2; i < bufferLength; i++) high += dataArray[i];

          bass = (bass / split1) / 255;
          mid = (mid / (split2 - split1)) / 255;
          high = (high / (bufferLength - split2)) / 255;

          // Trail persist background
          ctx.fillStyle = 'rgba(2, 2, 5, 0.18)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          // Quantum Core (Bass Response)
          const coreRadius = 30 + (bass * 80);
          const coreGrad = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, coreRadius);
          coreGrad.addColorStop(0, `rgba(0, 243, 255, ${0.12 * bass})`);
          coreGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
          ctx.fillStyle = coreGrad;
          ctx.beginPath();
          ctx.arc(centerX, centerY, coreRadius, 0, Math.PI * 2);
          ctx.fill();

          // Particle Physics
          particlesRef.current.forEach((p, i) => {
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Attractor (Bass)
            const gravity = (bass * 0.1);
            p.vx += (dx / dist) * gravity;
            p.vy += (dy / dist) * gravity;

            // Size Pulse (Bass)
            p.targetSize = 0.5 + (bass * 15);
            p.intensity = (bass + mid + high) / 3;

            // Color Shift (Mid - Neon Spectrum)
            const cyan = 180;
            const magenta = 310;
            const targetHue = cyan + (mid * (magenta - cyan));
            p.hue += (targetHue - p.hue) * 0.1;

            // Jitter & Trails (High)
            const jitter = (high * 25);
            p.vx += (Math.random() - 0.5) * jitter;
            p.vy += (Math.random() - 0.5) * jitter;

            // Dynamics integration
            p.vx *= 0.95;
            p.vy *= 0.95;
            p.x += p.vx;
            p.y += p.vy;

            // Boundaries
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Render Node
            const opacity = 0.3 + (mid * 0.5) + (high * 0.2);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 65%, ${opacity})`;

            if (high > 0.4) {
               ctx.shadowBlur = 10 * high;
               ctx.shadowColor = `hsla(${p.hue}, 100%, 75%, 1)`;
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, Math.max(0.5, p.targetSize / 2), 0, Math.PI * 2);
            ctx.fill();

            // Quantum Entanglement Arcs
            if (bass > 0.4 && i % 15 === 0) {
                const partners = [
                    particlesRef.current[(i + 2) % particlesRef.current.length],
                    particlesRef.current[(i + 7) % particlesRef.current.length]
                ];

                partners.forEach(pt => {
                    const dpx = p.x - pt.x;
                    const dpy = p.y - pt.y;
                    const pDist = Math.sqrt(dpx * dpx + dpy * dpy);

                    if (pDist < canvas.width * 0.12) {
                        ctx.strokeStyle = `hsla(${p.hue}, 100%, 60%, ${bass * 0.15})`;
                        ctx.lineWidth = 0.6;
                        ctx.beginPath();
                        ctx.moveTo(p.x, p.y);
                        const cpx = (p.x + pt.x) / 2;
                        const cpy = (p.y + pt.y) / 2 - (pDist * 0.2);
                        ctx.quadraticCurveTo(cpx, cpy, pt.x, pt.y);
                        ctx.stroke();
                    }
                });
            }
          });
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {isLoading ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                 {isLoading ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE"}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            <div className="bg-black/60 backdrop-blur-md border border-cyan-500/20 px-6 py-3 rounded-sm shadow-[0_0_40px_rgba(0,243,255,0.15)] relative max-w-[70%]">
                               {/* HUD corners */}
                               <div className="absolute top-0 left-0 w-3 h-3 border-t border-l border-[#00f3ff]"></div>
                               <div className="absolute bottom-0 right-0 w-3 h-3 border-b border-r border-[#00f3ff]"></div>

                               <span className="text-sm md:text-base font-black text-[#00f3ff] font-tech uppercase tracking-[0.4em] drop-shadow-[0_0_10px_rgba(0,243,255,0.8)] italic flex items-center gap-3 justify-center text-center leading-tight">
                                  <Share2 size={16} className="text-[#ff003c] animate-pulse shrink-0" />
                                  {episodeTitle.toUpperCase()}
                               </span>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2, Zap, Share2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

interface QuantumParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  targetSize: number;
  intensity: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<QuantumParticle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // Initialize Quantum Particles
      const particles: QuantumParticle[] = [];
      for (let i = 0; i < 300; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 192,
          vx: (Math.random() - 0.5) * 2,
          vy: (Math.random() - 0.5) * 2,
          size: Math.random() * 1.2 + 0.4,
          targetSize: 1,
          hue: 180,
          alpha: Math.random() * 0.4 + 0.2,
          intensity: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          let bass = 0; 
          let mid = 0;
          let high = 0;
          const split1 = Math.floor(bufferLength * 0.12);
          const split2 = Math.floor(bufferLength * 0.5);

          for (let i = 0; i < split1; i++) bass += dataArray[i];
          for (let i = split1; i < split2; i++) mid += dataArray[i];
          for (let i = split2; i < bufferLength; i++) high += dataArray[i];

          bass = (bass / split1) / 255;
          mid = (mid / (split2 - split1)) / 255;
          high = (high / (bufferLength - split2)) / 255;

          // Trail persist with deep cyberpunk black
          ctx.fillStyle = 'rgba(2, 2, 8, 0.22)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          // Entanglement physics
          particlesRef.current.forEach((p, i) => {
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Central Attractor (Bass)
            const gravity = (bass * 0.15);
            p.vx += (dx / dist) * gravity;
            p.vy += (dy / dist) * gravity;

            // Neural Size Pulse (Bass)
            p.targetSize = 0.8 + (bass * 16);
            p.intensity = (bass + mid + high) / 3;

            // Color Spectrum (Mid - Neon transitions)
            const baseHue = 180; // Cyan
            const hueRange = 160; // Up to Magenta/Red
            const targetHue = baseHue + (mid * hueRange);
            p.hue += (targetHue - p.hue) * 0.08;

            // Quantum Jitter (High)
            const jitter = (high * 24);
            p.vx += (Math.random() - 0.5) * jitter;
            p.vy += (Math.random() - 0.5) * jitter;

            p.vx *= 0.94;
            p.vy *= 0.94;
            p.x += p.vx;
            p.y += p.vy;

            // Wrapping logic
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Render node
            const alpha = 0.25 + (mid * 0.55) + (high * 0.2);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 60%, ${alpha})`;

            if (high > 0.4) {
               ctx.shadowBlur = 12 * high;
               ctx.shadowColor = `hsla(${p.hue}, 100%, 75%, 0.8)`;
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, Math.max(0.6, p.targetSize / 2), 0, Math.PI * 2);
            ctx.fill();

            // Entanglement Connections (Active Nodes)
            if (bass > 0.38 && i % 18 === 0) {
                const partnerCount = 2;
                for (let k = 1; k <= partnerCount; k++) {
                    const pt = particlesRef.current[(i + k * 3) % particlesRef.current.length];
                    const dpx = p.x - pt.x;
                    const dpy = p.y - pt.y;
                    const pDist = Math.sqrt(dpx * dpx + dpy * dpy);

                    if (pDist < canvas.width * 0.1) {
                        ctx.strokeStyle = `hsla(${p.hue}, 100%, 65%, ${bass * 0.18})`;
                        ctx.lineWidth = 0.5;
                        ctx.beginPath();
                        ctx.moveTo(p.x, p.y);
                        const midX = (p.x + pt.x) / 2;
                        const midY = (p.y + pt.y) / 2 - (pDist * 0.2);
                        ctx.quadraticCurveTo(midX, midY, pt.x, pt.y);
                        ctx.stroke();
                    }
                }
            }
          });
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {isLoading ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                 {isLoading ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE"}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            <div className="bg-black/70 backdrop-blur-lg border border-cyan-500/20 px-5 py-2.5 rounded-sm shadow-[0_0_30px_rgba(0,243,255,0.12)] relative max-w-[65%]">
                               {/* HUD corners */}
                               <div className="absolute top-0 left-0 w-2.5 h-2.5 border-t border-l border-[#00f3ff]"></div>
                               <div className="absolute bottom-0 right-0 w-2.5 h-2.5 border-b border-r border-[#00f3ff]"></div>

                               <span className="text-xs md:text-sm font-black text-[#00f3ff] font-tech uppercase tracking-[0.3em] drop-shadow-[0_0_8px_rgba(0,243,255,0.6)] italic flex items-center gap-3 justify-center text-center leading-tight">
                                  <Share2 size={14} className="text-[#ff003c] animate-pulse shrink-0" />
                                  {episodeTitle.toUpperCase()}
                               </span>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2, Zap, Share2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

interface QuantumParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  targetSize: number;
  intensity: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<QuantumParticle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // Initialize high-density Quantum Particle system
      const particles: QuantumParticle[] = [];
      for (let i = 0; i < 350; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 192,
          vx: (Math.random() - 0.5) * 2,
          vy: (Math.random() - 0.5) * 2,
          size: Math.random() * 1.5 + 0.5,
          targetSize: 1,
          hue: 180,
          alpha: Math.random() * 0.4 + 0.2,
          intensity: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          // Neural Frequency Decomposition
          let bass = 0; 
          let mid = 0;
          let high = 0;
          const split1 = Math.floor(bufferLength * 0.1);
          const split2 = Math.floor(bufferLength * 0.5);

          for (let i = 0; i < split1; i++) bass += dataArray[i];
          for (let i = split1; i < split2; i++) mid += dataArray[i];
          for (let i = split2; i < bufferLength; i++) high += dataArray[i];

          bass = (bass / split1) / 255;
          mid = (mid / (split2 - split1)) / 255;
          high = (high / (bufferLength - split2)) / 255;

          // Trail temporal persistence (Cyberpunk black)
          ctx.fillStyle = 'rgba(2, 2, 12, 0.25)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          // Central Gravity Well (Bass)
          const coreRadius = 20 + (bass * 100);
          const coreGrad = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, coreRadius);
          coreGrad.addColorStop(0, `rgba(0, 243, 255, ${0.15 * bass})`);
          coreGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
          ctx.fillStyle = coreGrad;
          ctx.beginPath();
          ctx.arc(centerX, centerY, coreRadius, 0, Math.PI * 2);
          ctx.fill();

          // Particle Quantum Physics
          particlesRef.current.forEach((p, i) => {
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Bass-driven attraction
            const gravity = (bass * 0.22);
            p.vx += (dx / dist) * gravity;
            p.vy += (dy / dist) * gravity;

            // Frequency Size modulation
            p.targetSize = 0.5 + (bass * 20);
            p.intensity = (bass + mid + high) / 3;

            // Neon Hue cycling (Cyan -> Magenta -> Red)
            const cyanHue = 180;
            const magentaHue = 320;
            const hueTarget = cyanHue + (mid * (magentaHue - cyanHue));
            p.hue += (hueTarget - p.hue) * 0.12;

            // Quantum temporal jitter (High)
            const jitterScale = (high * 30);
            p.vx += (Math.random() - 0.5) * jitterScale;
            p.vy += (Math.random() - 0.5) * jitterScale;

            // Friction/Dynamics
            p.vx *= 0.93;
            p.vy *= 0.93;
            p.x += p.vx;
            p.y += p.vy;

            // Quantum Wrap-around
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Shimmering rendering
            const alphaVal = 0.2 + (mid * 0.6) + (high * 0.2);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 65%, ${alphaVal})`;

            if (high > 0.45) {
               ctx.shadowBlur = 15 * high;
               ctx.shadowColor = `hsla(${p.hue}, 100%, 75%, 0.9)`;
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, Math.max(0.6, p.targetSize / 2.2), 0, Math.PI * 2);
            ctx.fill();

            // Quantum Entanglement Arcs (Neural Layer)
            if (bass > 0.35 && i % 20 === 0) {
                const searchDist = canvas.width * 0.08;
                for (let k = 1; k <= 3; k++) {
                    const pt = particlesRef.current[(i + k * 4) % particlesRef.current.length];
                    const distCheck = Math.sqrt(Math.pow(p.x - pt.x, 2) + Math.pow(p.y - pt.y, 2));

                    if (distCheck < searchDist) {
                        ctx.strokeStyle = `hsla(${p.hue}, 100%, 60%, ${bass * 0.2})`;
                        ctx.lineWidth = 0.4;
                        ctx.beginPath();
                        ctx.moveTo(p.x, p.y);
                        // Entanglement curvature
                        const mx = (p.x + pt.x) / 2;
                        const my = (p.y + pt.y) / 2 - (distCheck * 0.25 * mid);
                        ctx.quadraticCurveTo(mx, my, pt.x, pt.y);
                        ctx.stroke();
                    }
                }
            }
          });
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {isLoading ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                 {isLoading ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE"}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none opacity-40"></div>

                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            <div className="bg-black/75 backdrop-blur-xl border border-cyan-500/30 px-5 py-2.5 rounded-sm shadow-[0_0_40px_rgba(0,243,255,0.15)] relative max-w-[60%]">
                               {/* Holographic HUD Corners */}
                               <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-[#00f3ff] shadow-[0_0_5px_#00f3ff]"></div>
                               <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-[#00f3ff] shadow-[0_0_5px_#00f3ff]"></div>

                               <span className="text-[10px] md:text-xs font-black text-[#00f3ff] font-tech uppercase tracking-[0.4em] drop-shadow-[0_0_10px_rgba(0,243,255,0.8)] italic flex items-center gap-3 justify-center text-center leading-tight">
                                  <Share2 size={12} className="text-[#ff003c] animate-pulse shrink-0" />
                                  {episodeTitle.toUpperCase()}
                               </span>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2, Zap, Share2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

interface QuantumParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  targetSize: number;
  intensity: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<QuantumParticle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // Initialize high-density Quantum Particle system
      const particles: QuantumParticle[] = [];
      for (let i = 0; i < 400; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 192,
          vx: (Math.random() - 0.5) * 2.5,
          vy: (Math.random() - 0.5) * 2.5,
          size: Math.random() * 1.5 + 0.5,
          targetSize: 1,
          hue: 180,
          alpha: Math.random() * 0.4 + 0.2,
          intensity: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          // Neural Frequency Decomposition
          let bass = 0; 
          let mid = 0;
          let high = 0;
          const split1 = Math.floor(bufferLength * 0.1);
          const split2 = Math.floor(bufferLength * 0.45);

          for (let i = 0; i < split1; i++) bass += dataArray[i];
          for (let i = split1; i < split2; i++) mid += dataArray[i];
          for (let i = split2; i < bufferLength; i++) high += dataArray[i];

          bass = (bass / split1) / 255;
          mid = (mid / (split2 - split1)) / 255;
          high = (high / (bufferLength - split2)) / 255;

          // Temporal Persistence (Persistence of Vision effect)
          ctx.fillStyle = 'rgba(2, 2, 10, 0.22)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          // Entanglement Core (Dynamic Hub)
          const coreRadius = 25 + (bass * 120);
          const coreGrad = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, coreRadius);
          coreGrad.addColorStop(0, `rgba(0, 243, 255, ${0.12 * bass})`);
          coreGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
          ctx.fillStyle = coreGrad;
          ctx.beginPath();
          ctx.arc(centerX, centerY, coreRadius, 0, Math.PI * 2);
          ctx.fill();

          // Particle Physics Engine
          particlesRef.current.forEach((p, i) => {
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Bass-driven Gravitational Pull
            const gravity = (bass * 0.25);
            p.vx += (dx / dist) * gravity;
            p.vy += (dy / dist) * gravity;

            // Size modulation based on high frequencies
            p.targetSize = 0.5 + (high * 18);
            p.intensity = (bass + mid + high) / 3;

            // Neon Hue transitions (Cyan to Magenta to Red)
            const baseHue = 180; 
            const hueShift = 140 * mid;
            p.hue = baseHue + hueShift;

            // Quantum Jitter
            const jitter = (high * 35);
            p.vx += (Math.random() - 0.5) * jitter;
            p.vy += (Math.random() - 0.5) * jitter;

            p.vx *= 0.92;
            p.vy *= 0.92;
            p.x += p.vx;
            p.y += p.vy;

            // Quantum Wrap
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Render Particle Node
            const particleAlpha = 0.2 + (mid * 0.6);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 65%, ${particleAlpha})`;

            if (high > 0.45) {
               ctx.shadowBlur = 20 * high;
               ctx.shadowColor = `hsla(${p.hue}, 100%, 75%, 0.9)`;
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, Math.max(0.6, p.targetSize / 2), 0, Math.PI * 2);
            ctx.fill();

            // Quantum Entanglement Filaments
            if (bass > 0.35 && i % 24 === 0) {
                const connRange = canvas.width * 0.08;
                for (let k = 1; k <= 2; k++) {
                    const pt = particlesRef.current[(i + k * 5) % particlesRef.current.length];
                    const distCheck = Math.sqrt(Math.pow(p.x - pt.x, 2) + Math.pow(p.y - pt.y, 2));

                    if (distCheck < connRange) {
                        ctx.strokeStyle = `hsla(${p.hue}, 100%, 60%, ${bass * 0.2})`;
                        ctx.lineWidth = 0.5;
                        ctx.beginPath();
                        ctx.moveTo(p.x, p.y);
                        // Filament Curvature
                        const mx = (p.x + pt.x) / 2;
                        const my = (p.y + pt.y) / 2 - (distCheck * 0.3 * mid);
                        ctx.quadraticCurveTo(mx, my, pt.x, pt.y);
                        ctx.stroke();
                    }
                }
            }
          });
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {isLoading ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                 {isLoading ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE"}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none opacity-30"></div>

                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            <div className="bg-black/75 backdrop-blur-xl border border-cyan-500/30 px-4 py-2 rounded-sm shadow-[0_0_35px_rgba(0,243,255,0.18)] relative max-w-[55%] flex flex-col items-center">
                               {/* HUD Geometric Elements */}
                               <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-[#00f3ff] shadow-[0_0_4px_#00f3ff]"></div>
                               <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-[#00f3ff] shadow-[0_0_4px_#00f3ff]"></div>
                               <div className="absolute top-0 right-0 w-1.5 h-1.5 border-t border-r border-[#ff003c]"></div>
                               <div className="absolute bottom-0 left-0 w-1.5 h-1.5 border-b border-l border-[#ff003c]"></div>

                               <span className="text-[9px] md:text-[10px] font-black text-[#00f3ff] font-tech uppercase tracking-[0.4em] drop-shadow-[0_0_6px_rgba(0,243,255,0.8)] italic flex items-center gap-2 justify-center text-center leading-none">
                                  <Activity size={10} className="text-[#ff003c] animate-pulse shrink-0" />
                                  {episodeTitle.toUpperCase()}
                               </span>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2, Zap, Share2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

interface QuantumParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  targetSize: number;
  charge: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<QuantumParticle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // Initialize high-fidelity Quantum Particle system
      const particles: QuantumParticle[] = [];
      for (let i = 0; i < 450; i++) {
        particles.push({
          x: Math.random() * 1800,
          y: Math.random() * 192,
          vx: (Math.random() - 0.5) * 3,
          vy: (Math.random() - 0.5) * 3,
          size: Math.random() * 1.8 + 0.4,
          targetSize: 1,
          hue: 180,
          alpha: Math.random() * 0.5 + 0.2,
          charge: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current && !isPlayerMinimized) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          let bass = 0; 
          let mid = 0;
          let high = 0;
          const split1 = Math.floor(bufferLength * 0.12);
          const split2 = Math.floor(bufferLength * 0.5);

          for (let i = 0; i < split1; i++) bass += dataArray[i];
          for (let i = split1; i < split2; i++) mid += dataArray[i];
          for (let i = split2; i < bufferLength; i++) high += dataArray[i];

          bass = (bass / split1) / 255;
          mid = (mid / (split2 - split1)) / 255;
          high = (high / (bufferLength - split2)) / 255;

          // Deep Black Hole background with temporal trails
          ctx.fillStyle = 'rgba(1, 1, 5, 0.28)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          // Entanglement Singularity (Bass Pulse)
          const coreRadius = 15 + (bass * 140);
          const coreGrad = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, coreRadius);
          coreGrad.addColorStop(0, `rgba(0, 243, 255, ${0.18 * bass})`);
          coreGrad.addColorStop(0.5, `rgba(255, 0, 60, ${0.05 * mid})`);
          coreGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
          ctx.fillStyle = coreGrad;
          ctx.beginPath();
          ctx.arc(centerX, centerY, coreRadius, 0, Math.PI * 2);
          ctx.fill();

          // Particle Quantum Physics Engine
          ctx.globalCompositeOperation = 'screen';
          particlesRef.current.forEach((p, i) => {
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Gravitational Pull towards Center (Bass)
            const gravity = (bass * 0.3);
            p.vx += (dx / dist) * gravity;
            p.vy += (dy / dist) * gravity;

            // Frequency Charge
            p.charge = (mid * 0.5) + (high * 0.5);
            p.targetSize = 0.4 + (high * 22);

            // Neon Hue transitions
            const baseHue = 180; // Cyan
            const hueRange = 150; // To Magenta/Red
            p.hue = baseHue + (mid * hueRange);

            // Entropy Jitter (High)
            const jitter = (high * 35);
            p.vx += (Math.random() - 0.5) * jitter;
            p.vy += (Math.random() - 0.5) * jitter;

            // Dynamics
            p.vx *= 0.91;
            p.vy *= 0.91;
            p.x += p.vx;
            p.y += p.vy;

            // Quantum Wrapping
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Render Particle
            const alpha = 0.25 + (p.charge * 0.6);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 65%, ${alpha})`;

            if (high > 0.4 || p.charge > 0.6) {
               ctx.shadowBlur = 25 * p.charge;
               ctx.shadowColor = `hsla(${p.hue}, 100%, 75%, 0.8)`;
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, Math.max(0.6, p.targetSize / 2.5), 0, Math.PI * 2);
            ctx.fill();

            // Entanglement Connections (Neural Filaments)
            if (bass > 0.3 && i % 25 === 0) {
                const connRange = canvas.width * 0.07;
                for (let k = 1; k <= 2; k++) {
                    const pt = particlesRef.current[(i + k * 7) % particlesRef.current.length];
                    const distCheck = Math.sqrt(Math.pow(p.x - pt.x, 2) + Math.pow(p.y - pt.y, 2));

                    if (distCheck < connRange) {
                        ctx.strokeStyle = `hsla(${p.hue}, 100%, 60%, ${bass * 0.22})`;
                        ctx.lineWidth = 0.4;
                        ctx.beginPath();
                        ctx.moveTo(p.x, p.y);
                        // Curvature influenced by high frequencies
                        const mx = (p.x + pt.x) / 2;
                        const my = (p.y + pt.y) / 2 - (distCheck * 0.3 * high);
                        ctx.quadraticCurveTo(mx, my, pt.x, pt.y);
                        ctx.stroke();
                    }
                }
            }
          });
          ctx.globalCompositeOperation = 'source-over';
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex, isPlayerMinimized]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {isLoading ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                 {isLoading ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE"}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           <div className={`bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[277px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                      {/* Matrix Grid */}
                      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.03)_1px,transparent_1px)] bg-[size:24px_24px] pointer-events-none"></div>

                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                            {/* Holographic HUD Container */}
                            <div className="bg-black/80 backdrop-blur-xl border border-cyan-500/40 px-4 py-2 rounded-sm shadow-[0_0_40px_rgba(0,243,255,0.2)] relative max-w-[50%] flex flex-col items-center">
                               {/* HUD Accents */}
                               <div className="absolute -top-1 -left-1 w-3 h-3 border-t-2 border-l-2 border-[#00f3ff] shadow-[0_0_8px_#00f3ff]"></div>
                               <div className="absolute -bottom-1 -right-1 w-3 h-3 border-b-2 border-r-2 border-[#ff003c] shadow-[0_0_8px_#ff003c]"></div>

                               <div className="flex items-center gap-2 mb-1.5">
                                  <div className="w-1 h-1 bg-[#00f3ff] animate-ping"></div>
                                  <span className="text-[7px] font-mono text-cyan-500 uppercase tracking-widest opacity-60">Neural_Stream.active</span>
                               </div>

                               <span className="text-[8px] md:text-[9px] font-black text-white font-tech uppercase tracking-[0.5em] drop-shadow-[0_0_5px_rgba(0,243,255,0.8)] italic flex items-center gap-3 justify-center text-center leading-none">
                                  {episodeTitle.toUpperCase()}
                               </span>

                               <div className="mt-1.5 flex gap-1 items-center">
                                  <div className="w-12 h-[1px] bg-cyan-900"></div>
                                  <Activity size={8} className="text-[#ff003c] animate-pulse" />
                                  <div className="w-12 h-[1px] bg-cyan-900"></div>
                               </div>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : audioSrc ? (
                        <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                      ) : (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                          <Activity size={32} className="opacity-20" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors rounded-full bg-zinc-900/50" title={isPlayerMinimized ? "Expand Player" : "Minimize Player"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>
           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw, Minimize2, Maximize2, Zap, Share2 } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

interface QuantumParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  hue: number;
  alpha: number;
  targetSize: number;
  charge: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<QuantumParticle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // High-density background particle system
      const particles: QuantumParticle[] = [];
      const count = 500;
      for (let i = 0; i < count; i++) {
        particles.push({
          x: Math.random() * window.innerWidth,
          y: Math.random() * window.innerHeight,
          vx: (Math.random() - 0.5) * 2,
          vy: (Math.random() - 0.5) * 2,
          size: Math.random() * 2 + 0.5,
          targetSize: 1,
          hue: 180,
          alpha: Math.random() * 0.4 + 0.1,
          charge: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          let bass = 0, mid = 0, high = 0;
          const split1 = Math.floor(bufferLength * 0.1);
          const split2 = Math.floor(bufferLength * 0.5);
          for (let i = 0; i < split1; i++) bass += dataArray[i];
          for (let i = split1; i < split2; i++) mid += dataArray[i];
          for (let i = split2; i < bufferLength; i++) high += dataArray[i];
          bass = (bass / split1) / 255;
          mid = (mid / (split2 - split1)) / 255;
          high = (high / (bufferLength - split2)) / 255;

          // Full scope temporal trail
          ctx.fillStyle = 'rgba(1, 1, 3, 0.15)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          ctx.globalCompositeOperation = 'screen';
          particlesRef.current.forEach((p, i) => {
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Central Attractor physics
            const gravity = (bass * 0.4);
            p.vx += (dx / dist) * gravity;
            p.vy += (dy / dist) * gravity;

            // Noise/Entropy
            const entropy = (high * 0.8);
            p.vx += (Math.random() - 0.5) * entropy;
            p.vy += (Math.random() - 0.5) * entropy;

            p.charge = (mid * 0.5) + (high * 0.5);
            p.targetSize = 0.5 + (high * 15);
            p.hue = 180 + (mid * 140); // Cyan to Red

            p.vx *= 0.96;
            p.vy *= 0.96;
            p.x += p.vx;
            p.y += p.vy;

            // Loop wrapping
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Render Particle
            const alpha = 0.1 + (p.charge * 0.7);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 65%, ${alpha})`;

            if (p.charge > 0.6) {
                ctx.shadowBlur = 15 * p.charge;
                ctx.shadowColor = `hsla(${p.hue}, 100%, 75%, 0.8)`;
            } else {
                ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, Math.max(0.6, p.targetSize / 4), 0, Math.PI * 2);
            ctx.fill();

            // Quantum Connections (Neural Web)
            if (bass > 0.35 && i % 30 === 0) {
                const range = canvas.width * 0.15;
                const pt = particlesRef.current[(i + 15) % particlesRef.current.length];
                const d = Math.sqrt(Math.pow(p.x - pt.x, 2) + Math.pow(p.y - pt.y, 2));
                if (d < range) {
                    ctx.strokeStyle = `hsla(${p.hue}, 100%, 60%, ${bass * 0.15})`;
                    ctx.lineWidth = 0.5;
                    ctx.beginPath();
                    ctx.moveTo(p.x, p.y);
                    const mx = (p.x + pt.x) / 2;
                    const my = (p.y + pt.y) / 2 - (d * 0.2 * high);
                    ctx.quadraticCurveTo(mx, my, pt.x, pt.y);
                    ctx.stroke();
                }
            }
          });
          ctx.globalCompositeOperation = 'source-over';
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
