export const generatePodcastAudio = async (
  file: FileContext,
  chapter: Chapter,
  tone: string = 'Engaging',
  hosts: { host1: string, voice1: string, host2: string, voice2: string },
  language: string = 'English'
): Promise<{ audio: string; script: string; episodeTitle: string }> => {
  return withRetry(async () => {
    const ai = getAi();
    // Step 1: Generate the script
    const scriptResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Create a ${tone} podcast dialogue about the chapter "${chapter.title}" in ${language}. 
          Keep the conversation concise (max 300 words to ensure processing stability). 
          The script MUST strictly use the format "SpeakerName: Text" for every single line.
          Use hosts ${hosts.host1} and ${hosts.host2}. 
          Output JSON with 'episodeTitle' and 'script'.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            episodeTitle: { type: Type.STRING },
            script: { type: Type.STRING }
          },
          required: ["episodeTitle", "script"]
        }
      }
    });

    const parsedResponse = JSON.parse(scriptResponse.text || "{}");
    if (!parsedResponse.script) throw new Error("Script generation failed");

    // Clean script for TTS to avoid 500 errors from unexpected characters
    const cleanScript = parsedResponse.script
      .replace(/\*\*/g, '')
      .replace(/\*/g, '')
      .replace(/\[.*?\]/g, '') // Remove stage directions
      .trim();

    // Step 2: Generate the multi-speaker audio
    const audioResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: cleanScript }] }],
      config: {
        responseModalities: ['AUDIO'],
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              { speaker: hosts.host1, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice1 } } },
              { speaker: hosts.host2, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice2 } } }
            ]
          }
        }
      }
    });

    const base64Audio = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) {
      console.error("TTS Response missing audio data:", audioResponse);
      throw new Error("Audio generation failed - No data returned from API");
    }

    return { audio: base64Audio, script: cleanScript, episodeTitle: parsedResponse.episodeTitle };
  });
};

