export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const particlesRef = useRef<QuantumParticle[]>([]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);
    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;
    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;
      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();
      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];
    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);
    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });
    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }
    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;
    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);
      if (abortRef.current) return;
      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;

      // High-density background particle system
      const particles: QuantumParticle[] = [];
      const count = 600;
      for (let i = 0; i < count; i++) {
        particles.push({
          x: Math.random() * window.innerWidth,
          y: Math.random() * window.innerHeight,
          vx: (Math.random() - 0.5) * 3,
          vy: (Math.random() - 0.5) * 3,
          size: Math.random() * 2.5 + 0.5,
          targetSize: 1,
          hue: 180,
          alpha: Math.random() * 0.5 + 0.1,
          charge: 0
        });
      }
      particlesRef.current = particles;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, audioSrc]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const audio = audioRef.current;

    const draw = () => {
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      if (canvasRef.current && analyserRef.current) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);

          let bass = 0, mid = 0, high = 0;
          const split1 = Math.floor(bufferLength * 0.12);
          const split2 = Math.floor(bufferLength * 0.55);
          for (let i = 0; i < split1; i++) bass += dataArray[i];
          for (let i = split1; i < split2; i++) mid += dataArray[i];
          for (let i = split2; i < bufferLength; i++) high += dataArray[i];
          bass = (bass / split1) / 255;
          mid = (mid / (split2 - split1)) / 255;
          high = (high / (bufferLength - split2)) / 255;

          // Full scope temporal trail
          ctx.fillStyle = 'rgba(1, 1, 4, 0.18)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;

          ctx.globalCompositeOperation = 'screen';
          particlesRef.current.forEach((p, i) => {
            const dx = centerX - p.x;
            const dy = centerY - p.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Central Attractor physics
            const gravity = (bass * 0.5);
            p.vx += (dx / dist) * gravity;
            p.vy += (dy / dist) * gravity;

            // High frequency entropy
            const entropy = (high * 1.2);
            p.vx += (Math.random() - 0.5) * entropy;
            p.vy += (Math.random() - 0.5) * entropy;

            p.charge = (mid * 0.6) + (high * 0.4);
            p.targetSize = 0.5 + (high * 20);
            p.hue = 180 + (mid * 160); // Cyan to Magenta to Red

            p.vx *= 0.95;
            p.vy *= 0.95;
            p.x += p.vx;
            p.y += p.vy;

            // Screen wrapping
            if (p.x < 0) p.x = canvas.width;
            if (p.x > canvas.width) p.x = 0;
            if (p.y < 0) p.y = canvas.height;
            if (p.y > canvas.height) p.y = 0;

            // Render Particle
            const alpha = 0.15 + (p.charge * 0.75);
            ctx.fillStyle = `hsla(${p.hue}, 100%, 65%, ${alpha})`;

            if (p.charge > 0.55) {
                ctx.shadowBlur = 20 * p.charge;
                ctx.shadowColor = `hsla(${p.hue}, 100%, 75%, 0.8)`;
            } else {
                ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.arc(p.x, p.y, Math.max(0.6, p.targetSize / 3.5), 0, Math.PI * 2);
            ctx.fill();

            // High-density Quantum Connections
            if (bass > 0.32 && i % 25 === 0) {
                const range = canvas.width * 0.12;
                const pt = particlesRef.current[(i + 20) % particlesRef.current.length];
                const d = Math.sqrt(Math.pow(p.x - pt.x, 2) + Math.pow(p.y - pt.y, 2));
                if (d < range) {
                    ctx.strokeStyle = `hsla(${p.hue}, 100%, 60%, ${bass * 0.22})`;
                    ctx.lineWidth = 0.6;
                    ctx.beginPath();
                    ctx.moveTo(p.x, p.y);
                    const mx = (p.x + pt.x) / 2;
                    const my = (p.y + pt.y) / 2 - (d * 0.35 * mid);
                    ctx.quadraticCurveTo(mx, my, pt.x, pt.y);
                    ctx.stroke();
                }
            }
          });
          ctx.globalCompositeOperation = 'source-over';
        }
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden text-left relative bg-black">
       {/* Global Full-Scope Visualizer Canvas */}
       <canvas 
         ref={canvasRef} 
         width={window.innerWidth} 
         height={window.innerHeight} 
         className="absolute inset-0 w-full h-full pointer-events-none opacity-85" 
       />

       {/* Matrix Grid Overlay */}
       <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.02)_1px,transparent_1px)] bg-[size:32px_32px] pointer-events-none"></div>

       {/* Top HUD Toolbar */}
       <div className="z-10 bg-zinc-950/40 backdrop-blur-md p-3 rounded-lg border border-cyan-900/30 mb-4 flex items-center justify-between shrink-0 shadow-[0_4px_20px_rgba(0,0,0,0.5)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span className="drop-shadow-[0_0_8px_rgba(0,243,255,0.6)]">Neural_Podcast</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/40 p-1 rounded-sm border border-zinc-800/50">
                 <div className="p-1.5 text-zinc-600"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[110px] bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-800"></div>
                 <div className="p-1.5 text-zinc-600"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[110px] bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_15px_rgba(0,243,255,0.2)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {isLoading ? <Square size={14} fill="currentColor" /> : hasInitiated ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                 {isLoading ? "STOP" : hasInitiated ? "REGENERATE" : "INITIATE"}
              </button>
          </div>
       </div>

       {/* Middle Immersive Player Section */}
       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full relative z-10">
           {/* Visualizer Display Box (Holographic Overlay) */}
           <div className={`bg-zinc-950/60 backdrop-blur-sm border border-zinc-800/40 rounded-lg p-0 relative overflow-hidden shrink-0 flex flex-col shadow-[0_0_40px_rgba(0,0,0,0.5)] transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-auto' : 'h-[160px]'}`}>
               {!isPlayerMinimized && (
                   <div className="flex-1 w-full flex items-center justify-center overflow-hidden relative group">
                      {/* Central HUD Title */}
                      {audioSrc && !isLoading && episodeTitle && (
                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none animate-fade-in">
                            <div className="bg-black/80 backdrop-blur-xl border border-cyan-500/40 px-6 py-2.5 rounded-sm shadow-[0_0_50px_rgba(0,243,255,0.2)] relative max-w-[50%] flex flex-col items-center">
                               {/* Geometric corner accents */}
                               <div className="absolute -top-1 -left-1 w-3 h-3 border-t-2 border-l-2 border-[#00f3ff] shadow-[0_0_8px_#00f3ff]"></div>
                               <div className="absolute -bottom-1 -right-1 w-3 h-3 border-b-2 border-r-2 border-[#ff003c] shadow-[0_0_8px_#ff003c]"></div>

                               <div className="flex items-center gap-2 mb-1 opacity-60">
                                  <div className="w-1 h-1 bg-[#00f3ff] animate-ping"></div>
                                  <span className="text-[7px] font-mono text-cyan-500 uppercase tracking-[0.4em]">Neural_Link.verified</span>
                               </div>

                               <span className="text-[9px] md:text-[10px] font-black text-white font-tech uppercase tracking-[0.4em] drop-shadow-[0_0_8px_rgba(0,243,255,0.9)] italic flex items-center gap-3 justify-center text-center leading-none">
                                  {episodeTitle.toUpperCase()}
                               </span>
                            </div>
                        </div>
                      )}

                      {isLoading ? (
                        <div className="z-20 scale-75 animate-fade-in bg-black/40 backdrop-blur-md p-8 rounded-full">
                          <Loader text="SYNTHESIZING_ENTANGLEMENT..." />
                        </div>
                      ) : !audioSrc && (
                        <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs opacity-50">
                          <Activity size={32} className="animate-pulse" />
                          <span>AWAITING_QUANTUM_STREAM</span>
                        </div>
                      )}
                   </div>
               )}

               {/* Transport Controls */}
               <div className="bg-[#020202]/80 p-3 flex items-center justify-between border-t border-zinc-900/50">
                   <div className="flex-1 flex items-center gap-3 text-[9px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button key={s} onClick={() => setPlaybackRate(s)} className={`transition-all ${playbackRate === s ? 'text-[#00f3ff] font-bold shadow-[0_0_5px_#00f3ff]' : 'text-zinc-600 hover:text-zinc-400'}`}>{s.toFixed(2)}x</button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-8">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-600 hover:text-cyan-400 transition-colors disabled:opacity-20"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-12 h-12 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_20px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_30px_rgba(0,243,255,0.6)] hover:scale-105'}`}>
                         {isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" className="ml-1" />}
                       </button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-600 hover:text-cyan-400 transition-colors disabled:opacity-20"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2 items-center">
                       <button onClick={downloadScript} disabled={!script} className={`p-2 transition-all rounded-full ${script ? 'text-zinc-500 hover:text-[#00f3ff] hover:bg-zinc-900/50' : 'text-zinc-800 opacity-20'}`} title="Download Script"><FileDown size={20} /></button>
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 transition-all rounded-full ${audioSrc ? 'text-zinc-500 hover:text-[#ff003c] hover:bg-zinc-900/50' : 'text-zinc-800 opacity-20'}`} onClick={(e) => !audioSrc && e.preventDefault()} title="Download Audio"><Download size={20} /></a>
                       <button onClick={() => setIsPlayerMinimized(!isPlayerMinimized)} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-all rounded-full bg-zinc-900/30" title={isPlayerMinimized ? "Expand Display" : "Minimize Display"}>{isPlayerMinimized ? <Maximize2 size={20} /> : <Minimize2 size={20} />}</button>
                   </div>
               </div>
           </div>

           <audio 
             ref={audioRef} 
             src={audioSrc || undefined} 
             onEnded={() => setIsPlaying(false)} 
             onPlay={() => { if(audioRef.current) audioRef.current.playbackRate = playbackRate; }}
             className="hidden" 
           />

           {/* Transcript HUD Section */}
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/60 backdrop-blur-sm border border-zinc-800/30 rounded-lg overflow-hidden flex flex-col shadow-[0_8px_32px_rgba(0,0,0,0.7)]">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm relative">
                    {/* Perspective gradient for transcript */}
                    <div className="absolute inset-0 pointer-events-none bg-gradient-to-b from-black/40 via-transparent to-black/40 z-20"></div>

                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const cur = seg.speaker.toUpperCase();
                      const leftAligned = cur === h1 || cur.includes(h1);
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in relative z-10`}>
                            <div className={`relative max-w-[85%] rounded-sm p-5 pt-7 border transition-all duration-500 ${isActive ? (leftAligned ? 'bg-cyan-950/25 border-cyan-500 shadow-[0_0_30px_rgba(6,182,212,0.4)] scale-[1.02] z-30' : 'bg-rose-950/25 border-[#ff003c] shadow-[0_0_30px_rgba(255,0,60,0.4)] scale-[1.02] z-30') : 'bg-zinc-900/20 border-zinc-800/40 opacity-70 hover:opacity-100 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-3 px-3 py-1 text-[9px] font-black uppercase tracking-[0.2em] border ${leftAligned ? 'left-5 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-5 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>{seg.speaker}</div>
                                <p className={`leading-relaxed transition-colors duration-500 ${isActive ? 'text-white font-bold' : 'text-zinc-500'}`}>{seg.text}</p>

                                {isActive && (
                                    <>
                                        {/* Activity filaments for active text */}
                                        <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-[70%] rounded-full animate-pulse ${leftAligned ? '-left-1 bg-cyan-500 shadow-[0_0_15px_#00f3ff]' : '-right-1 bg-[#ff003c] shadow-[0_0_15px_#ff003c]'}`}></div>
                                        <div className={`absolute -top-1 -right-1 w-2 h-2 rounded-full animate-ping ${leftAligned ? 'bg-cyan-400' : 'bg-rose-400'}`}></div>
                                    </>
                                )}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 backdrop-blur-md border border-dashed border-zinc-800/50 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-10 animate-pulse" />
                   <div className="text-center space-y-2">
                      <p className="text-xs uppercase tracking-[0.5em] text-cyan-500/50">Ready_to_Synchronize</p>
                      <p className="text-[10px] opacity-30 font-mono italic">// SELECT PARAMETERS TO INITIATE DATA STREAM</p>
                   </div>
               </div>
           )}
           {error && (
               <div className="flex-1 bg-rose-950/10 backdrop-blur-md border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={40} className="mb-4 animate-pulse" />
                   <p className="text-xs font-black uppercase tracking-[0.3em] mb-3 text-rose-400">Signal_Entanglement_Lost</p>
                   <p className="text-[10px] max-w-sm mb-8 opacity-60 italic leading-relaxed">ERROR_CODE: {error}</p>
                   <button onClick={handleToggleGeneration} className="px-10 py-3 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-[10px] font-black transition-all uppercase tracking-[0.3em] shadow-[0_0_20px_rgba(225,29,72,0.4)] active:scale-95">Re-Establish_Link</button>
               </div>
           )}
       </div>
    </div>
  );
};
